def _legacy_main_matplotlib_preview_controller():
    controller = globals().get("_main_matplotlib_preview_controller")
    if controller is None:
        return None
    return controller


def _draw_legacy_main_matplotlib_canvas_now() -> bool:
    if not _legacy_main_matplotlib_interaction_active():
        return False
    update_id, reason, prefix = _timing_current_draw_context()
    _timing_event(
        _timing_named_event(prefix, "canvas.draw.start", "canvas_draw.start"),
        phase="render",
        update_id=update_id,
        timing_reason=reason,
    )
    projection_refresh = globals().get("_apply_current_primary_raster_projection")
    if callable(projection_refresh):
        projection_refresh()
    active_canvas = globals().get("canvas", matplotlib_canvas)
    draw_fn = getattr(active_canvas, "draw", None)
    if not callable(draw_fn):
        draw_fn = getattr(matplotlib_canvas, "draw", None)
    if not callable(draw_fn):
        _timing_event(
            _timing_named_event(prefix, "canvas.draw.end", "canvas_draw.end"),
            phase="render",
            update_id=update_id,
            timing_reason=reason,
            drawn=False,
        )
        return False
    try:
        draw_fn()
    except Exception:
        _timing_event(
            _timing_named_event(prefix, "canvas.draw.end", "canvas_draw.end"),
            phase="render",
            update_id=update_id,
            timing_reason=reason,
            drawn=False,
        )
        return False
    _timing_event(
        _timing_named_event(prefix, "canvas.draw.end", "canvas_draw.end"),
        phase="render",
        update_id=update_id,
        timing_reason=reason,
        drawn=True,
    )
    return True


def _cancel_legacy_main_matplotlib_redraw() -> None:
    gui_main_matplotlib_interaction.cancel_pending_main_matplotlib_redraw(
        _main_matplotlib_redraw_widget(),
        simulation_runtime_state,
    )


def _request_legacy_main_matplotlib_redraw(*, force: bool = False) -> None:
    update_id, reason, prefix = _timing_current_draw_context()
    _timing_event(
        _timing_named_event(prefix, "canvas.draw_idle.start", "canvas_draw_idle.start"),
        phase="render",
        update_id=update_id,
        timing_reason=reason,
        force=bool(force),
    )
    preview_controller = _legacy_main_matplotlib_preview_controller()
    if preview_controller is not None and bool(preview_controller.preview_active()):
        if not bool(force):
            _timing_event(
                _timing_named_event(prefix, "canvas.draw_idle.end", "canvas_draw_idle.end"),
                phase="render",
                update_id=update_id,
                timing_reason=reason,
                scheduled=False,
                reason_skipped="preview_active",
            )
            return
        _clear_legacy_main_matplotlib_preview_view(redraw=False)
    gui_main_matplotlib_interaction.request_main_matplotlib_redraw(
        widget=_main_matplotlib_redraw_widget(),
        runtime_state=simulation_runtime_state,
        interval_s=float(MAIN_MATPLOTLIB_INTERACTION_REDRAW_INTERVAL_S),
        perf_counter_fn=perf_counter,
        draw_now=_draw_legacy_main_matplotlib_canvas_now,
        force=bool(force),
    )
    _timing_event(
        _timing_named_event(prefix, "canvas.draw_idle.end", "canvas_draw_idle.end"),
        phase="render",
        update_id=update_id,
        timing_reason=reason,
        scheduled=True,
    )


def _suspend_legacy_main_matplotlib_overlays() -> None:
    if not _legacy_main_matplotlib_interaction_active():
        return
    gui_main_matplotlib_interaction.suspend_main_matplotlib_overlays(
        simulation_runtime_state,
        suspend_callback=(lambda: _clear_deferred_overlays(clear_qr_overlay=True)),
    )


def _restore_legacy_main_matplotlib_overlays(*, redraw: bool = True) -> bool:
    if not _legacy_main_matplotlib_interaction_active():
        simulation_runtime_state.main_matplotlib_overlays_suspended = False
        return False
    return bool(
        gui_main_matplotlib_interaction.restore_main_matplotlib_overlays(
            simulation_runtime_state,
            restore_callback=(
                (
                    lambda: (
                        _refresh_settled_overlays(),
                        _request_legacy_main_matplotlib_redraw(force=True),
                    )
                )
                if bool(redraw)
                else None
            ),
        )
    )


def _preview_legacy_main_matplotlib_view_limits(
    xlim: tuple[float, float],
    ylim: tuple[float, float],
) -> bool:
    if not _legacy_main_matplotlib_interaction_active():
        return False
    preview_controller = _legacy_main_matplotlib_preview_controller()
    if preview_controller is None:
        return False
    return bool(preview_controller.preview_view_limits(xlim, ylim))


def _commit_legacy_main_matplotlib_preview_view() -> bool:
    preview_controller = _legacy_main_matplotlib_preview_controller()
    if preview_controller is None or not bool(preview_controller.preview_active()):
        return False
    if not bool(preview_controller.commit_preview_view()):
        return False
    gui_controllers.clear_tk_after_token(
        root,
        simulation_runtime_state.interaction_settle_token,
    )
    simulation_runtime_state.interaction_settle_token = None
    simulation_runtime_state.interaction_drag_active = False
    simulation_runtime_state.interaction_drag_requires_settled_update = False
    _refresh_run_status_bar()
    if not _restore_legacy_main_matplotlib_overlays(redraw=True):
        _request_legacy_main_matplotlib_redraw(force=True)
    return True


def _reset_main_figure_live_interaction_state(*, redraw: bool = True) -> None:
    gui_controllers.clear_tk_after_token(
        root,
        getattr(simulation_runtime_state, "interaction_settle_token", None),
    )
    setattr(simulation_runtime_state, "interaction_settle_token", None)
    setattr(simulation_runtime_state, "interaction_drag_active", False)
    setattr(simulation_runtime_state, "interaction_drag_requires_settled_update", False)
    restored_overlays = False
    if bool(getattr(simulation_runtime_state, "main_matplotlib_overlays_suspended", False)):
        try:
            restored_overlays = bool(_restore_legacy_main_matplotlib_overlays(redraw=bool(redraw)))
        except Exception:
            restored_overlays = False
    if not restored_overlays:
        setattr(simulation_runtime_state, "main_matplotlib_overlays_suspended", False)
    _maybe_refresh_run_status_bar()


def _clear_legacy_main_matplotlib_preview_view(*, redraw: bool = True) -> bool:
    preview_controller = _legacy_main_matplotlib_preview_controller()
    if preview_controller is None:
        return False
    cleared = bool(preview_controller.clear_preview_view(redraw=bool(redraw)))
    if cleared:
        _reset_main_figure_live_interaction_state(redraw=bool(redraw))
    return cleared


def _clear_pending_main_figure_preview_interaction() -> bool:
    """Drop transient main-figure preview state without committing old limits."""

    preview_cleared = bool(_clear_legacy_main_matplotlib_preview_view(redraw=False))
    cleared = preview_cleared
    runtime_state = globals().get("geometry_runtime_state")
    if runtime_state is None:
        return cleared

    dropped_preview_state = False
    if getattr(runtime_state, "_canvas_preview_limits", None) is not None:
        setattr(runtime_state, "_canvas_preview_limits", None)
        cleared = True
        dropped_preview_state = True
    if getattr(runtime_state, "_canvas_pan_session", None) is not None:
        setattr(runtime_state, "_canvas_pan_session", None)
        cleared = True
        dropped_preview_state = True
    if dropped_preview_state and not preview_cleared:
        _reset_main_figure_live_interaction_state(redraw=False)
    return cleared


def _configure_primary_viewport_redraw_helpers() -> None:
    global _request_main_canvas_redraw
    global _request_overlay_canvas_redraw

    def _request_main_canvas_redraw(*, force_matplotlib: bool = False) -> None:
        _request_legacy_main_matplotlib_redraw(force=bool(force_matplotlib))

    def _request_overlay_canvas_redraw(*, force: bool = False) -> None:
        if not force:
            defer_redraw = globals().get("_defer_nonessential_redraw")
            if callable(defer_redraw):
                try:
                    if bool(defer_redraw()):
                        return
                except Exception:
                    pass
        _request_legacy_main_matplotlib_redraw(force=bool(force))


def _flush_main_canvas_tk_present() -> None:
    """Flush Tk idletasks so forced first-paint redraws reach visible canvas."""

    widget = None
    active_canvas = globals().get("matplotlib_canvas")
    if active_canvas is not None:
        get_tk_widget = getattr(active_canvas, "get_tk_widget", None)
        if callable(get_tk_widget):
            try:
                widget = get_tk_widget()
            except Exception:
                widget = None
    for candidate in (widget, globals().get("root")):
        update_idletasks = getattr(candidate, "update_idletasks", None)
        if not callable(update_idletasks):
            continue
        try:
            update_idletasks()
            return
        except Exception:
            continue


def _schedule_post_idle_main_canvas_redraw() -> None:
    """Force one main-canvas redraw after Tk returns to the event loop."""

    def _present_redraw() -> None:
        _request_main_canvas_redraw(force_matplotlib=True)
        _flush_main_canvas_tk_present()

    after_idle = getattr(root, "after_idle", None)
    if callable(after_idle):
        try:
            after_idle(_present_redraw)
            return
        except Exception:
            pass
    _present_redraw()


def _schedule_first_visible_simulation_settle_pass() -> None:
    """Delay one detector settle pass until Tk and Matplotlib have stabilized."""

    expected_signature = getattr(
        simulation_runtime_state,
        "last_unscaled_image_signature",
        None,
    )
    if expected_signature is None:
        gui_controllers.clear_tk_after_token(
            root,
            getattr(simulation_runtime_state, "first_visible_simulation_settle_token", None),
        )
        simulation_runtime_state.first_visible_simulation_settle_token = None
        simulation_runtime_state.first_visible_simulation_settled_signature = None
        return

    gui_controllers.clear_tk_after_token(
        root,
        getattr(simulation_runtime_state, "first_visible_simulation_settle_token", None),
    )
    simulation_runtime_state.first_visible_simulation_settle_token = None

    def _schedule_delayed_settle(callback) -> bool:
        after = getattr(root, "after", None)
        if not callable(after):
            return False
        try:
            simulation_runtime_state.first_visible_simulation_settle_token = after(
                settle_delay_ms,
                callback,
            )
            return True
        except Exception:
            simulation_runtime_state.first_visible_simulation_settle_token = None
            return False

    def _run_first_visible_simulation_settle(*, attempt: int, retry_allowed: bool) -> None:
        simulation_runtime_state.first_visible_simulation_settle_token = None
        if (
            getattr(simulation_runtime_state, "last_unscaled_image_signature", None)
            != expected_signature
        ):
            return
        if getattr(simulation_runtime_state, "unscaled_image", None) is None:
            return
        if _resolved_primary_analysis_display_mode() != "detector":
            return
        if bool(getattr(simulation_runtime_state, "preview_active", False)):
            return
        if simulation_runtime_state.worker_active_job is not None:
            return
        if simulation_runtime_state.worker_queued_job is not None:
            return
        if _live_interaction_active():
            return
        try:
            apply_scale_factor_to_existing_results(
                update_limits=False,
                update_1d=False,
                update_canvas=False,
                update_chi_square=False,
            )
            _refresh_settled_overlays()
            _request_legacy_main_matplotlib_redraw(force=True)
            _flush_main_canvas_tk_present()
            simulation_runtime_state.first_visible_simulation_settled_signature = expected_signature
        except Exception as exc:
            _append_runtime_update_exception_trace(
                "first_visible_simulation_settle_failed",
                type(exc),
                exc,
                exc.__traceback__,
                attempt=int(attempt),
                retry_allowed=bool(retry_allowed),
            )
            if retry_allowed:
                retry_callback = lambda: _run_first_visible_simulation_settle(
                    attempt=(int(attempt) + 1),
                    retry_allowed=False,
                )
                if _schedule_delayed_settle(retry_callback):
                    return
                retry_callback()
                return
            _request_legacy_main_matplotlib_redraw(force=True)
            _flush_main_canvas_tk_present()

    settle_delay_ms = int(globals().get("LIVE_DRAG_SETTLE_MS", 80))
    if _schedule_delayed_settle(
        lambda: _run_first_visible_simulation_settle(
            attempt=1,
            retry_allowed=True,
        )
    ):
        return
    _run_first_visible_simulation_settle(
        attempt=1,
        retry_allowed=True,
    )


def _bind_primary_canvas_interactions(target_canvas) -> None:
    global primary_canvas_interaction_canvas
    global primary_canvas_interaction_cids

    old_canvas = primary_canvas_interaction_canvas
    old_cids = tuple(primary_canvas_interaction_cids or ())
    disconnect = getattr(old_canvas, "mpl_disconnect", None)
    if callable(disconnect):
        for cid in old_cids:
            try:
                disconnect(cid)
            except Exception:
                pass

    callbacks = globals().get("canvas_interaction_runtime_callbacks")
    if callbacks is None or target_canvas is None:
        primary_canvas_interaction_canvas = target_canvas
        primary_canvas_interaction_cids = ()
        return

    try:
        primary_canvas_interaction_cids = tuple(
            gui_runtime_geometry_preview.initialize_runtime_canvas_interaction_bindings(
                canvas=target_canvas,
                callbacks=callbacks,
            )
            or ()
        )
    except Exception:
        primary_canvas_interaction_cids = ()
    primary_canvas_interaction_canvas = target_canvas


