def _apply_geometry_manual_pairs_rows(
    rows: Sequence[object] | None,
    *,
    replace_existing: bool = True,
) -> tuple[int, int, list[str]]:
    """Import saved manual geometry pairs onto the currently loaded backgrounds."""

    def _backfill_imported_pairs_for_background(
        background_index: int,
        entries: Sequence[dict[str, object]],
    ) -> list[dict[str, object]]:
        display_to_native = _background_display_to_native_detector_coords_for_background(
            int(background_index)
        )
        if display_to_native is None:
            display_to_native = _background_display_to_native_detector_coords
        backfilled, _changed_count = (
            gui_manual_geometry.geometry_manual_backfill_missing_caked_coordinates(
                entries,
                background_display_to_native_detector_coords=display_to_native,
                native_detector_coords_to_caked_display_coords=(
                    _native_detector_coords_to_live_caked_coords
                ),
            )
        )
        return [dict(entry) for entry in backfilled]

    return gui_manual_geometry.apply_geometry_manual_pairs_rows(
        rows,
        osc_files=background_runtime_state.osc_files,
        pairs_for_index=_geometry_manual_pairs_for_index,
        pair_entry_from_jsonable=_geometry_manual_pair_entry_from_jsonable,
        replace_pairs_by_background=_replace_geometry_manual_pairs_by_background,
        clear_preview_artists=_clear_geometry_manual_preview_artists,
        cancel_pick_session=_cancel_geometry_manual_pick_session,
        invalidate_pick_cache=_invalidate_geometry_manual_pick_cache,
        clear_manual_undo_stack=_clear_geometry_manual_undo_stack,
        clear_geometry_fit_undo_stack=_clear_geometry_fit_undo_stack,
        render_current_pairs=_render_current_geometry_manual_pairs,
        update_button_label=_update_geometry_manual_pick_button_label,
        refresh_status=_refresh_background_status,
        backfill_imported_pairs_for_background=_backfill_imported_pairs_for_background,
        replace_existing=replace_existing,
    )


def _backfill_geometry_manual_pair_caked_coordinate_cache() -> int:
    """Fill legacy detector-origin manual pairs once caked projection is available."""

    pairs_by_background = getattr(geometry_manual_state, "pairs_by_background", None)
    if not isinstance(pairs_by_background, dict):
        return 0
    changed_total = 0
    for raw_background_index, raw_entries in list(pairs_by_background.items()):
        try:
            background_index = int(raw_background_index)
        except Exception:
            continue
        entries = [dict(entry) for entry in raw_entries or () if isinstance(entry, Mapping)]
        if not entries:
            continue
        display_to_native = _background_display_to_native_detector_coords_for_background(
            int(background_index)
        )
        if display_to_native is None:
            display_to_native = _background_display_to_native_detector_coords
        backfilled, changed_count = (
            gui_manual_geometry.geometry_manual_backfill_missing_caked_coordinates(
                entries,
                background_display_to_native_detector_coords=display_to_native,
                native_detector_coords_to_caked_display_coords=(
                    _native_detector_coords_to_live_caked_coords
                ),
            )
        )
        if changed_count <= 0:
            continue
        pairs_by_background[int(background_index)] = [dict(entry) for entry in backfilled]
        changed_total += int(changed_count)
    if changed_total > 0:
        try:
            _invalidate_geometry_manual_pick_cache()
        except Exception:
            pass
        try:
            _clear_geometry_fit_dataset_cache()
        except Exception:
            pass
    return int(changed_total)


def _apply_geometry_manual_pairs_snapshot(
    snapshot: dict[str, object],
    *,
    allow_background_reload: bool = True,
) -> str:
    """Restore saved manual geometry placements from a snapshot dictionary."""

    return gui_manual_geometry.apply_geometry_manual_pairs_snapshot(
        snapshot,
        allow_background_reload=allow_background_reload,
        osc_files=background_runtime_state.osc_files,
        load_background_files=background_runtime_callbacks.load_files,
        apply_pairs_rows=_apply_geometry_manual_pairs_rows,
        schedule_update=schedule_update,
    )


def _invalidate_peak_picker_caches(*, clear_source_snapshot: bool = False) -> None:
    """Drop cached picker-facing simulation/background state."""
    _invalidate_manual_pick_projection_cache_only()
    _invalidate_geometry_q_group_entries_cache_only()
    if clear_source_snapshot:
        _invalidate_source_row_snapshots_only(current_background_only=True)


def _invalidate_geometry_q_group_entries_cache_only() -> None:
    simulation_runtime_state.geometry_q_group_entries_cache_signature = None
    simulation_runtime_state.geometry_q_group_entries_cache = []


def _invalidate_source_row_snapshots_only(
    *,
    current_background_only: bool = False,
) -> None:
    source_row_snapshots = getattr(
        simulation_runtime_state,
        "source_row_snapshots",
        None,
    )
    if not isinstance(source_row_snapshots, dict):
        return
    if not bool(current_background_only):
        source_row_snapshots.clear()
        return
    try:
        background_index = int(background_runtime_state.current_background_index)
    except Exception:
        return
    source_row_snapshots.pop(background_index, None)


def _invalidate_intersection_caches_only() -> None:
    simulation_runtime_state.stored_intersection_cache = None
    simulation_runtime_state.stored_primary_intersection_cache = None
    simulation_runtime_state.stored_secondary_intersection_cache = None
    simulation_runtime_state.stored_primary_intersection_cache_signature = None
    simulation_runtime_state.stored_secondary_intersection_cache_signature = None


def _invalidate_manual_pick_projection_cache_only() -> None:
    geometry_runtime_state.manual_pick_cache_signature = None
    geometry_runtime_state.manual_pick_cache_data = {}
    payload_cache = globals().get("_hkl_pick_simulation_points_payload_cache")
    if isinstance(payload_cache, dict):
        payload_cache.clear()


def _request_geometry_q_group_refresh_if_available() -> None:
    try:
        gui_controllers.request_geometry_q_group_refresh(geometry_q_group_state)
    except Exception:
        return


def _manual_projection_cache_present() -> bool:
    payload_cache = globals().get("_hkl_pick_simulation_points_payload_cache")
    return bool(
        getattr(geometry_runtime_state, "manual_pick_cache_signature", None) is not None
        or getattr(geometry_runtime_state, "manual_pick_cache_data", None)
        or (isinstance(payload_cache, dict) and payload_cache)
    )


def _caked_or_q_space_projection_cache_present() -> bool:
    caking_cache = getattr(simulation_runtime_state, "caking_cache", None)
    return bool(
        getattr(simulation_runtime_state, "last_caked_image_unscaled", None) is not None
        or getattr(simulation_runtime_state, "last_caked_extent", None) is not None
        or getattr(simulation_runtime_state, "last_caked_background_image_unscaled", None)
        is not None
        or getattr(simulation_runtime_state, "last_caked_radial_values", None) is not None
        or getattr(simulation_runtime_state, "last_caked_azimuth_values", None) is not None
        or getattr(simulation_runtime_state, "last_caked_transform_bundle", None) is not None
        or getattr(simulation_runtime_state, "last_caked_intersection_cache", None) is not None
        or getattr(
            simulation_runtime_state,
            "last_caked_intersection_cache_transform_bundle",
            None,
        )
        is not None
        or getattr(simulation_runtime_state, "last_q_space_image_unscaled", None) is not None
        or getattr(simulation_runtime_state, "last_q_space_extent", None) is not None
        or getattr(simulation_runtime_state, "last_q_space_background_image_unscaled", None)
        is not None
        or getattr(simulation_runtime_state, "last_q_space_qr_values", None) is not None
        or getattr(simulation_runtime_state, "last_q_space_qz_values", None) is not None
        or getattr(simulation_runtime_state, "last_q_space_payload_signature", None) is not None
        or bool(getattr(simulation_runtime_state, "geometry_fit_caking_ai_cache", None))
        or (
            isinstance(caking_cache, dict)
            and (bool(caking_cache.get("sim_results")) or bool(caking_cache.get("bg_results")))
        )
    )


def _clear_detector_center_projection_caches() -> bool:
    had_caked_or_q_space_projection_cache = _caked_or_q_space_projection_cache_present()
    simulation_runtime_state.geometry_fit_caking_ai_cache = {}
    simulation_runtime_state.caking_cache = _empty_caking_cache()
    return bool(had_caked_or_q_space_projection_cache)


def _invalidate_picker_handoff_caches_for_update_action(
    action: UpdateAction,
    *,
    physics_signature_changed: bool = False,
    hit_table_signature_changed: bool = False,
    q_group_content_signature_changed: bool = False,
    detector_geometry_changed: bool = False,
    current_background_snapshot_only: bool = False,
):
    policy = gui_runtime_qr_selector_cache_policy.qr_selector_cache_policy_for_update_action(
        action,
        physics_signature_changed=bool(physics_signature_changed),
        hit_table_signature_changed=bool(hit_table_signature_changed),
        q_group_content_signature_changed=bool(q_group_content_signature_changed),
        detector_geometry_changed=bool(detector_geometry_changed),
    )
    if not policy.retain_manual_pick_cache:
        _invalidate_manual_pick_projection_cache_only()
    if not policy.retain_geometry_q_group_entries:
        _invalidate_geometry_q_group_entries_cache_only()
    if not policy.retain_source_row_snapshots:
        _invalidate_source_row_snapshots_only(
            current_background_only=bool(current_background_snapshot_only)
        )
    if not policy.retain_intersection_caches:
        _invalidate_intersection_caches_only()
    if (
        policy.require_q_group_refresh_after_apply
        and not policy.defer_q_group_refresh_until_rows_available
    ):
        _request_geometry_q_group_refresh_if_available()
    return policy


def _invalidate_geometry_manual_pick_cache() -> None:
    """Drop cached manual-pick simulation/background state."""

    _invalidate_peak_picker_caches(clear_source_snapshot=False)


def _invalidate_geometry_manual_pick_cache_and_schedule_prewarm_if_armed() -> None:
    """Invalidate manual picker cache, then prewarm only for armed stable UI paths."""

    _invalidate_geometry_manual_pick_cache()
    if bool(getattr(geometry_runtime_state, "manual_pick_armed", False)):
        _schedule_geometry_manual_pick_cache_prewarm()


def _set_geometry_manual_pick_cache_state(
    signature: object,
    cache_data: dict[str, object] | None,
) -> None:
    if _retain_runtime_optional_cache("manual_pick", feature_needed=True):
        geometry_runtime_state.manual_pick_cache_signature = signature
        geometry_runtime_state.manual_pick_cache_data = (
            dict(cache_data) if isinstance(cache_data, dict) else {}
        )
        return
    geometry_runtime_state.manual_pick_cache_signature = None
    geometry_runtime_state.manual_pick_cache_data = {}


