def _selected_qr_rod_detector_mask_payload_for_inputs(
    inputs: Mapping[str, object],
) -> dict[str, object] | None:
    if inputs is None:
        return None
    signature = inputs.get("mask_signature")
    if signature is None:
        return None
    payload_cache = getattr(geometry_runtime_state, "selected_qr_rod_detector_payload_cache", None)
    if not isinstance(payload_cache, dict):
        payload_cache = {}
        try:
            setattr(
                geometry_runtime_state,
                "selected_qr_rod_detector_payload_cache",
                payload_cache,
            )
        except Exception:
            payload_cache = {}
    cached_payload = payload_cache.get(signature)
    if isinstance(cached_payload, dict):
        return cached_payload

    mask_result = gui_qr_cylinder_overlay.build_selected_qr_rod_qz_detector_mask(
        selected_entry=inputs["selected_entry"],
        config=inputs["config"],
        detector_shape=inputs["detector_shape"],
        delta_qr=inputs["delta_qr"],
        qz_min=inputs["qz_min"],
        qz_max=inputs["qz_max"],
        detector_phi_deg=inputs.get("detector_phi_deg"),
        phi_min=inputs.get("phi_min", -180.0),
        phi_max=inputs.get("phi_max", 180.0),
        phi_windows=inputs.get("phi_windows"),
        shape_mask=inputs.get("shape_mask"),
        selected_qr_rod_key=inputs.get("selected_qr_rod_key"),
        include_shape=bool(inputs.get("include_selected_qr_rod_shape", False)),
        shape_source_signature=inputs.get("shape_source_signature"),
        qr_map=inputs.get("qr_map"),
        qz_map=inputs.get("qz_map"),
        valid_q=inputs.get("valid_q"),
    )
    if not isinstance(mask_result, Mapping):
        return None
    mask = np.asarray(mask_result.get("mask"), dtype=bool)
    if tuple(mask.shape) != tuple(int(v) for v in inputs["detector_shape"]):
        return None
    visual_payload = gui_qr_cylinder_overlay.build_detector_selected_qr_rod_band_visual_payload(
        qr_map=inputs.get("qr_map"),
        qz_map=inputs.get("qz_map"),
        valid_q=inputs.get("valid_q"),
        qr_center=inputs.get("qr_center"),
        delta_qr=inputs.get("delta_qr"),
        qz_min=inputs.get("qz_min"),
        qz_max=inputs.get("qz_max"),
        detector_phi_deg=inputs.get("detector_phi_deg"),
        phi_min=inputs.get("phi_min", -180.0),
        phi_max=inputs.get("phi_max", 180.0),
        phi_windows=inputs.get("phi_windows"),
        shape_mask=inputs.get("shape_mask"),
        signature=signature,
    )
    result = {
        "selected_entry": dict(inputs["selected_entry"]),
        "selected_qr_rod_key": inputs.get("selected_qr_rod_key"),
        "mask": mask,
        "signature": signature,
        "qz_min": inputs.get("qz_min"),
        "qz_max": inputs.get("qz_max"),
        "include_selected_qr_rod_shape": bool(inputs.get("include_selected_qr_rod_shape", False)),
        "shape_available": bool(mask_result.get("shape_available", False)),
        "shape_pixel_count": int(mask_result.get("shape_pixel_count", 0) or 0),
        "shape_signature": inputs.get("shape_signature"),
    }
    if isinstance(visual_payload, Mapping):
        result["visual_payload"] = dict(visual_payload)
        result["visual_overlay"] = np.asarray(
            visual_payload.get("visual_overlay"),
            dtype=np.float32,
        )
        result["visual_signature"] = visual_payload.get("signature")
    payload_cache[signature] = result
    return result


def _current_selected_qr_rod_detector_mask_payloads() -> list[dict[str, object]]:
    shared_inputs = _current_selected_qr_rod_detector_shared_inputs()
    if shared_inputs is None:
        return []
    selected_entries = list(shared_inputs.get("selected_entries") or [])
    selected_keys = list(shared_inputs.get("selected_qr_rod_keys") or [])
    payloads: list[dict[str, object]] = []
    for selected_entry, selected_key in zip(selected_entries, selected_keys, strict=False):
        inputs = _selected_qr_rod_detector_support_inputs_from_shared(
            shared_inputs,
            require_qz_range=True,
            selected_entry=selected_entry,
            selected_key=selected_key,
        )
        payload = (
            _selected_qr_rod_detector_mask_payload_for_inputs(inputs)
            if isinstance(inputs, Mapping)
            else None
        )
        if isinstance(payload, dict):
            payloads.append(payload)
    return payloads


def _current_selected_qr_rod_detector_integration_context() -> dict[str, object] | None:
    inputs = _current_selected_qr_rod_detector_support_inputs(require_qz_range=True)
    if inputs is None:
        return None
    qz_lo = inputs.get("qz_min")
    qz_hi = inputs.get("qz_max")
    if qz_lo is None or qz_hi is None:
        return None
    bin_count = _selected_qr_rod_qz_profile_bin_count(inputs.get("detector_shape"))
    qz_edges = np.linspace(float(qz_lo), float(qz_hi), int(bin_count) + 1, dtype=np.float64)
    context = dict(inputs)
    context["qz_edges"] = qz_edges
    context["signature"] = (
        "selected_qr_rod_detector_qz_profile",
        inputs.get("mask_signature"),
        int(bin_count),
    )
    return context


def _current_selected_qr_rod_detector_drag_context() -> dict[str, object] | None:
    shared_inputs = _current_selected_qr_rod_detector_shared_inputs()
    if shared_inputs is None:
        return None
    selected_entries = list(shared_inputs.get("selected_entries") or [])
    selected_keys = list(shared_inputs.get("selected_qr_rod_keys") or [])
    contexts: list[dict[str, object]] = []
    union_support = None
    signatures: list[object] = []
    for selected_entry, selected_key in zip(selected_entries, selected_keys, strict=False):
        inputs = _selected_qr_rod_detector_support_inputs_from_shared(
            shared_inputs,
            require_qz_range=False,
            selected_entry=selected_entry,
            selected_key=selected_key,
        )
        if inputs is None:
            continue
        support = gui_qr_cylinder_overlay.build_detector_qr_rod_support_mask(
            qr_map=inputs.get("qr_map"),
            qz_map=inputs.get("qz_map"),
            valid_q=inputs.get("valid_q"),
            qr_center=inputs.get("qr_center"),
            delta_qr=inputs.get("delta_qr"),
            detector_phi_deg=inputs.get("detector_phi_deg"),
            phi_min=inputs.get("phi_min", -180.0),
            phi_max=inputs.get("phi_max", 180.0),
            phi_windows=inputs.get("phi_windows"),
            shape_mask=inputs.get("shape_mask"),
        )
        if not isinstance(support, Mapping):
            continue
        support_mask = np.asarray(support.get("mask"), dtype=bool)
        if union_support is None:
            union_support = np.zeros_like(support_mask, dtype=bool)
        if support_mask.shape != union_support.shape:
            continue
        union_support |= support_mask
        signatures.append(inputs.get("mask_signature"))
        contexts.append(
            {
                "selected_entry": dict(inputs["selected_entry"]),
                "config": inputs["config"],
                "detector_shape": inputs["detector_shape"],
                "qr_map": inputs["qr_map"],
                "qz_map": inputs["qz_map"],
                "valid_q": inputs["valid_q"],
                "detector_phi_deg": inputs.get("detector_phi_deg"),
                "qr_center": inputs["qr_center"],
                "delta_qr": inputs["delta_qr"],
                "phi_min": inputs.get("phi_min", -180.0),
                "phi_max": inputs.get("phi_max", 180.0),
                "phi_windows": inputs.get("phi_windows"),
                "shape_mask": inputs.get("shape_mask"),
                "signature": inputs.get("mask_signature"),
                "selected_qr_rod_key": inputs.get("selected_qr_rod_key"),
            }
        )
    if not contexts or union_support is None or not np.any(union_support):
        return None
    context = dict(contexts[0])
    context["per_rod_contexts"] = contexts
    context["union_support_mask"] = union_support
    context["selected_qr_rod_keys"] = [str(ctx.get("selected_qr_rod_key", "")) for ctx in contexts]
    context["signature"] = (
        "selected_qr_rod_detector_drag_union",
        tuple(context["selected_qr_rod_keys"]),
        tuple(signatures),
        tuple(int(value) for value in union_support.shape),
        int(np.count_nonzero(union_support)),
    )
    return context


def _current_selected_qr_rod_drag_context() -> dict[str, object] | None:
    if not _active_caked_primary_view():
        return None

    roi_values = _current_analysis_roi_values()
    if not bool(roi_values.get("integrate_selected_qr_rod", False)):
        return None

    selected_entries = _current_selected_qr_rod_entries(_analysis_selected_qr_rod_entries())
    if not selected_entries:
        return None

    radial_axis = np.asarray(
        simulation_runtime_state.last_caked_radial_values,
        dtype=float,
    ).reshape(-1)
    azimuth_axis = np.asarray(
        simulation_runtime_state.last_caked_azimuth_values,
        dtype=float,
    ).reshape(-1)
    radial_axis = radial_axis[(radial_axis >= 0.0) & (radial_axis <= 90.0)]
    if radial_axis.size <= 0 or azimuth_axis.size <= 0:
        return None
    config_factory = globals().get("qr_cylinder_overlay_render_config_factory")
    if not callable(config_factory):
        return None
    try:
        config = config_factory()
    except Exception:
        return None
    if not isinstance(config, gui_qr_cylinder_overlay.QrCylinderOverlayRenderConfig):
        return None
    projection_context = _current_qr_cylinder_caked_projection_context()
    if projection_context is None:
        return None
    contexts: list[dict[str, object]] = []
    selected_keys = _current_selected_qr_rod_keys_from_roi(roi_values)
    if not selected_keys:
        selected_keys = [
            gui_controllers.encode_bragg_qr_group_key(entry.get("key"))
            for entry in selected_entries
        ]
    for selected_entry, selected_key in zip(selected_entries, selected_keys, strict=False):
        try:
            qr_value = float(selected_entry["qr"])
        except Exception:
            continue
        if not np.isfinite(qr_value):
            continue
        contexts.append(
            {
                "qr": float(qr_value),
                "selected_entry": dict(selected_entry),
                "selected_qr_rod_key": str(selected_key),
                "config": config,
                "projection_context": projection_context,
                "radial_axis": radial_axis,
                "azimuth_axis": azimuth_axis,
            }
        )
    if not contexts:
        return None
    context = dict(contexts[0])
    context["per_rod_contexts"] = contexts
    context["selected_qr_rod_keys"] = [str(ctx.get("selected_qr_rod_key", "")) for ctx in contexts]
    return context


def _scattering_angles_to_detector_pixel(
    two_theta_deg: float,
    phi_deg: float,
    center: Sequence[float] | None,
    detector_distance: float,
    pixel_size: float,
) -> tuple[float | None, float | None]:
    """Convert ``(2theta, phi)`` in degrees to one detector pixel position."""

    if center is None or len(center) < 2:
        return None, None
    if not (np.isfinite(detector_distance) and detector_distance > 0.0):
        return None, None
    if not (np.isfinite(pixel_size) and pixel_size > 0.0):
        return None, None
    try:
        center_row = float(center[0])
        center_col = float(center[1])
    except Exception:
        return None, None
    if not (
        np.isfinite(two_theta_deg)
        and np.isfinite(phi_deg)
        and np.isfinite(center_row)
        and np.isfinite(center_col)
    ):
        return None, None

    radius = float(detector_distance) * float(np.tan(np.deg2rad(float(two_theta_deg))))
    phi_rad = float(np.deg2rad(float(phi_deg)))
    dx = radius * float(np.sin(phi_rad))
    dy = radius * float(np.cos(phi_rad))
    col = center_col + dx / float(pixel_size)
    row = center_row - dy / float(pixel_size)
    return float(col), float(row)


def _geometry_fit_caked_roi_fit_space_to_detector_point(
    *,
    detector_shape: Sequence[object] | None,
    radial_axis: Sequence[float] | None,
    azimuth_axis: Sequence[float] | None,
    ai: FastAzimuthalIntegrator | None = None,
    transform_bundle: CakeTransformBundle | None = None,
) -> Callable[[float, float], tuple[float | None, float | None] | None] | None:
    """Build one fit-space `(2theta, phi)` to detector-point projector for ROI use."""

    normalized_shape = _geometry_fit_detector_shape_2d(detector_shape)
    if normalized_shape is None:
        return None
    exact_ai = ai if isinstance(ai, FastAzimuthalIntegrator) else None
    normalized_payload = _normalize_geometry_fit_caked_view_payload(
        {
            "detector_shape": normalized_shape,
            "radial_axis": radial_axis,
            "azimuth_axis": azimuth_axis,
            "transform_bundle": transform_bundle,
        },
        detector_shape=normalized_shape,
        ai=exact_ai,
    )
    if not isinstance(normalized_payload, Mapping):
        return None
    bundle = normalized_payload.get("transform_bundle")
    if not isinstance(bundle, CakeTransformBundle):
        return None
    radial = np.asarray(normalized_payload.get("radial_axis"), dtype=np.float64).reshape(-1)
    azimuth = np.asarray(normalized_payload.get("azimuth_axis"), dtype=np.float64).reshape(-1)

    def _project(
        two_theta_deg: float,
        phi_deg: float,
    ) -> tuple[float | None, float | None] | None:
        return caked_point_to_detector_pixel(
            exact_ai,
            normalized_shape,
            radial,
            azimuth,
            float(two_theta_deg),
            float(phi_deg),
            transform_bundle=bundle,
        )

    return _project


def _geometry_fit_worker_caked_projection_view(
    *,
    detector_shape: Sequence[object] | None,
    ai: FastAzimuthalIntegrator | None,
    npt_rad: int | None = None,
    npt_azim: int | None = None,
) -> dict[str, object] | None:
    """Build exact-cake axis metadata for worker ROI filtering before first cake."""

    return gui_geometry_fit.build_geometry_fit_exact_caked_projection_view(
        detector_shape=detector_shape,
        ai=ai,
        npt_rad=(
            int(max(1, npt_rad))
            if npt_rad is not None
            else int(max(1, DEFAULT_ANALYSIS_RADIAL_BINS))
        ),
        npt_azim=(
            int(max(1, npt_azim))
            if npt_azim is not None
            else int(max(1, DEFAULT_ANALYSIS_AZIMUTH_BINS))
        ),
    )


