def _hkl_pick_simulation_points_from_qr_picker_cache() -> object:
    """Return indexed Qr/manual simulation-point rows used by HKL picking."""

    params_factory = globals().get("_current_geometry_fit_params")
    if callable(params_factory):
        try:
            param_set = dict(params_factory())
        except Exception:
            param_set = None
    else:
        param_set = None

    payload_cache = globals().setdefault("_hkl_pick_simulation_points_payload_cache", {})
    if not isinstance(payload_cache, dict):
        payload_cache = {}
        globals()["_hkl_pick_simulation_points_payload_cache"] = payload_cache

    fixed_row_fields = (
        "source_table_index",
        "source_row_index",
        "source_branch_index",
        "q_group_key",
        "hkl",
        "hkl_raw",
        "native_col",
        "native_row",
        "sim_col_raw",
        "sim_row_raw",
        "caked_x",
        "caked_y",
        "raw_caked_x",
        "raw_caked_y",
        "two_theta_deg",
        "phi_deg",
        "sim_col",
        "sim_row",
        "display_col",
        "display_row",
    )
    fixed_row_field_names = set(fixed_row_fields)

    def _normalize_signature_value(value: object) -> object:
        if isinstance(value, np.generic):
            try:
                return _normalize_signature_value(value.item())
            except Exception:
                return None
        if isinstance(value, np.ndarray):
            try:
                return _normalize_signature_value(value.tolist())
            except Exception:
                return None
        if hasattr(value, "items") and callable(getattr(value, "items", None)):
            try:
                keys = sorted(value.keys(), key=lambda item: str(item))
            except Exception:
                return None
            normalized_items: list[tuple[str, object]] = []
            for key in keys:
                key_name = str(key)
                try:
                    raw_item = value.get(key)
                except Exception:
                    return None
                normalized_items.append((key_name, _normalize_signature_value(raw_item)))
            return tuple(normalized_items)
        if isinstance(value, (list, tuple)):
            return tuple(_normalize_signature_value(item) for item in value)
        if isinstance(value, (bool, int, str)) or value is None:
            return value
        try:
            numeric = float(value)
        except Exception:
            return None
        return round(float(numeric), 6) if np.isfinite(numeric) else None

    def _row_fingerprint(row: dict[str, object]) -> tuple[object, ...]:
        fixed_values = tuple(
            _normalize_signature_value(row.get(field_name)) for field_name in fixed_row_fields
        )
        extras: list[tuple[str, object]] = []
        for key in sorted(row.keys(), key=lambda item: str(item)):
            key_name = str(key)
            if key_name in fixed_row_field_names:
                continue
            extras.append((key_name, _normalize_signature_value(row.get(key))))
        return fixed_values + (tuple(extras),)

    def _normalized_signature_digest(value: object) -> str:
        hashlib_module = __import__("hashlib")
        json_module = __import__("json")
        normalized_value = _normalize_signature_value(value)
        try:
            encoded_value = json_module.dumps(
                normalized_value,
                ensure_ascii=True,
                allow_nan=False,
                separators=(",", ":"),
            ).encode("ascii")
        except Exception:
            encoded_value = repr(normalized_value).encode("utf-8", "backslashreplace")
        hasher = hashlib_module.blake2b(digest_size=16)
        hasher.update(encoded_value)
        return str(hasher.hexdigest())

    def _rows_content_signature(rows: list[dict[str, object]]) -> str:
        hashlib_module = __import__("hashlib")
        json_module = __import__("json")
        hasher = hashlib_module.blake2b(digest_size=16)
        for row in rows:
            if not isinstance(row, dict):
                continue
            try:
                encoded_row = json_module.dumps(
                    _row_fingerprint(row),
                    ensure_ascii=True,
                    allow_nan=False,
                    separators=(",", ":"),
                ).encode("ascii")
            except Exception:
                encoded_row = repr(_row_fingerprint(row)).encode(
                    "utf-8",
                    "backslashreplace",
                )
            hasher.update(encoded_row)
            hasher.update(b"\x1e")
        return str(hasher.hexdigest())

    def _flatten_grouped_rows(grouped_rows: object) -> list[dict[str, object]]:
        rows: list[dict[str, object]] = []
        if not isinstance(grouped_rows, dict):
            return rows
        for entries in grouped_rows.values():
            if isinstance(entries, (list, tuple)):
                rows.extend(dict(entry) for entry in entries if isinstance(entry, dict))
        return rows

    def _grouped_rows_and_signature(
        cache_data: object,
    ) -> tuple[list[dict[str, object]], tuple[object, ...]]:
        if not isinstance(cache_data, dict):
            return [], ("empty",)
        detector_payload_available = any(
            bool(cache_data.get(key))
            for key in (
                "detector_picker_rows",
                "detector_picker_source_rows",
                "detector_picker_grouped_candidates",
            )
        )
        grouped = cache_data.get("grouped_candidates")
        signature_kind = "grouped"
        rows: list[dict[str, object]] = []
        if detector_payload_available:
            manual_geometry_module = globals().get("gui_manual_geometry")
            if manual_geometry_module is None:
                from ra_sim.gui import manual_geometry as manual_geometry_module
            runtime_state = globals().get("simulation_runtime_state")
            detector_grouped = manual_geometry_module.geometry_manual_detector_picker_grouped_candidates_from_cache(
                cache_data,
                profile_cache=getattr(runtime_state, "profile_cache", {}),
            )
            detector_rows = _flatten_grouped_rows(detector_grouped)
            if detector_rows:
                grouped = detector_grouped
                rows = detector_rows
                signature_kind = "detector_picker_grouped"
        if not rows:
            rows = _flatten_grouped_rows(grouped)
        if not rows and not isinstance(grouped, dict):
            return [], ("no_grouped_candidates",)
        signature = (
            signature_kind,
            cache_data.get("signature"),
            len(rows),
            _rows_content_signature(rows),
        )
        return rows, signature

    get_cache = globals().get("_get_geometry_manual_pick_cache")
    cache_data: object = {}
    if callable(get_cache):
        try:
            cache_data = get_cache(param_set=param_set, prefer_cache=True)
        except TypeError:
            try:
                cache_data = get_cache(prefer_cache=True)
            except TypeError:
                try:
                    cache_data = get_cache()
                except Exception:
                    cache_data = {}
            except Exception:
                cache_data = {}
        except Exception:
            cache_data = {}
    rows, signature = _grouped_rows_and_signature(cache_data)
    if rows:
        if payload_cache.get("signature") == signature and isinstance(
            payload_cache.get("payload"),
            dict,
        ):
            return payload_cache["payload"]
        payload = gui_peak_selection.build_hkl_pick_simulation_point_payload(rows)
        payload["source_signature"] = signature
        payload_cache["signature"] = signature
        payload_cache["payload"] = payload
        return payload

    # Early-startup fallback stays valid only if it rebuilds rows through the
    # same active Qr/manual candidate filter used by the picker cache.
    provider = globals().get("_geometry_manual_simulated_peaks_for_params")
    pick_candidates_provider = globals().get("_geometry_manual_pick_candidates")
    if callable(provider) and callable(pick_candidates_provider):
        try:
            raw_rows = provider(param_set, prefer_cache=True)
        except TypeError:
            try:
                raw_rows = provider(param_set)
            except Exception:
                raw_rows = []
        except Exception:
            raw_rows = []
        if isinstance(raw_rows, (list, tuple)):
            grouped_rows = pick_candidates_provider(raw_rows)
            rows = _flatten_grouped_rows(grouped_rows)
            signature = (
                "provider",
                (_normalized_signature_digest(param_set) if isinstance(param_set, dict) else None),
                len(rows),
                _rows_content_signature(rows),
            )
            if rows:
                if payload_cache.get("signature") == signature and isinstance(
                    payload_cache.get("payload"),
                    dict,
                ):
                    return payload_cache["payload"]
                payload = gui_peak_selection.build_hkl_pick_simulation_point_payload(rows)
                payload["source_signature"] = signature
                payload_cache["signature"] = signature
                payload_cache["payload"] = payload
                return payload
    return []


