def _apply_1d_plot_log_scale(*, redraw: bool = False) -> None:
    use_log = bool(_fit_axes_log_y_enabled())
    axes = []
    figure = globals().get("fig_1d")
    if figure is not None:
        try:
            axes = list(getattr(figure, "axes", []) or [])
        except Exception:
            axes = []
    if not axes:
        axes = [globals().get("ax_1d_radial"), globals().get("ax_1d_azim")]
    for axis_obj in axes:
        if axis_obj is None:
            continue
        try:
            axis_obj.set_yscale("log" if use_log else "linear", nonpositive="clip")
        except TypeError:
            try:
                axis_obj.set_yscale("log" if use_log else "linear")
            except Exception:
                continue
        except Exception:
            continue
        try:
            axis_obj.relim()
            axis_obj.autoscale_view()
        except Exception:
            pass
    if redraw and canvas_1d is not None:
        try:
            canvas_1d.draw_idle()
        except Exception:
            pass


def _set_1d_axes_for_selected_qr_rod_profile(y_label: str) -> None:
    _set_1d_layout_for_selected_qr_rod()
    ax_1d_radial.set_xlabel("Qz (A^-1)")
    ax_1d_radial.set_title("Selected Qr Rod Integration (Qz)")
    ax_1d_radial.set_ylabel(y_label)
    ax_1d_azim.set_xlabel("Azimuth (degrees)")
    ax_1d_azim.set_title("Azimuthal Integration (φ)")
    ax_1d_azim.set_ylabel(y_label)


def _selected_qr_rod_profile_x_axis(
    profile: Mapping[str, object] | None,
) -> tuple[np.ndarray | None, str, str]:
    if isinstance(profile, Mapping) and "l_center" in profile:
        try:
            l_center = np.asarray(profile["l_center"], dtype=float)
        except Exception:
            l_center = None
        if l_center is not None and l_center.ndim == 1 and l_center.size > 0:
            return l_center, "l", "L (r.l.u.)"
    if isinstance(profile, Mapping):
        try:
            qz_center = np.asarray(profile["qz_center"], dtype=float)
        except Exception:
            qz_center = None
        if qz_center is not None and qz_center.ndim == 1:
            return qz_center, "qz", "Qz (A^-1)"
    return None, "qz", "Qz (A^-1)"


def _clear_selected_qr_rod_detector_1d_plot() -> None:
    _clear_selected_qr_rod_line_state()
    if line_1d_rad is not None:
        line_1d_rad.set_data([], [])
    if line_1d_rad_bg is not None:
        line_1d_rad_bg.set_data([], [])
    if line_1d_az is not None:
        line_1d_az.set_data([], [])
    if line_1d_az_bg is not None:
        line_1d_az_bg.set_data([], [])
    simulation_runtime_state.last_1d_integration_data.update(
        {
            "radials_sim": None,
            "intensities_2theta_sim": None,
            "azimuths_sim": None,
            "intensities_azimuth_sim": None,
            "radials_bg": None,
            "intensities_2theta_bg": None,
            "azimuths_bg": None,
            "intensities_azimuth_bg": None,
            "x_axis_kind": "qz",
            "x_axis_label": "Qz (A^-1)",
        }
    )
    _set_1d_axes_for_selected_qr_rod_profile("Intensity")
    ax_1d_radial.relim()
    ax_1d_radial.autoscale_view()
    ax_1d_azim.relim()
    ax_1d_azim.autoscale_view()
    if canvas_1d is not None:
        canvas_1d.draw_idle()


def _selected_qr_rod_axis_title(payload: Mapping[str, object]) -> str:
    entry = payload.get("selected_entry")
    if isinstance(entry, Mapping):
        try:
            qr_center = float(entry.get("qr"))
        except Exception:
            qr_center = float("nan")
        if np.isfinite(qr_center):
            return f"Qr = {qr_center:.4f} A^-1"
    key = str(payload.get("selected_qr_rod_key", "") or "")
    return f"Selected Qr rod {key}".strip()


def _selected_qr_rod_no_profile_status(text: str) -> None:
    try:
        progress_label_positions.config(text=text)
    except Exception:
        pass


def _update_1d_plots_from_selected_qr_rods_caked(
    *,
    sim_res2: object,
    bg_res2: object | None,
    payloads: Sequence[Mapping[str, object]],
) -> bool:
    global line_1d_rad, line_1d_rad_bg, line_1d_az, line_1d_az_bg

    rod_payloads = [payload for payload in payloads if isinstance(payload, Mapping)]
    if not rod_payloads:
        return False

    rod_profile_intensity_mode = _current_rod_profile_intensity_mode()
    y_label = (
        "Raw accumulated intensity"
        if rod_profile_intensity_mode == "raw_sum"
        else "Intensity density (support-normalized)"
    )
    axes = _set_1d_layout_for_selected_qr_rods(len(rod_payloads))
    if not axes:
        return False

    scale = _get_scale_factor_value(default=1.0)
    selected_keys = [str(payload.get("selected_qr_rod_key", "") or "") for payload in rod_payloads]
    primary_key = selected_keys[0] if selected_keys else ""
    mask_payloads_by_key = {
        (selected_keys[idx] if selected_keys[idx] else f"rod-{idx + 1}"): payload
        for idx, payload in enumerate(rod_payloads)
    }
    sim_shared = _selected_qr_rod_caked_shared_profile_inputs(sim_res2)
    if isinstance(sim_shared, dict):
        sim_shared["mask_payloads_by_key"] = mask_payloads_by_key
        sim_shared["rod_profile_intensity_mode"] = rod_profile_intensity_mode
    bg_shared = (
        _selected_qr_rod_caked_shared_profile_inputs(bg_res2) if bg_res2 is not None else None
    )
    if isinstance(bg_shared, dict):
        bg_shared["mask_payloads_by_key"] = mask_payloads_by_key
        bg_shared["rod_profile_intensity_mode"] = rod_profile_intensity_mode
    profiles_by_key: dict[str, dict[str, object]] = {}
    primary_sim_profile = None
    primary_bg_profile = None
    primary_sim_curve = None
    primary_bg_curve = None
    primary_x = None
    primary_x_axis_kind = "qz"
    primary_x_axis_label = "Qz (A^-1)"
    plotted_any = False

    for idx, (axis, payload) in enumerate(zip(axes, rod_payloads, strict=False)):
        key = str(payload.get("selected_qr_rod_key", "") or f"rod-{idx + 1}")
        line_record = _selected_qr_rod_lines_for_axis(axis, key=key, slot_index=idx)
        if not isinstance(line_record, Mapping):
            return False
        selected_entry = payload.get("selected_entry", {})
        if not isinstance(selected_entry, Mapping):
            selected_entry = {}
        sim_profile = _selected_qr_rod_caked_profile_from_shared_inputs(
            sim_shared,
            selected_entry,
            key,
        )
        sim_curve = _selected_qr_rod_profile_curve(sim_profile, rod_profile_intensity_mode)
        bg_profile = None
        bg_curve = None
        if bg_res2 is not None:
            bg_profile = _selected_qr_rod_caked_profile_from_shared_inputs(
                bg_shared,
                selected_entry,
                key,
            )
            bg_curve = _selected_qr_rod_profile_curve(bg_profile, rod_profile_intensity_mode)

        axis.set_title(_selected_qr_rod_axis_title(payload))
        axis.set_ylabel(y_label)
        axis.set_yscale("linear")

        x_values = None
        x_axis_kind = "qz"
        x_axis_label = "Qz (A^-1)"
        sim_line = line_record.get("sim")
        bg_line = line_record.get("bg")
        if sim_profile is not None and sim_curve is not None:
            x_values, x_axis_kind, x_axis_label = _selected_qr_rod_profile_x_axis(sim_profile)
            sim_line.set_data(x_values, sim_curve * scale)
            plotted_any = True
        else:
            sim_line.set_data([], [])
        if bg_profile is not None and bg_curve is not None:
            bg_x_values, bg_axis_kind, bg_axis_label = _selected_qr_rod_profile_x_axis(bg_profile)
            bg_line.set_data(bg_x_values, bg_curve)
            if x_values is None:
                x_values = bg_x_values
                x_axis_kind = bg_axis_kind
                x_axis_label = bg_axis_label
        else:
            bg_line.set_data([], [])
        if idx == len(rod_payloads) - 1:
            axis.set_xlabel(x_axis_label)
        else:
            axis.set_xlabel("")
        axis.legend()

        profiles_by_key[key] = {
            "qz": None
            if sim_profile is None
            else np.asarray(sim_profile["qz_center"], dtype=float),
            "l": (
                None
                if not isinstance(sim_profile, Mapping) or "l_center" not in sim_profile
                else np.asarray(sim_profile["l_center"], dtype=float)
            ),
            "sim": None if sim_curve is None else np.asarray(sim_curve, dtype=float),
            "bg": None if bg_curve is None else np.asarray(bg_curve, dtype=float),
            "sim_profile": sim_profile,
            "bg_profile": bg_profile,
            "metadata": {
                "selected_qr_rod_key": key,
                "signature": payload.get("signature"),
                "include_selected_qr_rod_shape": bool(
                    payload.get("include_selected_qr_rod_shape", False)
                ),
                "selected_qr_rod_shape_available": bool(payload.get("shape_available", False)),
                "selected_qr_rod_shape_pixel_count": int(payload.get("shape_pixel_count", 0) or 0),
            },
        }
        if idx == 0:
            primary_sim_profile = sim_profile
            primary_bg_profile = bg_profile
            primary_sim_curve = sim_curve
            primary_bg_curve = bg_curve
            primary_x = x_values
            primary_x_axis_kind = x_axis_kind
            primary_x_axis_label = x_axis_label
            line_1d_rad = sim_line
            line_1d_rad_bg = bg_line
            line_1d_az = line_record.get("hidden_sim")
            line_1d_az_bg = line_record.get("hidden_bg")

    if not plotted_any:
        return False

    simulation_runtime_state.last_1d_integration_data.update(
        {
            "mode": "selected_qr_rods",
            "selected_qr_rod_keys": list(selected_keys),
            "primary_selected_qr_rod_key": primary_key,
            "selected_qr_rod_profiles": profiles_by_key,
            "radials_sim": primary_x,
            "intensities_2theta_sim": (
                None if primary_sim_curve is None else np.asarray(primary_sim_curve, dtype=float)
            ),
            "azimuths_sim": None,
            "intensities_azimuth_sim": None,
            "radials_bg": primary_x if primary_bg_curve is not None else None,
            "intensities_2theta_bg": (
                None if primary_bg_curve is None else np.asarray(primary_bg_curve, dtype=float)
            ),
            "azimuths_bg": None,
            "intensities_azimuth_bg": None,
            "selected_qr_rod_profile_sim": primary_sim_profile,
            "selected_qr_rod_profile_bg": primary_bg_profile,
            "selected_qr_rod_profile_signature": tuple(
                payload.get("signature") for payload in rod_payloads
            ),
            "include_selected_qr_rod_shape": any(
                bool(payload.get("include_selected_qr_rod_shape", False))
                for payload in rod_payloads
            ),
            "selected_qr_rod_shape_available": any(
                bool(payload.get("shape_available", False)) for payload in rod_payloads
            ),
            "selected_qr_rod_shape_pixel_count": int(
                sum(int(payload.get("shape_pixel_count", 0) or 0) for payload in rod_payloads)
            ),
            "x_axis_kind": primary_x_axis_kind,
            "x_axis_label": primary_x_axis_label,
        }
    )
    _apply_1d_plot_log_scale(redraw=False)
    _render_analysis_peak_overlays(redraw=False)
    if canvas_1d is not None:
        canvas_1d.draw_idle()
    return True


_update_1d_plots_from_selected_qr_rods_caked = _qr_rod_profiled("selected_rod_plot_update")(
    _update_1d_plots_from_selected_qr_rods_caked
)


def _update_1d_plots_from_caked(sim_res2, bg_res2):
    _ensure_analysis_figure()
    _clear_analysis_peak_fit_results(redraw=False, update_text=True)
    if _selected_qr_rod_mode_requested():
        payloads = _current_selected_qr_rod_caked_mask_payloads_for_result(sim_res2)
        if payloads and _update_1d_plots_from_selected_qr_rods_caked(
            sim_res2=sim_res2,
            bg_res2=bg_res2,
            payloads=payloads,
        ):
            return
        _clear_selected_qr_rod_detector_1d_plot()
        _selected_qr_rod_no_profile_status(
            "Selected-Qr rod profile unavailable: caked data or mask missing."
        )
        return

    caked_intensity_mode = _current_caked_intensity_mode()
    i2t_sim, i_phi_sim, az_sim, rad_sim = _caked_profiles_from_sum_fields(
        sim_res2,
        tth_min=tth_min_var.get(),
        tth_max=tth_max_var.get(),
        phi_min=phi_min_var.get(),
        phi_max=phi_max_var.get(),
        intensity_mode=caked_intensity_mode,
    )
    simulation_runtime_state.last_1d_integration_data["radials_sim"] = rad_sim
    simulation_runtime_state.last_1d_integration_data["intensities_2theta_sim"] = i2t_sim
    simulation_runtime_state.last_1d_integration_data["azimuths_sim"] = az_sim
    simulation_runtime_state.last_1d_integration_data["intensities_azimuth_sim"] = i_phi_sim
    simulation_runtime_state.last_1d_integration_data["x_axis_kind"] = "2theta"
    simulation_runtime_state.last_1d_integration_data["x_axis_label"] = "2θ (degrees)"

    scale = _get_scale_factor_value(default=1.0)
    y_label = (
        "Raw accumulated intensity"
        if caked_intensity_mode == "raw_sum"
        else "Intensity density (support-normalized)"
    )
    _set_1d_axes_for_standard_caked_profiles(y_label)
    line_1d_rad.set_data(rad_sim, i2t_sim * scale)
    line_1d_az.set_data(az_sim, i_phi_sim * scale)

    if bg_res2 is not None:
        i2t_bg, i_phi_bg, az_bg, rad_bg = _caked_profiles_from_sum_fields(
            bg_res2,
            tth_min=tth_min_var.get(),
            tth_max=tth_max_var.get(),
            phi_min=phi_min_var.get(),
            phi_max=phi_max_var.get(),
            intensity_mode=caked_intensity_mode,
        )
        simulation_runtime_state.last_1d_integration_data["radials_bg"] = rad_bg
        simulation_runtime_state.last_1d_integration_data["intensities_2theta_bg"] = i2t_bg
        simulation_runtime_state.last_1d_integration_data["azimuths_bg"] = az_bg
        simulation_runtime_state.last_1d_integration_data["intensities_azimuth_bg"] = i_phi_bg
        line_1d_rad_bg.set_data(rad_bg, i2t_bg)
        line_1d_az_bg.set_data(az_bg, i_phi_bg)
    else:
        line_1d_rad_bg.set_data([], [])
        line_1d_az_bg.set_data([], [])
        simulation_runtime_state.last_1d_integration_data["radials_bg"] = None
        simulation_runtime_state.last_1d_integration_data["intensities_2theta_bg"] = None
        simulation_runtime_state.last_1d_integration_data["azimuths_bg"] = None
        simulation_runtime_state.last_1d_integration_data["intensities_azimuth_bg"] = None

    _apply_1d_plot_log_scale(redraw=False)
    _render_analysis_peak_overlays(redraw=False)
    if canvas_1d is not None:
        canvas_1d.draw_idle()


def _refresh_primary_caked_raster_from_cached_state() -> bool:
    if _resolved_primary_analysis_display_mode() != "caked":
        return False
    if simulation_runtime_state.last_caked_image_unscaled is None:
        return False

    try:
        preserved_primary_limits = gui_canvas_interactions.capture_axis_limits(ax)
    except Exception:
        preserved_primary_limits = None

    apply_display = globals().get("_apply_primary_figure_display_from_cached_results")
    if not callable(apply_display):
        return False
    try:
        target_mode = apply_display("caked", preserved_primary_limits)
    except Exception:
        return False
    if target_mode != "caked":
        return False

    apply_projection = globals().get("_apply_current_primary_raster_projection")
    if callable(apply_projection):
        apply_projection()
    request_redraw = globals().get("_request_main_canvas_redraw")
    if callable(request_redraw):
        request_redraw(force_matplotlib=True)
    return True


def _refresh_visible_caked_display_from_cached_results() -> bool:
    show_caked_requested = bool(
        _resolved_primary_analysis_display_mode() == "caked"
        or _current_app_shell_view_mode() == "caked"
        or (
            getattr(analysis_view_controls_view_state, "show_caked_2d_var", None) is not None
            and analysis_view_controls_view_state.show_caked_2d_var.get()
        )
    )
    if not show_caked_requested:
        return False
    if simulation_runtime_state.last_res2_sim is None:
        return False
    refreshed = _restore_caked_display_payload_from_cached_results(
        background_visible=bool(background_runtime_state.visible),
        q_space_requested=bool(_current_app_shell_view_mode() == "q_space"),
    )
    if refreshed:
        refreshed_primary = _refresh_primary_caked_raster_from_cached_state()
        refresh_display = globals().get("_refresh_display_from_controls")
        if callable(refresh_display) and not refreshed_primary:
            refresh_display()
    return bool(refreshed)


def _cached_analysis_display_refresh_needed_for_range_update() -> bool:
    show_caked_requested = bool(
        _resolved_primary_analysis_display_mode() == "caked"
        or _current_app_shell_view_mode() == "caked"
        or (
            getattr(analysis_view_controls_view_state, "show_caked_2d_var", None) is not None
            and analysis_view_controls_view_state.show_caked_2d_var.get()
        )
    )
    if not show_caked_requested:
        return False
    if getattr(simulation_runtime_state, "last_res2_sim", None) is None:
        return False

    if _current_app_shell_view_mode() == "q_space":
        return getattr(simulation_runtime_state, "last_q_space_image_unscaled", None) is None

    if getattr(simulation_runtime_state, "last_caked_image_unscaled", None) is None:
        return True
    if (
        _normalize_caked_intensity_mode(
            getattr(simulation_runtime_state, "last_caked_intensity_mode", "density")
        )
        != _current_caked_intensity_mode()
    ):
        return True
    if (
        getattr(background_runtime_state, "visible", False)
        and getattr(simulation_runtime_state, "last_res2_background", None) is not None
        and (
            getattr(simulation_runtime_state, "last_caked_background_image_unscaled", None) is None
        )
    ):
        return True
    return False


def _refresh_integration_from_cached_results():

    ai = simulation_runtime_state.ai_cache.get("ai")
    refresh_caked_display = _cached_analysis_display_refresh_needed_for_range_update()
    if refresh_caked_display:
        caked_display_refreshed = _refresh_visible_caked_display_from_cached_results()
    else:
        caked_display_refreshed = False
    if not analysis_view_controls_view_state.show_1d_var.get():
        _clear_1d_plot_cache_and_lines()
        refresh_integration_region_visuals()
        _request_overlay_canvas_redraw()
        return True
    if not _analysis_integration_outputs_visible():
        if caked_display_refreshed:
            refresh_integration_region_visuals()
            _request_overlay_canvas_redraw()
        return True

    if simulation_runtime_state.unscaled_image is None:
        return False

    if ai is None:
        return False

    analysis_pending = (
        simulation_runtime_state.analysis_active_job is not None
        or simulation_runtime_state.analysis_queued_job is not None
    )
    if gui_integration_range_drag.range_refresh_requires_pending_analysis_result(
        active_job=simulation_runtime_state.analysis_active_job,
        queued_job=simulation_runtime_state.analysis_queued_job,
        cached_result=simulation_runtime_state.last_res2_sim,
    ):
        return False

    if simulation_runtime_state.last_res2_sim is None:
        simulation_runtime_state.last_res2_sim = caking(simulation_runtime_state.unscaled_image, ai)

    bg_res2 = None
    native_background = _current_background_backend_for_comparison()
    if background_runtime_state.visible and native_background is not None:
        if simulation_runtime_state.last_res2_background is None:
            if not analysis_pending:
                simulation_runtime_state.last_res2_background = caking(native_background, ai)
        bg_res2 = simulation_runtime_state.last_res2_background
    else:
        simulation_runtime_state.last_res2_background = None

    _update_1d_plots_from_caked(simulation_runtime_state.last_res2_sim, bg_res2)
    if refresh_caked_display and not caked_display_refreshed:
        _refresh_visible_caked_display_from_cached_results()
    refresh_integration_region_visuals()
    _request_overlay_canvas_redraw()
    return True


def _clip_bandwidth_percent(value) -> float:
    fallback = float(defaults.get("bandwidth_percent", bandwidth * 100.0))
    try:
        bw_percent = float(value)
    except (TypeError, ValueError, tk.TclError):
        bw_percent = fallback
    if not np.isfinite(bw_percent):
        bw_percent = fallback
    return float(np.clip(bw_percent, 0.0, 10.0))


def _current_bandwidth_fraction() -> float:
    var = globals().get("bandwidth_percent_var")
    if var is None:
        return float(max(0.0, bandwidth))
    try:
        bw_percent = var.get()
    except Exception:
        bw_percent = defaults.get("bandwidth_percent", bandwidth * 100.0)
    return _clip_bandwidth_percent(bw_percent) / 100.0


def update_mosaic_cache():
    """
    Keep the current beam/mosaic samples unless sampling inputs changed.

    This preserves the same sampled beam positions/divergence across normal
    simulation updates so changing unrelated sliders does not rebuild the
    detector pattern unnecessarily.
    """
    active_bandwidth = _current_bandwidth_fraction()
    expected_sample_count = int(max(1, simulation_runtime_state.num_samples))
    sampling_signature = (
        RANDOM_GAUSSIAN_SAMPLING,
        expected_sample_count,
        float(divergence_sigma),
        float(bw_sigma),
        float(lambda_),
        float(active_bandwidth),
    )

    beam_x_cached = np.asarray(
        simulation_runtime_state.profile_cache.get("beam_x_array", []), dtype=np.float64
    ).ravel()
    beam_y_cached = np.asarray(
        simulation_runtime_state.profile_cache.get("beam_y_array", []), dtype=np.float64
    ).ravel()
    theta_cached = np.asarray(
        simulation_runtime_state.profile_cache.get("theta_array", []), dtype=np.float64
    ).ravel()
    phi_cached = np.asarray(
        simulation_runtime_state.profile_cache.get("phi_array", []), dtype=np.float64
    ).ravel()
    wavelength_cached = np.asarray(
        simulation_runtime_state.profile_cache.get("wavelength_array", []), dtype=np.float64
    ).ravel()

    has_cached_samples = (
        beam_x_cached.size > 0
        and beam_x_cached.size == int(expected_sample_count)
        and beam_y_cached.size == beam_x_cached.size
        and theta_cached.size == beam_x_cached.size
        and phi_cached.size == beam_x_cached.size
        and wavelength_cached.size == beam_x_cached.size
    )

    cached_signature = simulation_runtime_state.profile_cache.get("_sampling_signature")
    should_resample = not has_cached_samples
    if has_cached_samples:
        if cached_signature is None:
            # Existing externally-provided samples: keep them and adopt the
            # current signature so future explicit sampling-input changes can
            # trigger a re-sample.
            simulation_runtime_state.profile_cache["_sampling_signature"] = sampling_signature
        else:
            should_resample = tuple(cached_signature) != sampling_signature

    if should_resample:
        (
            beam_x_array,
            beam_y_array,
            theta_array,
            phi_array,
            wavelength_array,
        ) = generate_random_profiles(
            num_samples=expected_sample_count,
            divergence_sigma=divergence_sigma,
            bw_sigma=bw_sigma,
            lambda0=lambda_,
            bandwidth=active_bandwidth,
        )
        sample_weights_array = None
        simulation_runtime_state.profile_cache = {
            "beam_x_array": beam_x_array,
            "beam_y_array": beam_y_array,
            "theta_array": theta_array,
            "phi_array": phi_array,
            "wavelength_array": wavelength_array,
            "sample_weights": sample_weights_array,
            "_sampling_signature": sampling_signature,
        }
    else:
        sample_weights_array = simulation_runtime_state.profile_cache.get("sample_weights")

    active_optics_cif_path = _resolve_optics_cif_path()
    optics_signature = (
        tuple(
            simulation_runtime_state.profile_cache.get("_sampling_signature", sampling_signature)
        ),
        os.path.abspath(str(active_optics_cif_path)),
        bool(_debug_refraction_disabled()),
    )
    if simulation_runtime_state.profile_cache.get("_optics_signature") != optics_signature:
        (
            n2_sample_array,
            n2_source_meta,
            n2_wavelength_snapshot,
        ) = _current_sample_n2_payload(
            simulation_runtime_state.profile_cache.get("wavelength_array", []),
            active_cif_path=active_optics_cif_path,
        )
        simulation_runtime_state.profile_cache["n2_sample_array"] = n2_sample_array
        simulation_runtime_state.profile_cache["_n2_sample_array_source"] = n2_source_meta
        simulation_runtime_state.profile_cache["_n2_sample_array_wavelength_snapshot"] = (
            n2_wavelength_snapshot
        )
        simulation_runtime_state.profile_cache["_optics_signature"] = optics_signature

    simulation_runtime_state.profile_cache.update(
        {
            "sigma_mosaic_deg": sigma_mosaic_var.get(),
            "gamma_mosaic_deg": gamma_mosaic_var.get(),
            "eta": eta_var.get(),
            "solve_q_steps": current_solve_q_values().steps,
            "solve_q_rel_tol": current_solve_q_values().rel_tol,
            "solve_q_mode": current_solve_q_values().mode_flag,
            "bandwidth_percent": active_bandwidth * 100.0,
            "sample_weights": sample_weights_array,
            "_refraction_effects_disabled": bool(_debug_refraction_disabled()),
        }
    )


