def _worker_job_key(payload: object) -> tuple[object, int, str]:
    if not isinstance(payload, dict):
        return (None, -1, "full")
    return (
        payload.get("signature"),
        int(payload.get("epoch", -1)),
        str(payload.get("job_kind", "full")),
    )


def _selection_cache_refresh_active_sides(payload: object) -> tuple[str, ...]:
    if not isinstance(payload, dict) or str(payload.get("job_kind", "full")) != "full":
        return ()
    active_sides = _normalized_active_peak_row_sides(payload.get("active_peak_row_sides", ()))
    if not active_sides:
        return ()
    has_active_side_build = False
    for side in active_sides:
        if bool(payload.get(f"build_{side}_intersection_cache", False)) or bool(
            payload.get(f"{side}_intersection_cache_built", False)
        ):
            has_active_side_build = True
            break
    return active_sides if has_active_side_build else ()


def _selection_cache_refresh_job_matches(existing: object, requested: object) -> bool:
    if not isinstance(existing, dict) or not isinstance(requested, dict):
        return False
    requested_sides = _selection_cache_refresh_active_sides(requested)
    if not requested_sides:
        return False
    if _selection_cache_refresh_active_sides(existing) != requested_sides:
        return False
    return _worker_job_key(existing) == _worker_job_key(requested)


def _hit_table_state_present_for_run_sides(
    *,
    run_primary: bool,
    run_secondary: bool,
    run_sixh_reference: bool = False,
    run_disordered_phase: bool = False,
) -> bool:
    if bool(run_primary) and simulation_runtime_state.stored_primary_max_positions is None:
        return False
    if bool(run_secondary) and simulation_runtime_state.stored_secondary_max_positions is None:
        return False
    if (
        bool(run_sixh_reference)
        and getattr(simulation_runtime_state, "stored_sixh_reference_max_positions", None) is None
    ):
        return False
    if bool(run_disordered_phase) and _disordered_phase_stored_hit_table_row_count() <= 0:
        return False
    return True


def _active_peak_row_sides_for_job(
    *,
    job_kind: str,
    run_primary: bool,
    run_secondary: bool,
    secondary_available: bool,
) -> tuple[str, ...]:
    normalized_job_kind = str(job_kind or "full")
    if normalized_job_kind == "preview":
        return ()
    if normalized_job_kind == "primary_fill":
        return ("primary",) if bool(run_primary) else ()
    active_sides: list[str] = []
    if bool(run_primary):
        active_sides.append("primary")
    if bool(run_secondary) and bool(secondary_available):
        active_sides.append("secondary")
    return tuple(active_sides)


def _normalized_active_peak_row_sides(value: object) -> tuple[str, ...]:
    if not isinstance(value, Sequence) or isinstance(value, (str, bytes)):
        return ()
    normalized: list[str] = []
    for raw_side in value:
        side = str(raw_side or "").strip().lower()
        if side not in {"primary", "secondary"} or side in normalized:
            continue
        normalized.append(side)
    return tuple(normalized)


def _active_peak_row_sides_have_fresh_raw_rows(
    active_peak_row_sides: Sequence[object] | None,
    *,
    primary_raw_rows_fresh: bool,
    secondary_raw_rows_fresh: bool,
) -> bool:
    active_sides = _normalized_active_peak_row_sides(active_peak_row_sides)
    if not active_sides:
        return False
    for side in active_sides:
        if side == "primary" and not bool(primary_raw_rows_fresh):
            return False
        if side == "secondary" and not bool(secondary_raw_rows_fresh):
            return False
    return True


def _table_row_count(table_payload: object) -> int:
    if table_payload is None:
        return 0
    if isinstance(table_payload, Mapping):
        return 1
    if isinstance(table_payload, np.ndarray):
        if table_payload.ndim >= 2:
            return int(table_payload.shape[0])
        return int(table_payload.size > 0)
    if not isinstance(table_payload, Sequence) or isinstance(
        table_payload,
        (str, bytes),
    ):
        try:
            table_payload = list(table_payload)
        except Exception:
            return 0
    row_count = 0
    for table in table_payload:
        if isinstance(table, Mapping):
            row_count += 1
            continue
        try:
            rows = gui_geometry_q_group_manager.geometry_reference_hit_rows(table)
        except Exception:
            rows = []
        if rows:
            row_count += int(len(rows))
            continue
        try:
            arr = np.asarray(table)
        except Exception:
            continue
        if arr.ndim >= 2:
            row_count += int(arr.shape[0])
        elif arr.size > 0:
            row_count += 1
    return int(row_count)


def _disordered_phase_stored_hit_table_row_count() -> int:
    return _table_row_count(
        getattr(
            simulation_runtime_state,
            "stored_disordered_phase_max_positions",
            None,
        )
    )


def _disordered_phase_stored_rows_available() -> bool:
    return _disordered_phase_stored_hit_table_row_count() > 0


def _cached_hit_tables_reusable(
    requested_signature: object,
    *,
    run_primary: bool,
    run_secondary: bool,
    run_sixh_reference: bool = False,
    run_disordered_phase: bool = False,
) -> bool:
    if requested_signature != simulation_runtime_state.stored_hit_table_signature:
        return False
    return _hit_table_state_present_for_run_sides(
        run_primary=run_primary,
        run_secondary=run_secondary,
        run_sixh_reference=run_sixh_reference,
        run_disordered_phase=run_disordered_phase,
    )


def _side_detector_cache_is_current(side: str, current_signature: object) -> bool:
    if current_signature is None:
        return False
    normalized_side = str(side or "").strip().lower()
    if normalized_side == "primary":
        side_signature = getattr(
            simulation_runtime_state,
            "stored_primary_intersection_cache_signature",
            None,
        )
        return (
            side_signature is not None
            and current_signature == side_signature
            and getattr(simulation_runtime_state, "stored_primary_intersection_cache", None)
            is not None
        )
    if normalized_side == "secondary":
        side_signature = getattr(
            simulation_runtime_state,
            "stored_secondary_intersection_cache_signature",
            None,
        )
        return (
            side_signature is not None
            and current_signature == side_signature
            and getattr(simulation_runtime_state, "stored_secondary_intersection_cache", None)
            is not None
        )
    return False


