def _geometry_active_primary_cif_path_for_disordered_phase() -> str | None:
    try:
        active_primary_cif = _active_primary_cif_path()
    except Exception:
        return None
    if active_primary_cif in (None, ""):
        return None
    try:
        return str(Path(str(active_primary_cif)).resolve())
    except Exception:
        return str(active_primary_cif) if str(active_primary_cif).strip() else None


def _geometry_disordered_phase_qr_enable_status() -> DisorderedPhaseQrEnableStatus:
    raw_weights = _geometry_disordered_phase_raw_weight_values()
    stacking_disorder_enabled = any(abs(float(weight)) > 1.0e-12 for weight in raw_weights)
    nonzero_disordered_weight = any(abs(float(raw_weights[index])) > 1.0e-12 for index in (1, 2))
    active_primary_cif_path = _geometry_active_primary_cif_path_for_disordered_phase()

    if not _geometry_generated_disordered_qr_reference_checked():
        return DisorderedPhaseQrEnableStatus(
            enabled=False,
            reason="checkbox disabled",
            stacking_disorder_enabled=bool(stacking_disorder_enabled),
            nonzero_disordered_weight=bool(nonzero_disordered_weight),
            active_primary_cif_path=active_primary_cif_path,
        )
    if not bool(stacking_disorder_enabled):
        return DisorderedPhaseQrEnableStatus(
            enabled=False,
            reason="stacking disorder disabled",
            stacking_disorder_enabled=False,
            nonzero_disordered_weight=bool(nonzero_disordered_weight),
            active_primary_cif_path=active_primary_cif_path,
        )
    if not bool(nonzero_disordered_weight):
        return DisorderedPhaseQrEnableStatus(
            enabled=False,
            reason="zero disordered weight",
            stacking_disorder_enabled=True,
            nonzero_disordered_weight=False,
            active_primary_cif_path=active_primary_cif_path,
        )
    if active_primary_cif_path is None:
        return DisorderedPhaseQrEnableStatus(
            enabled=False,
            reason="no active primary CIF",
            stacking_disorder_enabled=True,
            nonzero_disordered_weight=True,
            active_primary_cif_path=None,
        )
    return DisorderedPhaseQrEnableStatus(
        enabled=True,
        reason="enabled",
        stacking_disorder_enabled=True,
        nonzero_disordered_weight=True,
        active_primary_cif_path=active_primary_cif_path,
    )


def _geometry_disordered_phase_qr_enabled() -> bool:
    return _geometry_disordered_phase_qr_enable_status().enabled


def _file_sha256_or_mtime_signature(path: str | Path | None) -> tuple[str, object] | None:
    if path is None:
        return None
    file_path = Path(str(path))
    try:
        digest = hashlib.sha256()
        with file_path.open("rb") as handle:
            for chunk in iter(lambda: handle.read(1024 * 1024), b""):
                digest.update(chunk)
        return ("sha256", digest.hexdigest())
    except Exception:
        try:
            stat = file_path.stat()
        except Exception:
            return None
        return ("mtime_ns", int(stat.st_mtime_ns), int(stat.st_size))


def _geometry_disordered_phase_cell_override_signature() -> tuple[object, object]:
    values: list[object] = []
    for name in ("a_var", "c_var"):
        value = _runtime_var_float(name, float("nan"))
        values.append(round(float(value), 9) if np.isfinite(value) else None)
    return tuple(values)  # type: ignore[return-value]


def _geometry_disordered_phase_atom_fractional_signature() -> object:
    try:
        return _atom_site_fractional_signature(_current_atom_site_fractional_values())
    except Exception:
        return None


def _geometry_disordered_phase_occupancy_signature() -> tuple[object, ...]:
    values: list[object] = []
    try:
        occupancy_vars = _occupancy_control_vars()
    except Exception:
        occupancy_vars = []
    for occ_var in occupancy_vars or ():
        getter = getattr(occ_var, "get", None)
        try:
            value = getter() if callable(getter) else occ_var
            numeric = float(value)
        except Exception:
            values.append(None)
            continue
        values.append(round(float(numeric), 9) if np.isfinite(numeric) else None)
    return tuple(values)


def _clear_disordered_phase_runtime_tables(*, clear_inventory: bool = False) -> None:
    simulation_runtime_state.stored_disordered_phase_max_positions = None
    simulation_runtime_state.stored_disordered_phase_source_reflection_indices = None
    simulation_runtime_state.stored_disordered_phase_peak_table_lattice = None
    simulation_runtime_state.generated_disordered_phase_cif_path = None
    if bool(clear_inventory):
        simulation_runtime_state.disordered_phase_inventory_cache = None
    _invalidate_geometry_q_group_entries_cache_only()
    _invalidate_manual_pick_projection_cache_only()


def _geometry_disordered_phase_source_signature() -> tuple[object, ...]:
    status = _geometry_disordered_phase_qr_enable_status()
    if not status.enabled:
        return ("disordered_phase_qr_reference", False)

    p_values, weights = _geometry_disordered_phase_stack_values()
    active_path = status.active_primary_cif_path
    try:
        lambda_value = float(lambda_)
    except Exception:
        lambda_value = float("nan")
    try:
        two_theta_signature = tuple(
            round(float(value), 6) if np.isfinite(float(value)) else None
            for value in tuple(two_theta_range)
        )
    except Exception:
        two_theta_signature = ()
    try:
        mx_value = int(mx)
    except Exception:
        mx_value = 0
    try:
        threshold_value = float(intensity_threshold)
    except Exception:
        threshold_value = float("nan")

    return (
        "disordered_phase_qr_reference",
        True,
        active_path,
        _file_sha256_or_mtime_signature(active_path),
        True,
        _geometry_disordered_phase_cell_override_signature(),
        _geometry_disordered_phase_atom_fractional_signature(),
        _geometry_disordered_phase_occupancy_signature(),
        round(float(p_values[0]), 9),
        round(float(p_values[1]), 9),
        round(float(p_values[2]), 9),
        round(float(weights[0]), 9),
        round(float(weights[1]), 9),
        round(float(weights[2]), 9),
        int(mx_value),
        round(float(lambda_value), 9) if np.isfinite(lambda_value) else None,
        two_theta_signature,
        round(float(threshold_value), 6) if np.isfinite(threshold_value) else None,
        DISORDERED_PHASE_QR_GENERATOR_VERSION,
        ("inventory_mode_policy", "compact_6h_then_explicit_p1"),
        ("reference_threshold", 0.0),
    )


def _geometry_disordered_phase_inventory_payload(*, log_status: bool = True) -> dict[str, object]:
    signature = _geometry_disordered_phase_source_signature()
    disordered_qr_reference_threshold = 0.0

    def _empty_payload(
        *,
        skip_reason: str | None,
        diagnostics: Mapping[str, object] | None = None,
    ) -> dict[str, object]:
        payload = {
            "signature": signature,
            "miller": np.empty((0, 3), dtype=np.float64),
            "intensities": np.empty((0,), dtype=np.float64),
            "a": float("nan"),
            "c": float("nan"),
            "source_label": DISORDERED_PHASE_SOURCE_LABEL,
            "phase_label": DISORDERED_PHASE_DISPLAY_LABEL,
            "cif_path": None,
            "available": False,
            "skip_reason": skip_reason,
            "inventory_mode": None,
            "diagnostics": dict(diagnostics or {}),
        }
        if log_status:
            _log_disordered_qr_inventory_status(
                payload,
                active_primary_cif_path=payload["diagnostics"].get("source_cif"),
            )
        return payload

    if len(signature) < 2 or not bool(signature[1]):
        status = _geometry_disordered_phase_qr_enable_status()
        _clear_disordered_phase_runtime_tables(clear_inventory=True)
        return _empty_payload(skip_reason=str(status.reason))

    if log_status:
        _log_visible_disordered_qr_status("Disordered Qr refs enabled: true", enabled=True)
    cached = getattr(simulation_runtime_state, "disordered_phase_inventory_cache", None)
    if isinstance(cached, Mapping) and cached.get("signature") == signature:
        cached_path = cached.get("cif_path")
        simulation_runtime_state.generated_disordered_phase_cif_path = (
            str(cached_path) if cached_path else None
        )
        payload = {
            "signature": signature,
            "miller": np.asarray(cached.get("miller", ()), dtype=np.float64).copy(),
            "intensities": np.asarray(cached.get("intensities", ()), dtype=np.float64).copy(),
            "a": float(cached.get("a", float("nan"))),
            "c": float(cached.get("c", float("nan"))),
            "source_label": DISORDERED_PHASE_SOURCE_LABEL,
            "phase_label": DISORDERED_PHASE_DISPLAY_LABEL,
            "cif_path": cached_path,
            "available": bool(cached.get("available", True)),
            "skip_reason": cached.get("skip_reason"),
            "inventory_mode": cached.get("inventory_mode"),
            "diagnostics": dict(cached.get("diagnostics", {}) or {}),
        }
        if log_status:
            _log_disordered_qr_inventory_status(
                payload,
                active_primary_cif_path=payload["diagnostics"].get("source_cif"),
            )
        return payload

    if isinstance(cached, Mapping) and cached.get("signature") != signature:
        _clear_disordered_phase_runtime_tables(clear_inventory=False)

    active_primary_cif_path = signature[2] if len(signature) > 2 else None
    try:
        current_threshold = float(intensity_threshold)
    except Exception:
        current_threshold = float("nan")
    try:
        mx_value = int(mx)
    except Exception:
        mx_value = 0
    try:
        lambda_value = float(lambda_)
    except Exception:
        lambda_value = float("nan")
    try:
        theta_range = tuple(two_theta_range)
    except Exception:
        theta_range = ()
    diagnostics: dict[str, object] = {
        "source_cif": None if active_primary_cif_path is None else str(active_primary_cif_path),
        "source_cif_exists": False,
        "generated_cif": None,
        "generated_cif_exists": False,
        "generator_error_type": None,
        "generator_error_message": None,
        "miller_error_type": None,
        "miller_error_message": None,
        "current_threshold_miller_count": 0,
        "current_threshold_intensity_count": 0,
        "reference_threshold_miller_count": 0,
        "reference_threshold_intensity_count": 0,
        "a": float("nan"),
        "c": float("nan"),
        "intensity_threshold": current_threshold,
        "reference_threshold": disordered_qr_reference_threshold,
        "two_theta_range": theta_range,
        "mx": mx_value,
        "inventory_mode": None,
        "generator_version": DISORDERED_PHASE_QR_GENERATOR_VERSION,
    }

    if active_primary_cif_path is None:
        simulation_runtime_state.generated_disordered_phase_cif_path = None
        return _empty_payload(
            skip_reason="active primary CIF not found: None",
            diagnostics=diagnostics,
        )

    source_path = Path(str(active_primary_cif_path)).expanduser().resolve()
    diagnostics["source_cif"] = str(source_path)
    diagnostics["source_cif_exists"] = source_path.is_file()
    if not source_path.is_file():
        simulation_runtime_state.generated_disordered_phase_cif_path = None
        return _empty_payload(
            skip_reason=f"active primary CIF not found: {source_path}",
            diagnostics=diagnostics,
        )

    def _generate(mode: str):
        try:
            generated_value = generate_pbii_ht_shifted_cif(
                source_cif=source_path,
                output_dir=_disordered_phase_cif_cache_dir(),
                mode=mode,
            )
        except Exception as exc:
            diagnostics["generator_error_type"] = type(exc).__name__
            diagnostics["generator_error_message"] = str(exc)
            return None, f"generated CIF failed: {type(exc).__name__}: {exc}"
        generated_path = Path(generated_value.cif_path).expanduser().resolve()
        diagnostics["generated_cif"] = str(generated_path)
        diagnostics["generated_cif_exists"] = generated_path.is_file()
        diagnostics["a"] = float(getattr(generated_value, "a", float("nan")))
        diagnostics["c"] = float(getattr(generated_value, "c", float("nan")))
        diagnostics["inventory_mode"] = str(mode)
        if not generated_path.is_file():
            return generated_value, f"generated CIF missing: {generated_path}"
        return generated_value, None

    def _miller_for(generated_value, *, threshold: float):
        try:
            energy_kev = 12.398419843320026 / lambda_value
            miller_values, intensity_values, _deg, _details = miller_generator(
                mx_value,
                str(generated_value.cif_path),
                [1.0],
                lambda_value,
                energy=energy_kev,
                intensity_threshold=float(threshold),
                two_theta_range=theta_range,
            )
        except Exception as exc:
            diagnostics["miller_error_type"] = type(exc).__name__
            diagnostics["miller_error_message"] = str(exc)
            return (
                np.empty((0, 3), dtype=np.float64),
                np.empty((0,), dtype=np.float64),
                f"generated Miller calculation failed: {type(exc).__name__}: {exc}",
            )
        miller_values = np.asarray(miller_values, dtype=np.float64)
        intensity_values = np.asarray(intensity_values, dtype=np.float64).reshape(-1)
        return miller_values, intensity_values, None

    generated, skip_reason = _generate("compact_6h")
    if skip_reason is not None:
        simulation_runtime_state.generated_disordered_phase_cif_path = None
        return _empty_payload(skip_reason=skip_reason, diagnostics=diagnostics)

    current_miller, current_intensities, current_error = _miller_for(
        generated,
        threshold=current_threshold,
    )
    if current_error is not None:
        fallback_reason = current_error
    else:
        diagnostics["current_threshold_miller_count"] = int(
            current_miller.shape[0] if current_miller.ndim == 2 else 0
        )
        diagnostics["current_threshold_intensity_count"] = int(current_intensities.size)
        fallback_reason = None

    reference_miller, reference_intensities, reference_error = _miller_for(
        generated,
        threshold=disordered_qr_reference_threshold,
    )
    if reference_error is not None:
        fallback_reason = reference_error
    else:
        diagnostics["reference_threshold_miller_count"] = int(
            reference_miller.shape[0] if reference_miller.ndim == 2 else 0
        )
        diagnostics["reference_threshold_intensity_count"] = int(reference_intensities.size)
        if diagnostics["reference_threshold_miller_count"] <= 0:
            fallback_reason = (
                "generated Miller rows empty; "
                f"mx={mx_value} threshold={disordered_qr_reference_threshold:g} "
                f"two_theta_range={theta_range}"
            )

    selected_generated = generated
    selected_miller = reference_miller
    selected_intensities = reference_intensities
    selected_mode = "compact_6h"
    if fallback_reason is not None:
        _log_visible_disordered_qr_status(
            f"Disordered Qr refs inventory: using explicit-P1 fallback because {fallback_reason}"
        )
        diagnostics["compact_6h_skip_reason"] = fallback_reason
        fallback_generated, fallback_generate_error = _generate("explicit_p1")
        if fallback_generate_error is not None:
            simulation_runtime_state.generated_disordered_phase_cif_path = None
            return _empty_payload(skip_reason=fallback_generate_error, diagnostics=diagnostics)
        fallback_miller, fallback_intensities, fallback_error = _miller_for(
            fallback_generated,
            threshold=disordered_qr_reference_threshold,
        )
        diagnostics["reference_threshold_miller_count"] = int(
            fallback_miller.shape[0] if fallback_miller.ndim == 2 else 0
        )
        diagnostics["reference_threshold_intensity_count"] = int(fallback_intensities.size)
        if fallback_error is not None:
            simulation_runtime_state.generated_disordered_phase_cif_path = None
            return _empty_payload(skip_reason=fallback_error, diagnostics=diagnostics)
        if diagnostics["reference_threshold_miller_count"] <= 0:
            simulation_runtime_state.generated_disordered_phase_cif_path = None
            return _empty_payload(
                skip_reason=(
                    "generated Miller rows empty after explicit-P1 fallback; "
                    f"mx={mx_value} threshold={disordered_qr_reference_threshold:g} "
                    f"two_theta_range={theta_range}"
                ),
                diagnostics=diagnostics,
            )
        selected_generated = fallback_generated
        selected_miller = fallback_miller
        selected_intensities = fallback_intensities
        selected_mode = "explicit_p1"
        diagnostics["inventory_mode"] = selected_mode

    a_disordered = float(getattr(selected_generated, "a", float("nan")))
    c_disordered = float(getattr(selected_generated, "c", float("nan")))
    diagnostics["a"] = a_disordered
    diagnostics["c"] = c_disordered
    if not (np.isfinite(a_disordered) and a_disordered > 0.0):
        simulation_runtime_state.generated_disordered_phase_cif_path = None
        return _empty_payload(
            skip_reason=f"bad generated a value: {a_disordered}", diagnostics=diagnostics
        )
    if not (np.isfinite(c_disordered) and c_disordered > 0.0):
        simulation_runtime_state.generated_disordered_phase_cif_path = None
        return _empty_payload(
            skip_reason=f"bad generated c value: {c_disordered}", diagnostics=diagnostics
        )

    cif_path_text = str(Path(selected_generated.cif_path).expanduser().resolve())
    simulation_runtime_state.generated_disordered_phase_cif_path = cif_path_text

    payload = {
        "signature": signature,
        "miller": np.asarray(selected_miller, dtype=np.float64).copy(),
        "intensities": np.asarray(selected_intensities, dtype=np.float64).reshape(-1).copy(),
        "a": float(a_disordered),
        "c": float(c_disordered),
        "source_label": DISORDERED_PHASE_SOURCE_LABEL,
        "phase_label": DISORDERED_PHASE_DISPLAY_LABEL,
        "cif_path": cif_path_text,
        "available": True,
        "skip_reason": None,
        "inventory_mode": selected_mode,
        "diagnostics": dict(diagnostics),
    }
    simulation_runtime_state.disordered_phase_inventory_cache = {
        "signature": signature,
        "miller": np.asarray(payload["miller"], dtype=np.float64).copy(),
        "intensities": np.asarray(payload["intensities"], dtype=np.float64).copy(),
        "a": float(a_disordered),
        "c": float(c_disordered),
        "source_label": DISORDERED_PHASE_SOURCE_LABEL,
        "phase_label": DISORDERED_PHASE_DISPLAY_LABEL,
        "cif_path": cif_path_text,
        "available": True,
        "skip_reason": None,
        "inventory_mode": selected_mode,
        "diagnostics": dict(diagnostics),
    }
    if log_status:
        _log_disordered_qr_inventory_status(
            payload,
            active_primary_cif_path=str(source_path),
        )
    return payload


def _publish_combined_simulation_state(
    *,
    image_size_value: int,
    primary_a_value: float,
    primary_c_value: float,
    secondary_a_value: float,
    secondary_c_value: float,
    active_peak_row_sides: Sequence[object] | None = None,
    theta_initial_value: float | None = None,
) -> dict[str, object]:
    w1 = float(weight1_var.get())
    w2 = float(weight2_var.get())
    run_primary = bool(
        simulation_runtime_state.stored_primary_sim_image is not None and abs(w1) > 1e-12
    )
    run_secondary = bool(
        simulation_runtime_state.stored_secondary_sim_image is not None and abs(w2) > 1e-12
    )
    if active_peak_row_sides is None:
        active_display_sides = (
            ()
            if bool(getattr(simulation_runtime_state, "preview_active", False))
            else _active_peak_row_sides_for_job(
                job_kind="full",
                run_primary=run_primary,
                run_secondary=run_secondary,
                secondary_available=run_secondary,
            )
        )
    else:
        active_display_sides = _normalized_active_peak_row_sides(active_peak_row_sides)
    include_disordered_phase_peak_rows = bool(
        _geometry_disordered_phase_qr_enabled() and _disordered_phase_stored_rows_available()
    )
    include_primary_peak_rows = bool(
        "primary" in active_display_sides
        or (
            include_disordered_phase_peak_rows
            and simulation_runtime_state.stored_primary_max_positions is not None
        )
    )
    include_secondary_peak_rows = "secondary" in active_display_sides

    img1 = (
        simulation_runtime_state.stored_primary_sim_image
        if simulation_runtime_state.stored_primary_sim_image is not None
        else np.zeros((image_size_value, image_size_value), dtype=np.float64)
    )
    img2 = (
        simulation_runtime_state.stored_secondary_sim_image
        if simulation_runtime_state.stored_secondary_sim_image is not None
        else np.zeros((image_size_value, image_size_value), dtype=np.float64)
    )
    updated_image = w1 * img1 + w2 * img2

    max_positions_local: list[object] = []
    source_reflection_indices_local: list[int] = []
    peak_table_lattice_local: list[object] = []
    primary_max_positions_local: list[object] = []
    primary_peak_table_lattice_local: list[object] = []
    if (
        include_primary_peak_rows
        and simulation_runtime_state.stored_primary_max_positions is not None
    ):
        primary_max_positions_local = list(simulation_runtime_state.stored_primary_max_positions)
        max_positions_local.extend(primary_max_positions_local)
        if simulation_runtime_state.stored_primary_source_reflection_indices is not None:
            source_reflection_indices_local.extend(
                simulation_runtime_state.stored_primary_source_reflection_indices
            )
        if simulation_runtime_state.stored_primary_peak_table_lattice is not None:
            primary_peak_table_lattice_local = list(
                simulation_runtime_state.stored_primary_peak_table_lattice
            )

    secondary_max_positions_local: list[object] = []
    secondary_peak_table_lattice_local: list[object] = []
    if (
        include_secondary_peak_rows
        and simulation_runtime_state.stored_secondary_max_positions is not None
    ):
        secondary_max_positions_local = list(
            simulation_runtime_state.stored_secondary_max_positions
        )
        max_positions_local.extend(secondary_max_positions_local)
        if simulation_runtime_state.stored_secondary_source_reflection_indices is not None:
            source_reflection_indices_local.extend(
                simulation_runtime_state.stored_secondary_source_reflection_indices
            )
        if simulation_runtime_state.stored_secondary_peak_table_lattice is not None:
            secondary_peak_table_lattice_local = list(
                simulation_runtime_state.stored_secondary_peak_table_lattice
            )

    sixh_reference_max_positions_local: list[object] = []
    sixh_reference_peak_table_lattice_local: list[object] = []
    if (
        include_primary_peak_rows
        and _geometry_6h_qr_reference_enabled()
        and getattr(simulation_runtime_state, "stored_sixh_reference_max_positions", None)
        is not None
    ):
        sixh_reference_max_positions_local = list(
            simulation_runtime_state.stored_sixh_reference_max_positions
        )
        max_positions_local.extend(sixh_reference_max_positions_local)
        stored_sixh_indices = getattr(
            simulation_runtime_state,
            "stored_sixh_reference_source_reflection_indices",
            None,
        )
        if stored_sixh_indices is not None:
            source_reflection_indices_local.extend(list(stored_sixh_indices))
        if getattr(simulation_runtime_state, "stored_sixh_reference_peak_table_lattice", None):
            sixh_reference_peak_table_lattice_local = list(
                simulation_runtime_state.stored_sixh_reference_peak_table_lattice
            )

    disordered_phase_max_positions_local: list[object] = []
    disordered_phase_peak_table_lattice_local: list[object] = []
    if include_disordered_phase_peak_rows:
        disordered_phase_max_positions_local = list(
            simulation_runtime_state.stored_disordered_phase_max_positions
        )
        max_positions_local.extend(disordered_phase_max_positions_local)
        stored_disordered_indices = getattr(
            simulation_runtime_state,
            "stored_disordered_phase_source_reflection_indices",
            None,
        )
        if stored_disordered_indices is not None:
            source_reflection_indices_local.extend(list(stored_disordered_indices))
        if getattr(simulation_runtime_state, "stored_disordered_phase_peak_table_lattice", None):
            disordered_phase_peak_table_lattice_local = list(
                simulation_runtime_state.stored_disordered_phase_peak_table_lattice
            )

    if len(primary_peak_table_lattice_local) == len(primary_max_positions_local):
        peak_table_lattice_local.extend(primary_peak_table_lattice_local)
    else:
        peak_table_lattice_local.extend(
            [
                (float(primary_a_value), float(primary_c_value), "primary")
                for _ in primary_max_positions_local
            ]
        )
    if len(secondary_peak_table_lattice_local) == len(secondary_max_positions_local):
        peak_table_lattice_local.extend(secondary_peak_table_lattice_local)
    else:
        peak_table_lattice_local.extend(
            [
                (float(secondary_a_value), float(secondary_c_value), "secondary")
                for _ in secondary_max_positions_local
            ]
        )
    if len(sixh_reference_peak_table_lattice_local) == len(sixh_reference_max_positions_local):
        peak_table_lattice_local.extend(sixh_reference_peak_table_lattice_local)
    else:
        sixh_payload = _geometry_6h_reference_inventory_payload()
        peak_table_lattice_local.extend(
            [
                (
                    float(sixh_payload.get("a", float("nan"))),
                    float(sixh_payload.get("c", float("nan"))),
                    PBII_6H_QR_REFERENCE_SOURCE_LABEL,
                )
                for _ in sixh_reference_max_positions_local
            ]
        )
    if len(disordered_phase_peak_table_lattice_local) == len(disordered_phase_max_positions_local):
        peak_table_lattice_local.extend(disordered_phase_peak_table_lattice_local)
    else:
        disordered_payload = _geometry_disordered_phase_inventory_payload()
        peak_table_lattice_local.extend(
            [
                (
                    float(disordered_payload.get("a", float("nan"))),
                    float(disordered_payload.get("c", float("nan"))),
                    DISORDERED_PHASE_SOURCE_LABEL,
                    DISORDERED_PHASE_DISPLAY_LABEL,
                    "disordered",
                )
                for _ in disordered_phase_max_positions_local
            ]
        )

    simulation_runtime_state.stored_max_positions_local = list(max_positions_local)
    row_content_signature = (
        gui_geometry_q_group_manager._geometry_q_group_content_signature_from_hit_tables(
            max_positions_local
        )
    )
    if theta_initial_value is not None:
        try:
            theta_initial_float = float(theta_initial_value)
        except Exception:
            theta_initial_float = float("nan")
        if np.isfinite(theta_initial_float):
            row_content_signature = (
                "q_group_content_with_theta_initial",
                row_content_signature,
                ("theta_initial", round(float(theta_initial_float), 6)),
            )
    simulation_runtime_state.stored_q_group_content_signature = row_content_signature
    simulation_runtime_state.stored_source_reflection_indices_local = (
        list(source_reflection_indices_local)
        if len(source_reflection_indices_local) == len(max_positions_local)
        else None
    )
    simulation_runtime_state.stored_peak_table_lattice = list(peak_table_lattice_local)
    if include_disordered_phase_peak_rows:
        disordered_lattice_for_log = (
            peak_table_lattice_local[-len(disordered_phase_max_positions_local) :]
            if disordered_phase_max_positions_local
            else []
        )
        _log_disordered_qr_published_counts(
            disordered_phase_max_positions_local,
            peak_table_lattice=disordered_lattice_for_log,
            primary_a=float(primary_a_value),
            primary_c=float(primary_c_value),
        )

    current_hit_table_signature = getattr(
        simulation_runtime_state,
        "stored_hit_table_signature",
        None,
    )
    publish_intersection_cache = bool(active_display_sides) and all(
        _side_detector_cache_is_current(side, current_hit_table_signature)
        for side in active_display_sides
    )
    intersection_cache_local: list[object] = []
    if publish_intersection_cache:
        if "primary" in active_display_sides:
            intersection_cache_local.extend(
                _copy_intersection_cache_tables(
                    simulation_runtime_state.stored_primary_intersection_cache
                )
            )
        if "secondary" in active_display_sides:
            intersection_cache_local.extend(
                _copy_intersection_cache_tables(
                    simulation_runtime_state.stored_secondary_intersection_cache
                )
            )
    simulation_runtime_state.stored_intersection_cache = list(intersection_cache_local)
    _clear_caked_intersection_cache()
    simulation_runtime_state.stored_sim_image = updated_image
    if updated_image is None:
        simulation_runtime_state.stored_simulation_q_space_geometry = None
    return {
        "run_primary": bool(run_primary),
        "run_secondary": bool(run_secondary),
        "active_sides": tuple(active_display_sides),
        "combined_row_count": int(_table_row_count(max_positions_local)),
        "published_intersection_cache_row_count": int(_table_row_count(intersection_cache_local)),
        "row_content_signature": row_content_signature,
    }


def _restore_live_peak_rows_from_combined_hit_tables(
    *,
    active_peak_row_sides: Sequence[object] | None,
    primary_raw_rows_fresh: bool,
    secondary_raw_rows_fresh: bool,
    previous_row_content_signature: object = None,
) -> dict[str, object]:
    active_sides = _normalized_active_peak_row_sides(active_peak_row_sides)
    input_row_count = _table_row_count(simulation_runtime_state.stored_max_positions_local)
    diagnostics = {
        "active_sides": tuple(active_sides),
        "input_row_count": int(input_row_count),
        "projected_row_count": 0,
        "published_peak_record_count": 0,
        "skipped_reason": None,
    }
    if not active_sides:
        _clear_live_peak_record_cache_after_restore_miss()
        diagnostics["skipped_reason"] = "no_active_sides"
        return diagnostics
    if not _active_peak_row_sides_have_fresh_raw_rows(
        active_sides,
        primary_raw_rows_fresh=primary_raw_rows_fresh,
        secondary_raw_rows_fresh=secondary_raw_rows_fresh,
    ):
        _clear_live_peak_record_cache_after_restore_miss()
        diagnostics["skipped_reason"] = "stale_active_sides"
        return diagnostics
    if input_row_count <= 0:
        _clear_live_peak_record_cache_after_restore_miss()
        diagnostics["skipped_reason"] = "no_combined_rows"
        return diagnostics
    current_row_content_signature = getattr(
        simulation_runtime_state,
        "stored_q_group_content_signature",
        None,
    )
    if (
        simulation_runtime_state.peak_records
        and previous_row_content_signature == current_row_content_signature
    ):
        diagnostics["published_peak_record_count"] = int(len(simulation_runtime_state.peak_records))
        diagnostics["skipped_reason"] = "unchanged_signature"
        return diagnostics
    try:
        primary_a_value = float(a_var.get())
    except Exception:
        primary_a_value = float("nan")
    try:
        primary_c_value = float(c_var.get())
    except Exception:
        primary_c_value = float("nan")
    projected_rows = gui_geometry_q_group_manager.build_projected_geometry_fit_simulated_peaks(
        getattr(simulation_runtime_state, "stored_max_positions_local", None),
        image_shape=(int(image_size), int(image_size)),
        native_sim_to_display_coords=_native_sim_to_display_coords,
        peak_table_lattice=getattr(
            simulation_runtime_state,
            "stored_peak_table_lattice",
            None,
        ),
        source_reflection_indices=getattr(
            simulation_runtime_state,
            "stored_source_reflection_indices_local",
            None,
        ),
        primary_a=float(primary_a_value),
        primary_c=float(primary_c_value),
        default_source_label="primary",
        allow_nominal_hkl_indices=True,
        native_detector_coords_to_detector_display_coords=(
            _native_detector_coords_to_live_bundle_detector_coords
        ),
        native_detector_coords_to_caked_display_coords=(
            _native_detector_coords_to_live_caked_coords
        ),
        project_peaks_to_current_view=_project_geometry_manual_peaks_to_current_view,
        caked_view_enabled=_active_caked_primary_view(),
    )
    diagnostics["projected_row_count"] = int(len(projected_rows))
    if not projected_rows:
        _clear_live_peak_record_cache_after_restore_miss()
        diagnostics["skipped_reason"] = "no_projected_rows"
        return diagnostics
    _geometry_manual_set_runtime_peak_cache_from_projected_rows(projected_rows)
    diagnostics["published_peak_record_count"] = int(
        len(getattr(simulation_runtime_state, "peak_records", ()) or ())
    )
    return diagnostics


def _analysis_job_key(payload: object) -> tuple[object, int, bool, object, object]:
    if not isinstance(payload, dict):
        return (None, -1, False, None, None)
    return (
        payload.get("signature"),
        int(payload.get("epoch", -1)),
        bool(payload.get("is_preview", False)),
        payload.get("sim_cache_sig"),
        payload.get("bg_cache_sig"),
    )


def _job_trace_fields(
    payload: object,
    *,
    prefix: str = "job",
) -> dict[str, object]:
    """Return one compact set of trace fields describing a runtime job payload."""

    if not isinstance(payload, dict):
        return {}
    fields: dict[str, object] = {
        f"{prefix}_id": payload.get("job_id"),
        f"{prefix}_epoch": payload.get("epoch"),
        f"{prefix}_signature": payload.get("signature"),
    }
    if "is_preview" in payload:
        fields[f"{prefix}_preview"] = bool(payload.get("is_preview", False))
    return fields


def _append_job_queue_trace(
    event: str,
    *,
    lane: str,
    job: object = None,
    active_job: object = None,
    queued_job: object = None,
    replaced_job: object = None,
    reason: object = None,
    outcome: object = None,
    error: object = None,
) -> None:
    """Append one queue-state trace event for simulation or analysis jobs."""

    fields: dict[str, object] = {
        "lane": str(lane),
        "update_phase": getattr(simulation_runtime_state, "update_phase", None),
        "worker_active": bool(
            getattr(simulation_runtime_state, "worker_active_job", None) is not None
        ),
        "worker_queued": bool(
            getattr(simulation_runtime_state, "worker_queued_job", None) is not None
        ),
        "analysis_active": bool(
            getattr(simulation_runtime_state, "analysis_active_job", None) is not None
        ),
        "analysis_queued": bool(
            getattr(simulation_runtime_state, "analysis_queued_job", None) is not None
        ),
    }
    fields.update(_job_trace_fields(job, prefix="job"))
    fields.update(_job_trace_fields(active_job, prefix="active"))
    fields.update(_job_trace_fields(queued_job, prefix="queued"))
    fields.update(_job_trace_fields(replaced_job, prefix="replaced"))
    if reason is not None:
        fields["reason"] = str(reason)
    if outcome is not None:
        fields["outcome"] = str(outcome)
    if error is not None:
        fields["error"] = str(error)
    _append_runtime_update_trace(event, **fields)


def _truncate_run_status_piece(text: object, *, max_chars: int = 24) -> str:
    summary = " ".join(str(text).split())
    if len(summary) <= max_chars:
        return summary
    if max_chars <= 6:
        return summary[:max_chars]
    lead = max(2, (max_chars - 3) // 2)
    tail = max(1, max_chars - 3 - lead)
    return f"{summary[:lead]}...{summary[-tail:]}"


def _extract_fit_quality_text() -> str:
    """Return the best available user-facing fit quality summary."""

    ordered_view_state = globals().get("ordered_structure_fit_view_state")
    ordered_result_var = getattr(ordered_view_state, "result_var", None)
    if ordered_result_var is not None:
        try:
            ordered_text = " ".join(str(ordered_result_var.get() or "").splitlines()[0].split())
        except Exception:
            ordered_text = ""
        if ordered_text and ordered_text != "No ordered-structure fit run yet.":
            return ordered_text

    ordered_label = globals().get("progress_label_ordered_structure")
    if ordered_label is not None:
        try:
            ordered_status = " ".join(str(ordered_label.cget("text") or "").split())
        except Exception:
            ordered_status = ""
        if ordered_status and ordered_status != "Ordered structure fit: waiting.":
            return ordered_status

    mosaic_label = globals().get("progress_label_mosaic")
    if mosaic_label is not None:
        try:
            mosaic_text = " ".join(str(mosaic_label.cget("text") or "").split())
        except Exception:
            mosaic_text = ""
        if mosaic_text:
            return mosaic_text

    geometry_label = globals().get("progress_label_geometry")
    if geometry_label is not None:
        try:
            geometry_text = " ".join(str(geometry_label.cget("text") or "").split())
        except Exception:
            geometry_text = ""
        if geometry_text:
            return geometry_text

    chi_label = globals().get("chi_square_label")
    if chi_label is not None:
        try:
            chi_text = " ".join(str(chi_label.cget("text") or "").split())
        except Exception:
            chi_text = ""
        if chi_text and chi_text not in {"Chi-Squared:", "Chi-Squared: N/A"}:
            return chi_text

    return "Waiting for ordered-structure fit"


def _current_app_shell_view_mode() -> str:
    shell_view_state = globals().get("app_shell_view_state")
    selected_mode = (
        str(
            getattr(
                getattr(shell_view_state, "view_mode_var", None),
                "get",
                lambda: "detector",
            )()
            or "detector"
        )
        .strip()
        .lower()
    )
    if selected_mode not in {"detector", "caked", "q_space"}:
        selected_mode = "detector"
    analysis_controls_state = globals().get("analysis_view_controls_view_state")
    show_caked = bool(
        getattr(
            getattr(analysis_controls_state, "show_caked_2d_var", None),
            "get",
            lambda: False,
        )()
    )
    if selected_mode == "q_space":
        return "q_space"
    if show_caked:
        return "caked"
    return "detector"


def _active_caked_primary_view() -> bool:
    return _current_app_shell_view_mode() == "caked"


def _resolved_primary_analysis_display_mode() -> str:
    requested_mode = _current_app_shell_view_mode()
    q_space_available = bool(
        simulation_runtime_state.last_q_space_image_unscaled is not None
        and simulation_runtime_state.last_q_space_extent is not None
    )
    caked_available = bool(
        simulation_runtime_state.last_caked_image_unscaled is not None
        and simulation_runtime_state.last_caked_extent is not None
    )
    if requested_mode == "q_space" and q_space_available:
        return "q_space"
    if requested_mode in {"q_space", "caked"} and caked_available:
        return "caked"
    return "detector"


