def _prepare_caked_display_payload(
    res2,
    *,
    ai: FastAzimuthalIntegrator | None = None,
    detector_shape: tuple[int, ...] | list[int] | None = None,
    intensity_mode: str = "density",
) -> dict[str, object] | None:
    payload = gui_geometry_fit.build_geometry_fit_caked_view_payload_from_result(
        res2,
        ai=ai,
        detector_shape=detector_shape,
    )
    if not isinstance(payload, dict):
        return payload
    mode = _normalize_caked_intensity_mode(intensity_mode)
    display_image = _caked_payload_image_for_intensity_mode(payload, mode)
    if display_image is not None:
        payload["image"] = display_image
        payload["background"] = display_image
    payload["caked_intensity_mode"] = mode
    return payload


def _caked_payload_image_for_intensity_mode(
    payload: Mapping[str, object],
    intensity_mode: str,
) -> np.ndarray | None:
    mode = _normalize_caked_intensity_mode(intensity_mode)
    image = np.asarray(payload.get("image"), dtype=float)
    if image.ndim != 2:
        return None
    sum_signal = payload.get("sum_signal")
    sum_normalization = payload.get("sum_normalization")
    count = payload.get("count")
    signal = None if sum_signal is None else np.asarray(sum_signal, dtype=float)
    normalization = (
        None if sum_normalization is None else np.asarray(sum_normalization, dtype=float)
    )
    if mode == "raw_sum":
        if signal is not None and signal.shape == image.shape:
            return signal.copy()
        if count is not None:
            count_array = np.asarray(count, dtype=float)
            if count_array.shape == image.shape:
                return image * count_array
        return image.copy()
    if (
        signal is None
        or normalization is None
        or signal.shape != image.shape
        or normalization.shape != image.shape
    ):
        return image.copy()
    density = np.full(image.shape, np.nan, dtype=float)
    valid = np.isfinite(signal) & np.isfinite(normalization) & (normalization > 0.0)
    density[valid] = signal[valid] / normalization[valid]
    return density


_Q_SPACE_DISPLAY_LUT_MAX_DETECTOR_PIXELS = 512 * 512


# Large detector frames can spike memory because LUT builds first accumulate big
# Python-side COO lists; use streaming exact accumulator instead.
def _q_space_display_conversion_method(detector_shape: tuple[int, int]) -> str:
    detector_pixels = int(detector_shape[0]) * int(detector_shape[1])
    if detector_pixels > _Q_SPACE_DISPLAY_LUT_MAX_DETECTOR_PIXELS:
        return "exact"
    return "lut"


def _prepare_q_space_display_payload(
    detector_image: np.ndarray | None,
    *,
    npt_rad: object,
    npt_azim: object,
    distance_m: object,
    center: object,
    pixel_size_m: object,
    wavelength_m: object,
    gamma_deg: object,
    Gamma_deg: object,
    chi_deg: object,
    psi_deg: object,
    psi_z_deg: object,
    theta_initial_deg: object,
    cor_angle_deg: object,
    zs: object,
    zb: object,
) -> dict[str, object] | None:
    if detector_image is None:
        return None
    image_array = np.asarray(detector_image, dtype=np.float64)
    detector_shape = tuple(int(v) for v in image_array.shape[:2])
    if len(detector_shape) < 2 or detector_shape[0] <= 0 or detector_shape[1] <= 0:
        return None
    center_array = np.asarray(center, dtype=np.float64).reshape(-1)
    if center_array.size < 2:
        return None
    result = convert_image_to_q_space(
        image_array,
        pixel_size_m=float(pixel_size_m),
        distance_m=float(distance_m),
        center_row_px=float(center_array[0]),
        center_col_px=float(center_array[1]),
        wavelength_m=float(wavelength_m),
        gamma_deg=float(gamma_deg),
        Gamma_deg=float(Gamma_deg),
        chi_deg=float(chi_deg),
        psi_deg=float(psi_deg),
        psi_z_deg=float(psi_z_deg),
        theta_initial_deg=float(theta_initial_deg),
        cor_angle_deg=float(cor_angle_deg),
        zs=float(zs),
        zb=float(zb),
        npt_rad=int(max(2, int(npt_rad))),
        npt_azim=int(max(2, int(npt_azim))),
        correct_solid_angle=True,
        method=_q_space_display_conversion_method(detector_shape),
    )
    qr_axis = np.asarray(getattr(result, "qr", ()), dtype=np.float64)
    qz_axis = np.asarray(result.qz, dtype=np.float64)
    if qr_axis.ndim != 1 or qz_axis.ndim != 1 or qr_axis.size < 1 or qz_axis.size < 2:
        return None
    original_qr_size = int(qr_axis.size)
    positive_qr = np.isfinite(qr_axis) & (qr_axis > 0.0)
    if not np.any(positive_qr):
        return None
    if not np.all(positive_qr):
        qr_axis = qr_axis[positive_qr]

    def _qr_filtered_array(name: str) -> np.ndarray | None:
        value = getattr(result, name, None)
        if value is None:
            return None
        array = np.asarray(value, dtype=np.float64)
        if (
            array.ndim >= 1
            and array.shape[-1] == original_qr_size
            and positive_qr.size == original_qr_size
            and not np.all(positive_qr)
        ):
            array = array[..., positive_qr]
        return array

    intensity = _qr_filtered_array("intensity")
    if intensity is None:
        return None
    sum_signal = _qr_filtered_array("sum_signal")
    sum_normalization = _qr_filtered_array("sum_normalization")
    count = _qr_filtered_array("count")
    qr_step = float(np.nanmedian(np.diff(qr_axis))) if qr_axis.size > 1 else 1.0
    qz_step = float(np.nanmedian(np.diff(qz_axis))) if qz_axis.size > 1 else 1.0
    return {
        "image": intensity,
        "qr": qr_axis,
        "qz": qz_axis,
        "sum_signal": sum_signal,
        "sum_normalization": sum_normalization,
        "count": count,
        "extent": [
            max(0.0, float(qr_axis[0] - 0.5 * qr_step)),
            float(qr_axis[-1] + 0.5 * qr_step),
            float(qz_axis[0] - 0.5 * qz_step),
            float(qz_axis[-1] + 0.5 * qz_step),
        ],
    }


def _store_q_space_display_payload(
    *,
    sim_payload: Mapping[str, object] | None,
    bg_payload: Mapping[str, object] | None,
) -> None:
    if isinstance(sim_payload, Mapping):
        simulation_runtime_state.last_q_space_image_unscaled = np.asarray(
            sim_payload.get("image"),
            dtype=float,
        )
        simulation_runtime_state.last_q_space_qr_values = np.asarray(
            sim_payload.get("qr"),
            dtype=float,
        )
        simulation_runtime_state.last_q_space_qz_values = np.asarray(
            sim_payload.get("qz"),
            dtype=float,
        )
        simulation_runtime_state.last_q_space_extent = list(sim_payload.get("extent", []))
    else:
        simulation_runtime_state.last_q_space_image_unscaled = None
        simulation_runtime_state.last_q_space_qr_values = None
        simulation_runtime_state.last_q_space_qz_values = None
        simulation_runtime_state.last_q_space_extent = None

    if isinstance(bg_payload, Mapping):
        simulation_runtime_state.last_q_space_background_image_unscaled = np.asarray(
            bg_payload.get("image"),
            dtype=float,
        )
    else:
        simulation_runtime_state.last_q_space_background_image_unscaled = None


def _invalidate_cached_analysis_space_payloads(
    *,
    clear_caked: bool = False,
    clear_q_space: bool = False,
) -> None:
    if clear_caked:
        simulation_runtime_state.last_caked_image_unscaled = None
        simulation_runtime_state.last_caked_extent = None
        simulation_runtime_state.last_caked_background_image_unscaled = None
        simulation_runtime_state.last_caked_radial_values = None
        simulation_runtime_state.last_caked_azimuth_values = None
        simulation_runtime_state.last_caked_intensity_mode = None
        _set_live_caked_transform_bundle(None)
        _clear_caked_intersection_cache()
    if clear_q_space:
        _store_q_space_display_payload(sim_payload=None, bg_payload=None)
        simulation_runtime_state.last_q_space_payload_signature = None


def _hidden_analysis_space_payload_clear_flags(
    *,
    caked_analysis_requested: bool,
    q_space_requested: bool,
    current_analysis_cache_sig: object,
    q_space_payload_geometry_sig: object,
) -> tuple[bool, bool]:
    has_hidden_caked_payload = bool(
        simulation_runtime_state.last_caked_image_unscaled is not None
        or simulation_runtime_state.last_caked_extent is not None
        or simulation_runtime_state.last_caked_background_image_unscaled is not None
        or simulation_runtime_state.last_caked_radial_values is not None
        or simulation_runtime_state.last_caked_azimuth_values is not None
        or simulation_runtime_state.last_caked_intersection_cache is not None
        or simulation_runtime_state.last_caked_intersection_cache_transform_bundle is not None
    )
    has_hidden_q_space_payload = bool(
        simulation_runtime_state.last_q_space_image_unscaled is not None
        or simulation_runtime_state.last_q_space_qr_values is not None
        or simulation_runtime_state.last_q_space_qz_values is not None
        or simulation_runtime_state.last_q_space_extent is not None
        or simulation_runtime_state.last_q_space_background_image_unscaled is not None
    )
    clear_hidden_caked_payload = bool(
        not caked_analysis_requested
        and has_hidden_caked_payload
        and getattr(simulation_runtime_state, "last_analysis_cache_sig", None)
        != current_analysis_cache_sig
    )
    clear_hidden_q_space_payload = bool(
        not q_space_requested
        and has_hidden_q_space_payload
        and getattr(simulation_runtime_state, "last_q_space_payload_signature", None)
        != (current_analysis_cache_sig, q_space_payload_geometry_sig)
    )
    return (clear_hidden_caked_payload, clear_hidden_q_space_payload)


def _invalidate_hidden_analysis_space_payloads_if_stale(
    *,
    caked_analysis_requested: bool,
    q_space_requested: bool,
    current_analysis_cache_sig: object,
    q_space_payload_geometry_sig: object,
) -> None:
    clear_hidden_caked_payload, clear_hidden_q_space_payload = (
        _hidden_analysis_space_payload_clear_flags(
            caked_analysis_requested=caked_analysis_requested,
            q_space_requested=q_space_requested,
            current_analysis_cache_sig=current_analysis_cache_sig,
            q_space_payload_geometry_sig=q_space_payload_geometry_sig,
        )
    )
    if clear_hidden_caked_payload or clear_hidden_q_space_payload:
        _invalidate_cached_analysis_space_payloads(
            clear_caked=clear_hidden_caked_payload,
            clear_q_space=clear_hidden_q_space_payload,
        )


def _analysis_display_payload_ready(
    *,
    show_caked_2d: bool,
    q_space_requested: bool,
    background_visible: bool,
    caked_image: object,
    caked_extent: object,
    caked_background_image: object,
    q_space_image: object,
    q_space_extent: object,
    q_space_background_image: object,
) -> bool:
    caked_ready = bool(
        (not show_caked_2d)
        or (
            caked_image is not None
            and caked_extent is not None
            and (not background_visible or caked_background_image is not None)
        )
    )
    q_space_ready = bool(
        (not q_space_requested)
        or (
            q_space_image is not None
            and q_space_extent is not None
            and (not background_visible or q_space_background_image is not None)
        )
    )
    return bool(caked_ready and q_space_ready)


def _analysis_payload_ready_after_restore_attempt(
    *,
    analysis_result_current: bool,
    show_caked_2d: bool,
    q_space_requested: bool,
    background_visible: bool,
    restore_payload: Callable[[], None],
) -> bool:
    """Return final analysis payload readiness after one optional restore pass."""

    analysis_payload_ready = _analysis_display_payload_ready(
        show_caked_2d=show_caked_2d,
        q_space_requested=q_space_requested,
        background_visible=background_visible,
        caked_image=simulation_runtime_state.last_caked_image_unscaled,
        caked_extent=simulation_runtime_state.last_caked_extent,
        caked_background_image=simulation_runtime_state.last_caked_background_image_unscaled,
        q_space_image=simulation_runtime_state.last_q_space_image_unscaled,
        q_space_extent=simulation_runtime_state.last_q_space_extent,
        q_space_background_image=(simulation_runtime_state.last_q_space_background_image_unscaled),
    )
    if bool(analysis_result_current) and not analysis_payload_ready:
        restore_payload()
        analysis_payload_ready = _analysis_display_payload_ready(
            show_caked_2d=show_caked_2d,
            q_space_requested=q_space_requested,
            background_visible=background_visible,
            caked_image=simulation_runtime_state.last_caked_image_unscaled,
            caked_extent=simulation_runtime_state.last_caked_extent,
            caked_background_image=(simulation_runtime_state.last_caked_background_image_unscaled),
            q_space_image=simulation_runtime_state.last_q_space_image_unscaled,
            q_space_extent=simulation_runtime_state.last_q_space_extent,
            q_space_background_image=(
                simulation_runtime_state.last_q_space_background_image_unscaled
            ),
        )
    return bool(analysis_payload_ready)


def _restore_caked_display_payload_from_cached_results(
    *,
    background_visible: bool,
    q_space_requested: bool,
) -> bool:
    """Rebuild caked display arrays from the current cached analysis results."""
    live_q_space_requested = bool(_current_app_shell_view_mode() == "q_space")
    analysis_cache_sig = getattr(simulation_runtime_state, "last_analysis_cache_sig", None)
    caked_intensity_mode = _current_caked_intensity_mode()

    sim_caked = _prepare_caked_display_payload(
        simulation_runtime_state.last_res2_sim,
        ai=simulation_runtime_state.ai_cache.get("ai"),
        detector_shape=simulation_runtime_state.ai_cache.get("detector_shape"),
        intensity_mode=caked_intensity_mode,
    )
    if isinstance(sim_caked, dict):
        resolved_bundle = sim_caked.get("transform_bundle")
        detector_shape = sim_caked.get("detector_shape")
        if not isinstance(resolved_bundle, CakeTransformBundle) and detector_shape is not None:
            resolved_bundle = resolve_cake_transform_bundle(
                simulation_runtime_state.ai_cache.get("ai"),
                detector_shape,
                sim_caked.get("radial_axis", sim_caked.get("radial")),
                gui_azimuth_deg=sim_caked.get("azimuth_axis", sim_caked.get("azimuth")),
                raw_azimuth_deg=sim_caked.get("raw_azimuth_axis", sim_caked.get("raw_azimuth")),
                transform_bundle=sim_caked.get("transform_bundle"),
                require_gui_display_match=True,
            )
        resolved_bundle = (
            resolved_bundle if isinstance(resolved_bundle, CakeTransformBundle) else None
        )
        simulation_runtime_state.last_caked_image_unscaled = np.asarray(
            sim_caked.get("image"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_radial_values = np.asarray(
            sim_caked.get("radial"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_azimuth_values = np.asarray(
            sim_caked.get("azimuth"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_intensity_mode = _normalize_caked_intensity_mode(
            sim_caked.get("caked_intensity_mode", caked_intensity_mode)
        )
        _set_live_caked_transform_bundle(resolved_bundle)
        simulation_runtime_state.last_caked_extent = list(sim_caked.get("extent", []))
        caked_intersection_cache = _prepare_caked_intersection_cache(
            getattr(simulation_runtime_state, "stored_intersection_cache", ()),
            transform_bundle=resolved_bundle,
            pixel_size_m=float(pixel_size_m),
            distance_m=float(corto_detector_var.get()),
            center_row_px=float(center_x_var.get()),
            center_col_px=float(center_y_var.get()),
            native_detector_coords_to_bundle_detector_coords=None,
        )
        simulation_runtime_state.last_caked_intersection_cache = caked_intersection_cache
        simulation_runtime_state.last_caked_intersection_cache_transform_bundle = resolved_bundle
        simulation_runtime_state.last_caked_intersection_cache_source_signature = (
            _current_combined_detector_intersection_cache_signature()
        )
    else:
        _invalidate_cached_analysis_space_payloads(clear_caked=True)

    bg_caked = None
    if background_visible and simulation_runtime_state.last_res2_background is not None:
        bg_caked = _prepare_caked_display_payload(
            simulation_runtime_state.last_res2_background,
            ai=simulation_runtime_state.ai_cache.get("ai"),
            detector_shape=simulation_runtime_state.ai_cache.get("detector_shape"),
            intensity_mode=caked_intensity_mode,
        )
    if isinstance(bg_caked, dict):
        simulation_runtime_state.last_caked_background_image_unscaled = np.asarray(
            bg_caked.get("image"),
            dtype=float,
        )
    else:
        simulation_runtime_state.last_caked_background_image_unscaled = None

    if live_q_space_requested:
        analysis_bins = getattr(simulation_runtime_state, "analysis_preview_bins", None)
        if (
            not isinstance(analysis_bins, tuple)
            or len(analysis_bins) != 2
            or not all(isinstance(value, int) and value > 0 for value in analysis_bins)
        ):
            analysis_bins = (
                int(DEFAULT_ANALYSIS_RADIAL_BINS),
                int(DEFAULT_ANALYSIS_AZIMUTH_BINS),
            )
        q_space_geometry = _current_q_space_geometry_for_stored_simulation()
        if q_space_geometry is None:
            q_space_geometry = _current_q_space_geometry_from_live_controls()
        try:
            sim_q_space_payload = _prepare_q_space_display_payload_with_geometry(
                simulation_runtime_state.unscaled_image,
                npt_rad=int(analysis_bins[0]),
                npt_azim=int(analysis_bins[1]),
                geometry=q_space_geometry,
            )
            bg_q_space_payload = _prepare_q_space_display_payload_with_geometry(
                (
                    _current_background_for_q_space_restore()
                    if background_visible
                    and simulation_runtime_state.last_res2_background is not None
                    else None
                ),
                npt_rad=int(analysis_bins[0]),
                npt_azim=int(analysis_bins[1]),
                geometry=q_space_geometry,
            )
        except Exception as exc:
            _store_q_space_display_payload(sim_payload=None, bg_payload=None)
            simulation_runtime_state.last_q_space_payload_signature = None
            resolved_progress_label = globals().get("progress_label")
            if resolved_progress_label is not None:
                resolved_progress_label.config(text=f"Q-space refresh failed: {exc}")
        else:
            _store_q_space_display_payload(
                sim_payload=sim_q_space_payload,
                bg_payload=bg_q_space_payload,
            )
            simulation_runtime_state.last_q_space_payload_signature = (
                analysis_cache_sig,
                _q_space_geometry_cache_signature_from_geometry(q_space_geometry),
            )
    else:
        _store_q_space_display_payload(
            sim_payload=None,
            bg_payload=None,
        )
        simulation_runtime_state.last_q_space_payload_signature = None
    ready = bool(
        isinstance(sim_caked, dict)
        or (
            live_q_space_requested
            and simulation_runtime_state.last_q_space_image_unscaled is not None
        )
    )
    if ready:
        _flush_pending_detector_to_caked_manual_trace("cached_caked_payload_restored")
    return ready


def _run_analysis_job(job: dict[str, object]) -> dict[str, object]:
    sim_image = np.asarray(job["image"], dtype=np.float64)
    bg_image = job.get("background_image")
    bg_array = None if bg_image is None else np.asarray(bg_image, dtype=np.float64)
    npt_rad = int(job.get("npt_rad", 1000))
    npt_azim = int(job.get("npt_azim", 720))
    is_preview = bool(job.get("is_preview", False))
    q_space_requested = bool(job.get("q_space_requested", False))
    caked_outputs_requested = bool(job.get("caked_outputs_requested", True))
    caked_correct_solid_angle = resolve_gui_caked_view_correct_solid_angle(
        job.get("caked_correct_solid_angle", None)
    )
    caked_intensity_mode = _normalize_caked_intensity_mode(
        job.get("caked_intensity_mode", "density")
    )
    cached_bg_res2 = job.get("cached_bg_res2")
    cached_bg_caked = job.get("cached_bg_caked")
    intersection_cache = _copy_intersection_cache_tables(
        job.get("intersection_cache"),
        allow_abbreviated_detector_cache=True,
    )
    job_center = np.asarray(job.get("center", ()), dtype=np.float64).reshape(-1)
    job_center_row_px = float(job_center[0]) if job_center.size >= 2 else None
    job_center_col_px = float(job_center[1]) if job_center.size >= 2 else None

    @contextlib.contextmanager
    def _analysis_timing_span(name: str, **fields: object):
        if not timing_enabled():
            yield
            return
        payload = {
            "phase": "analysis",
            "requested_view_mode": str(job.get("requested_view_mode", "")),
            "q_space_requested": bool(q_space_requested),
            "caked_outputs_requested": bool(caked_outputs_requested),
            "npt_rad": int(npt_rad),
            "npt_azim": int(npt_azim),
            "detector_shape": tuple(int(v) for v in sim_image.shape[:2]),
        }
        payload.update(fields)
        with timing_span(f"analysis_job.{name}", **payload):
            yield

    analysis_start_time = perf_counter()
    with _analysis_timing_span("total"):
        ai = _build_analysis_integrator(job) if caked_outputs_requested else None
        sim_res2 = None
        bg_res2 = None
        sim_caked = None
        bg_caked = None
        sim_caked_intersection_cache: list[object] = []
        resolved_bundle = None
        if caked_outputs_requested:
            with temporary_numba_thread_limit(default_reserved_cpu_worker_count()):
                with _analysis_timing_span("caking"):
                    sim_res2 = caking(
                        sim_image,
                        ai,
                        npt_rad=npt_rad,
                        npt_azim=npt_azim,
                        correct_solid_angle=caked_correct_solid_angle,
                    )
                if cached_bg_res2 is not None:
                    bg_res2 = cached_bg_res2
                elif bg_array is not None:
                    with _analysis_timing_span("background_caking"):
                        bg_res2 = caking(
                            bg_array,
                            ai,
                            npt_rad=npt_rad,
                            npt_azim=npt_azim,
                            correct_solid_angle=caked_correct_solid_angle,
                        )
                else:
                    bg_res2 = None
            with _analysis_timing_span("display_prepare", product="caked"):
                sim_caked = _prepare_caked_display_payload(
                    sim_res2,
                    ai=ai,
                    detector_shape=sim_image.shape,
                    intensity_mode=caked_intensity_mode,
                )
                if isinstance(sim_caked, dict):
                    resolved_bundle = sim_caked.get("transform_bundle")
                    detector_shape = sim_caked.get("detector_shape")
                    if (
                        not isinstance(resolved_bundle, CakeTransformBundle)
                        and detector_shape is not None
                    ):
                        resolved_bundle = resolve_cake_transform_bundle(
                            ai,
                            detector_shape,
                            sim_caked.get("radial_axis", sim_caked.get("radial")),
                            gui_azimuth_deg=sim_caked.get(
                                "azimuth_axis",
                                sim_caked.get("azimuth"),
                            ),
                            raw_azimuth_deg=sim_caked.get(
                                "raw_azimuth_axis",
                                sim_caked.get("raw_azimuth"),
                            ),
                            transform_bundle=sim_caked.get("transform_bundle"),
                            require_gui_display_match=True,
                        )
                    if isinstance(resolved_bundle, CakeTransformBundle):
                        sim_caked["transform_bundle"] = resolved_bundle
                    else:
                        resolved_bundle = None
                if (
                    isinstance(cached_bg_caked, dict)
                    and cached_bg_caked.get("caked_intensity_mode") == caked_intensity_mode
                ):
                    bg_caked = dict(cached_bg_caked)
                else:
                    bg_caked = _prepare_caked_display_payload(
                        bg_res2,
                        ai=ai,
                        detector_shape=bg_array.shape if bg_array is not None else sim_image.shape,
                        intensity_mode=caked_intensity_mode,
                    )
                sim_caked_intersection_cache = _prepare_caked_intersection_cache(
                    intersection_cache,
                    transform_bundle=resolved_bundle,
                    pixel_size_m=job.get("pixel_size_m"),
                    distance_m=job.get("distance_m"),
                    center_row_px=job_center_row_px,
                    center_col_px=job_center_col_px,
                    native_detector_coords_to_bundle_detector_coords=None,
                )

        sim_q_space = None
        bg_q_space = None
        if q_space_requested:
            q_space_geometry = _copy_q_space_geometry(job.get("q_space_geometry"))
            if q_space_geometry is None:
                q_space_geometry = _q_space_geometry_from_values(
                    distance_m=job.get("distance_m"),
                    center=job.get("center"),
                    pixel_size_m=job.get("pixel_size_m"),
                    wavelength_m=job.get("wavelength_m"),
                    gamma_deg=job.get("gamma_deg"),
                    Gamma_deg=job.get("Gamma_deg"),
                    chi_deg=job.get("chi_deg"),
                    psi_deg=job.get("psi_deg"),
                    psi_z_deg=job.get("psi_z_deg"),
                    theta_initial_deg=job.get("theta_initial_deg"),
                    cor_angle_deg=job.get("cor_angle_deg"),
                    zs=job.get("zs"),
                    zb=job.get("zb"),
                )
            with _analysis_timing_span("q_space_conversion", product="simulation"):
                sim_q_space = _prepare_q_space_display_payload_with_geometry(
                    sim_image,
                    npt_rad=npt_rad,
                    npt_azim=npt_azim,
                    geometry=q_space_geometry,
                )
            with _analysis_timing_span("q_space_conversion", product="background"):
                bg_q_space = _prepare_q_space_display_payload_with_geometry(
                    bg_array,
                    npt_rad=npt_rad,
                    npt_azim=npt_azim,
                    geometry=q_space_geometry,
                )

    return {
        "job_id": int(job["job_id"]),
        "signature": job["signature"],
        "epoch": int(job["epoch"]),
        "is_preview": is_preview,
        "analysis_bins": (npt_rad, npt_azim),
        "sim_cache_sig": job.get("sim_cache_sig"),
        "bg_cache_sig": job.get("bg_cache_sig"),
        "sim_caking_sig": job.get("sim_caking_sig"),
        "bg_caking_sig": job.get("bg_caking_sig"),
        "sim_res2": sim_res2,
        "bg_res2": bg_res2,
        "sim_caked": sim_caked,
        "sim_caked_intersection_cache": sim_caked_intersection_cache,
        "sim_caked_intersection_cache_source_signature": job.get(
            "intersection_cache_source_signature",
            _detector_intersection_cache_signature(intersection_cache),
        ),
        "bg_caked": bg_caked,
        "sim_q_space": sim_q_space,
        "bg_q_space": bg_q_space,
        "analysis_elapsed_ms": (perf_counter() - analysis_start_time) * 1e3,
    }


def _submit_async_analysis_job(job: dict[str, object]) -> None:
    simulation_runtime_state.analysis_active_job = job
    simulation_runtime_state.analysis_future = _ensure_analysis_worker_executor().submit(
        _run_analysis_job,
        dict(job),
    )
    simulation_runtime_state.analysis_error_text = None
    if simulation_runtime_state.worker_active_job is None:
        simulation_runtime_state.update_phase = "analyzing"
    _append_job_queue_trace(
        "job_started",
        lane="analysis",
        job=job,
        active_job=job,
        queued_job=simulation_runtime_state.analysis_queued_job,
    )
    _refresh_run_status_bar()
    if simulation_runtime_state.analysis_poll_token is None:
        simulation_runtime_state.analysis_poll_token = root.after(
            SIMULATION_WORKER_POLL_MS,
            _poll_async_analysis_job,
        )


def _poll_async_analysis_job() -> None:
    simulation_runtime_state.analysis_poll_token = None
    future = simulation_runtime_state.analysis_future
    active_job = simulation_runtime_state.analysis_active_job
    if future is None or active_job is None:
        if _promote_queued_analysis_job(reason="active_slot_available"):
            return
        _refresh_run_status_bar()
        return

    if not future.done():
        simulation_runtime_state.analysis_poll_token = root.after(
            SIMULATION_WORKER_POLL_MS,
            _poll_async_analysis_job,
        )
        return

    simulation_runtime_state.analysis_future = None
    simulation_runtime_state.analysis_active_job = None
    queued_job = simulation_runtime_state.analysis_queued_job
    try:
        result = future.result()
    except Exception as exc:
        _append_job_queue_trace(
            "job_finished",
            lane="analysis",
            job=active_job,
            active_job=None,
            queued_job=queued_job,
            outcome="error",
            error=exc,
        )
        simulation_runtime_state.analysis_error_text = str(exc)
        if simulation_runtime_state.worker_active_job is None:
            simulation_runtime_state.update_phase = "error"
        if "progress_label" in globals() and progress_label is not None:
            progress_label.config(text=f"Analysis update failed: {exc}")
        _refresh_run_status_bar()
        if _promote_queued_analysis_job(reason="previous_job_failed"):
            return
        return

    _append_job_queue_trace(
        "job_finished",
        lane="analysis",
        job=result,
        active_job=None,
        queued_job=queued_job,
        outcome="success",
    )
    latest_epoch = int(simulation_runtime_state.analysis_epoch)
    result_epoch = int(result.get("epoch", -1))
    superseded = isinstance(queued_job, dict) and int(queued_job.get("job_id", -1)) > int(
        result.get("job_id", -1)
    )
    if result_epoch != latest_epoch or superseded:
        _append_job_queue_trace(
            "job_discarded_as_stale",
            lane="analysis",
            job=result,
            active_job=None,
            queued_job=queued_job,
            reason=("superseded_by_newer_queued_job" if superseded else "result_epoch_mismatch"),
        )
        if _promote_queued_analysis_job(reason="previous_job_stale"):
            return
        else:
            if simulation_runtime_state.worker_active_job is None:
                simulation_runtime_state.update_phase = "ready"
            _refresh_run_status_bar()
        return

    simulation_runtime_state.analysis_ready_result = result
    if simulation_runtime_state.worker_active_job is None:
        simulation_runtime_state.update_phase = "applying"
    _refresh_run_status_bar()
    root.after_idle(do_update)


def _request_async_analysis_job(job: dict[str, object]) -> str:
    requested_key = _analysis_job_key(job)
    _append_job_queue_trace(
        "job_requested",
        lane="analysis",
        job=job,
        active_job=simulation_runtime_state.analysis_active_job,
        queued_job=simulation_runtime_state.analysis_queued_job,
    )
    ready_result = simulation_runtime_state.analysis_ready_result
    if _analysis_job_key(ready_result) == requested_key:
        if simulation_runtime_state.worker_active_job is None:
            simulation_runtime_state.update_phase = "applying"
        _refresh_run_status_bar()
        return "ready"
    if isinstance(ready_result, dict):
        _append_job_queue_trace(
            "job_discarded_as_stale",
            lane="analysis",
            job=ready_result,
            active_job=simulation_runtime_state.analysis_active_job,
            queued_job=simulation_runtime_state.analysis_queued_job,
            reason="superseded_by_new_request",
        )
        simulation_runtime_state.analysis_ready_result = None

    if _analysis_job_key(simulation_runtime_state.analysis_active_job) == requested_key:
        if simulation_runtime_state.worker_active_job is None:
            simulation_runtime_state.update_phase = "analyzing"
        _refresh_run_status_bar()
        return "running"

    if _analysis_job_key(simulation_runtime_state.analysis_queued_job) == requested_key:
        _append_job_queue_trace(
            "job_queued",
            lane="analysis",
            job=simulation_runtime_state.analysis_queued_job,
            active_job=simulation_runtime_state.analysis_active_job,
            queued_job=simulation_runtime_state.analysis_queued_job,
            reason="already_queued",
        )
        if simulation_runtime_state.worker_active_job is None:
            simulation_runtime_state.update_phase = "queued"
        _refresh_run_status_bar()
        return "queued"

    simulation_runtime_state.analysis_job_counter = (
        int(simulation_runtime_state.analysis_job_counter) + 1
    )
    queued_job = dict(job)
    queued_job["job_id"] = int(simulation_runtime_state.analysis_job_counter)
    simulation_runtime_state.analysis_error_text = None

    if (
        simulation_runtime_state.analysis_active_job is None
        and simulation_runtime_state.analysis_future is None
    ):
        _append_job_queue_trace(
            "job_submitted",
            lane="analysis",
            job=queued_job,
            active_job=None,
            queued_job=simulation_runtime_state.analysis_queued_job,
            reason="requested",
        )
        _submit_async_analysis_job(queued_job)
        return "submitted"

    # Latest-request-wins: keep one active job and one replacement queued job.
    _replace_queued_analysis_job(queued_job)
    _append_job_queue_trace(
        "job_queued",
        lane="analysis",
        job=queued_job,
        active_job=simulation_runtime_state.analysis_active_job,
        queued_job=simulation_runtime_state.analysis_queued_job,
        reason="awaiting_active_job",
    )
    if simulation_runtime_state.worker_active_job is None:
        simulation_runtime_state.update_phase = "queued"
    _refresh_run_status_bar()
    return "queued"


def _consume_ready_analysis_result(
    signature: object,
    *,
    is_preview: bool,
    sim_cache_sig: object,
    bg_cache_sig: object,
) -> dict[str, object] | None:
    ready_result = simulation_runtime_state.analysis_ready_result
    if _analysis_job_key(ready_result) != (
        signature,
        int(simulation_runtime_state.analysis_epoch),
        bool(is_preview),
        sim_cache_sig,
        bg_cache_sig,
    ):
        if isinstance(ready_result, dict) and int(ready_result.get("epoch", -1)) < int(
            simulation_runtime_state.analysis_epoch
        ):
            simulation_runtime_state.analysis_ready_result = None
        return None

    simulation_runtime_state.analysis_ready_result = None
    return dict(ready_result)


def _apply_ready_analysis_result(result: dict[str, object]) -> None:
    simulation_runtime_state.last_analysis_signature = result.get("signature")
    simulation_runtime_state.analysis_preview_active = bool(result.get("is_preview", False))
    simulation_runtime_state.last_analysis_cache_sig = (
        result.get("sim_cache_sig"),
        result.get("bg_cache_sig"),
    )
    analysis_bins = result.get("analysis_bins")
    if (
        isinstance(analysis_bins, (tuple, list))
        and len(analysis_bins) == 2
        and all(isinstance(value, (int, np.integer)) for value in analysis_bins)
    ):
        simulation_runtime_state.analysis_preview_bins = (
            int(analysis_bins[0]),
            int(analysis_bins[1]),
        )
    else:
        simulation_runtime_state.analysis_preview_bins = None
    _invalidate_qr_cylinder_band_cache()
    simulation_runtime_state.last_res2_sim = result.get("sim_res2")
    simulation_runtime_state.last_res2_background = result.get("bg_res2")

    sim_caked = result.get("sim_caked")
    if isinstance(sim_caked, dict):
        resolved_bundle = sim_caked.get("transform_bundle")
        resolved_bundle = (
            resolved_bundle if isinstance(resolved_bundle, CakeTransformBundle) else None
        )
        simulation_runtime_state.last_caked_image_unscaled = np.asarray(
            sim_caked.get("image"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_radial_values = np.asarray(
            sim_caked.get("radial"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_azimuth_values = np.asarray(
            sim_caked.get("azimuth"),
            dtype=float,
        )
        simulation_runtime_state.last_caked_intensity_mode = _normalize_caked_intensity_mode(
            sim_caked.get("caked_intensity_mode", "density")
        )
        _set_live_caked_transform_bundle(resolved_bundle)
        simulation_runtime_state.last_caked_extent = list(sim_caked.get("extent", []))
        caked_intersection_cache = _copy_intersection_cache_tables(
            result.get("sim_caked_intersection_cache", [])
        )
        simulation_runtime_state.last_caked_intersection_cache = caked_intersection_cache
        simulation_runtime_state.last_caked_intersection_cache_transform_bundle = resolved_bundle
        simulation_runtime_state.last_caked_intersection_cache_source_signature = result.get(
            "sim_caked_intersection_cache_source_signature"
        )
    else:
        _invalidate_cached_analysis_space_payloads(clear_caked=True)

    bg_caked = result.get("bg_caked")
    if isinstance(bg_caked, dict):
        simulation_runtime_state.last_caked_background_image_unscaled = np.asarray(
            bg_caked.get("image"),
            dtype=float,
        )
    else:
        simulation_runtime_state.last_caked_background_image_unscaled = None
    _store_q_space_display_payload(
        sim_payload=result.get("sim_q_space"),
        bg_payload=result.get("bg_q_space"),
    )
    analysis_signature = result.get("signature")
    q_space_geometry_sig = (
        analysis_signature[2]
        if isinstance(analysis_signature, tuple) and len(analysis_signature) >= 3
        else None
    )
    if isinstance(result.get("sim_q_space"), Mapping):
        simulation_runtime_state.last_q_space_payload_signature = (
            simulation_runtime_state.last_analysis_cache_sig,
            q_space_geometry_sig,
        )
    else:
        simulation_runtime_state.last_q_space_payload_signature = None
    _flush_pending_detector_to_caked_manual_trace("analysis_result_applied")

    _store_cached_caking_entry(
        "sim",
        result.get("sim_cache_sig"),
        res2=simulation_runtime_state.last_res2_sim,
        payload=sim_caked if isinstance(sim_caked, dict) else None,
    )
    _store_cached_caking_entry(
        "bg",
        result.get("bg_cache_sig"),
        res2=simulation_runtime_state.last_res2_background,
        payload=bg_caked if isinstance(bg_caked, dict) else None,
    )


def schedule_update():
    """Queue a throttled simulation/redraw update."""

    _trace_beam_center("update.scheduled.before")
    if bool(getattr(simulation_runtime_state, "startup_updates_suspended", False)):
        simulation_runtime_state.pending_startup_refresh = True
        _trace_beam_center("update.scheduled.suspended")
        return

    _ensure_runtime_update_trace_hooks()
    timing_reason = _timing_active_update_reason()
    timing_prefix = _timing_visible_event_prefix(timing_reason)
    timing_update_id = _timing_pending_action_update_id()
    if timing_update_id is None:
        timing_update_id = getattr(simulation_runtime_state, "current_update_trace_id", None)
    previous_pending = simulation_runtime_state.update_pending
    gui_controllers.clear_tk_after_token(
        root,
        simulation_runtime_state.integration_update_pending,
    )
    simulation_runtime_state.integration_update_pending = None
    if simulation_runtime_state.interaction_drag_active:
        simulation_runtime_state.interaction_drag_requires_settled_update = True

    gui_controllers.clear_tk_after_token(
        root,
        simulation_runtime_state.update_pending,
    )
    update_delay_ms = _current_update_debounce_ms()
    update_callback = do_update
    if _beam_center_trace_enabled():

        def _beam_center_traced_do_update():
            _trace_beam_center("root.after.update_callback.begin")
            try:
                return do_update()
            finally:
                _trace_beam_center_after_idle_drain("root.after.update_callback.end")

        update_callback = _beam_center_traced_do_update
    simulation_runtime_state.update_pending = root.after(
        update_delay_ms,
        update_callback,
    )
    _trace_beam_center(
        "update.scheduled.after",
        root_after_delay_ms=update_delay_ms,
        queued_token=simulation_runtime_state.update_pending,
    )
    _timing_event(
        _timing_named_event(timing_prefix, "update_scheduled", "update_scheduled"),
        phase="queue",
        update_id=timing_update_id,
        timing_reason=timing_reason,
        previous_pending=previous_pending,
        queued_token=simulation_runtime_state.update_pending,
    )
    _timing_event(
        _timing_named_event(timing_prefix, "queue_delay.start", "queue_delay.start"),
        phase="queue",
        update_id=timing_update_id,
        timing_reason=timing_reason,
    )
    if simulation_runtime_state.worker_active_job is None:
        simulation_runtime_state.update_phase = "queued"
    _append_runtime_update_trace(
        "schedule_update",
        previous_pending=previous_pending,
        queued_token=simulation_runtime_state.update_pending,
        update_running=simulation_runtime_state.update_running,
        update_phase=getattr(simulation_runtime_state, "update_phase", None),
        worker_active=bool(simulation_runtime_state.worker_active_job is not None),
        worker_queued=bool(simulation_runtime_state.worker_queued_job is not None),
        analysis_active=bool(simulation_runtime_state.analysis_active_job is not None),
        analysis_queued=bool(simulation_runtime_state.analysis_queued_job is not None),
        background_index=int(background_runtime_state.current_background_index),
        manual_pick_armed=bool(geometry_runtime_state.manual_pick_armed),
    )
    _refresh_run_status_bar()


def _refresh_geometry_fit_caked_roi_preview(*_args) -> None:
    """Refresh the main raster display after ROI preview toggles change."""

    try:
        apply_scale_factor_to_existing_results(
            update_limits=False,
            update_1d=False,
            update_canvas=True,
            update_chi_square=True,
        )
        _refresh_settled_overlays()
    except Exception:
        schedule_update()


