def _geometry_source_signature_numeric(
    value: object,
    *,
    default: float = 0.0,
) -> float:
    try:
        numeric = float(value)
    except Exception:
        numeric = float(default)
    if not np.isfinite(numeric):
        numeric = float(default)
    return float(numeric)


def _geometry_source_snapshot_signature_from_params(
    param_set,
    *,
    mosaic_params,
    optics_mode_component: int,
    include_mosaic_shape: bool = True,
    sf_prune_bias: float,
    sf_prune_stats,
    ordered_structure_scale: float,
    qr_cylinder_replace_requested: bool,
    primary_source_signature,
    secondary_source_signature,
    secondary_a: float,
    secondary_c: float,
    sixh_qr_reference_signature=None,
    disordered_phase_qr_reference_signature=None,
):
    params = dict(param_set or {})

    def _param_value(*keys: str, default: object = 0.0) -> object:
        for key in keys:
            if key in params:
                return params.get(key)
        return default

    signature = (
        round(_geometry_source_signature_numeric(_param_value("gamma")), 6),
        round(_geometry_source_signature_numeric(_param_value("Gamma")), 6),
        round(_geometry_source_signature_numeric(_param_value("chi")), 6),
        round(_geometry_source_signature_numeric(_param_value("psi_z", "psi")), 6),
        round(_geometry_source_signature_numeric(_param_value("zs")), 9),
        round(_geometry_source_signature_numeric(_param_value("zb")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_width")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_length")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_depth")), 12),
        round(_geometry_source_signature_numeric(_param_value("debye_x")), 6),
        round(_geometry_source_signature_numeric(_param_value("debye_y")), 6),
        round(_geometry_source_signature_numeric(_param_value("a")), 6),
        round(_geometry_source_signature_numeric(_param_value("c")), 6),
        round(
            _geometry_source_signature_numeric(_param_value("theta_initial", "theta_init")),
            6,
        ),
        round(_geometry_source_signature_numeric(_param_value("cor", "cor_angle")), 6),
        round(_geometry_source_signature_numeric(_param_value("center_x")), 3),
        round(_geometry_source_signature_numeric(_param_value("center_y")), 3),
        round(
            _geometry_source_signature_numeric(_param_value("distance_m", "d", "corto_detector")),
            9,
        ),
        int(mosaic_params["solve_q_steps"]),
        round(float(mosaic_params["solve_q_rel_tol"]), 8),
        int(mosaic_params["solve_q_mode"]),
        int(mosaic_params.get("events_per_beam_phase", DEFAULT_EVENTS_PER_BEAM_PHASE)),
        tuple(mosaic_params.get("_sampling_signature", ())),
        int(bool(mosaic_params.get("_refraction_effects_disabled", False))),
        round(_geometry_source_signature_numeric(sf_prune_bias), 3),
        int((sf_prune_stats or {}).get("qr_kept", 0)),
        int((sf_prune_stats or {}).get("hkl_primary_kept", 0)),
        round(_geometry_source_signature_numeric(ordered_structure_scale), 6),
        int(optics_mode_component),
        int(bool(qr_cylinder_replace_requested)),
        int(np.size(mosaic_params["beam_x_array"])),
        int(np.size(mosaic_params["theta_array"])),
        primary_source_signature,
        secondary_source_signature,
        sixh_qr_reference_signature,
        disordered_phase_qr_reference_signature,
        round(_geometry_source_signature_numeric(secondary_a), 6),
        round(_geometry_source_signature_numeric(secondary_c), 6),
    )
    if include_mosaic_shape:
        signature += (
            round(
                _geometry_source_signature_numeric(
                    _param_value(
                        "sigma_mosaic_deg",
                        default=mosaic_params.get("sigma_mosaic_deg", 0.0),
                    )
                ),
                6,
            ),
            round(
                _geometry_source_signature_numeric(
                    _param_value(
                        "gamma_mosaic_deg",
                        default=mosaic_params.get("gamma_mosaic_deg", 0.0),
                    )
                ),
                6,
            ),
            round(
                _geometry_source_signature_numeric(
                    _param_value("eta", default=mosaic_params.get("eta", 0.0))
                ),
                6,
            ),
        )
    return signature


def _geometry_source_snapshot_signature_for_background(
    background_index: int,
    param_set: dict[str, object] | None = None,
):
    params = dict(_current_geometry_fit_params())
    if isinstance(param_set, dict):
        params.update(dict(param_set))
    mosaic_params = build_mosaic_params()
    primary_source_signature = (
        (
            "qr",
            id(simulation_runtime_state.sim_primary_qr),
            len(simulation_runtime_state.sim_primary_qr),
        )
        if isinstance(simulation_runtime_state.sim_primary_qr, dict)
        and len(simulation_runtime_state.sim_primary_qr) > 0
        else (
            "miller",
            id(simulation_runtime_state.sim_miller1),
            tuple(np.asarray(simulation_runtime_state.sim_miller1).shape),
        )
    )
    secondary_source_signature = (
        "miller",
        id(simulation_runtime_state.sim_miller2),
        tuple(np.asarray(simulation_runtime_state.sim_miller2).shape),
    )
    stacking_p_signature: tuple[object, ...] = ()
    try:
        stacking_p_signature = tuple(
            _geometry_source_signature_numeric(var.get()) for var in (p0_var, p1_var, p2_var)
        )
    except Exception:
        stacking_p_signature = ()
    stacking_weight_signature: tuple[object, ...] = ()
    try:
        stacking_weight_signature = tuple(
            _geometry_source_signature_numeric(value)
            for value in gui_controllers.normalize_stacking_weight_values(
                [w0_var.get(), w1_var.get(), w2_var.get()]
            )
        )
    except Exception:
        stacking_weight_signature = ()
    primary_a = _geometry_source_signature_numeric(params.get("a"))
    primary_c = _geometry_source_signature_numeric(params.get("c"))
    secondary_a = float(av2) if av2 is not None else primary_a
    secondary_c = float(cv2) if cv2 is not None else primary_c
    image_signature = _geometry_source_snapshot_signature_from_params(
        params,
        mosaic_params=mosaic_params,
        optics_mode_component=int(_current_optics_mode_flag()),
        include_mosaic_shape=True,
        sf_prune_bias=current_sf_prune_bias(),
        sf_prune_stats=simulation_runtime_state.sf_prune_stats,
        ordered_structure_scale=float(_current_ordered_structure_scale()),
        qr_cylinder_replace_requested=_qr_cylinder_replace_simulation_enabled(),
        primary_source_signature=primary_source_signature,
        secondary_source_signature=secondary_source_signature,
        sixh_qr_reference_signature=_geometry_6h_qr_reference_source_signature(),
        disordered_phase_qr_reference_signature=_geometry_disordered_phase_source_signature(),
        secondary_a=secondary_a,
        secondary_c=secondary_c,
    )
    row_content_signature = gui_geometry_q_group_manager._geometry_q_group_signature_value(
        getattr(simulation_runtime_state, "stored_q_group_content_signature", None)
    )
    sf_picker_inventory_signature = (
        "sf_picker_inventory",
        str(getattr(simulation_runtime_state, "primary_source_mode", "")),
        str(getattr(simulation_runtime_state, "primary_requested_source_mode", "")),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_active_contribution_keys", ())
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_requested_contribution_keys", ())
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_filter_signature", None)
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_requested_filter_signature", None)
        ),
        tuple(sorted((simulation_runtime_state.sf_prune_stats or {}).items())),
        stacking_p_signature,
        stacking_weight_signature,
        _geometry_6h_qr_reference_source_signature(),
    )
    return image_signature + (row_content_signature, sf_picker_inventory_signature)


def _geometry_source_snapshot_base_simulation_signature(signature: object) -> object:
    if isinstance(signature, tuple) and len(signature) >= 2:
        return tuple(signature[:-2])
    if isinstance(signature, list) and len(signature) >= 2:
        return tuple(signature[:-2])
    return signature


def _geometry_source_snapshot_payload(
    *,
    background_index: int,
    simulation_signature: object,
    rows: Sequence[Mapping[str, object]] | None,
    created_from: str,
    source_reflection_index_count: int,
    empty_reason: str,
    projected_rows: Sequence[Mapping[str, object]] | None = None,
    diagnostics: Mapping[str, object] | None = None,
    requested_signature: object = None,
    requested_signature_summary: object = None,
    projection_view_signature: Mapping[str, object] | None = None,
) -> dict[str, object]:
    normalized_rows = [dict(entry) for entry in (rows or ()) if isinstance(entry, Mapping)]
    normalized_projected_rows = [
        dict(entry) for entry in (projected_rows or ()) if isinstance(entry, Mapping)
    ]
    normalized_projection_signature = (
        dict(projection_view_signature) if isinstance(projection_view_signature, Mapping) else None
    )
    normalized_diagnostics = dict(diagnostics) if isinstance(diagnostics, Mapping) else {}
    return {
        "background_index": int(background_index),
        "simulation_signature": simulation_signature,
        "requested_signature": (
            simulation_signature if requested_signature is None else requested_signature
        ),
        "requested_signature_summary": requested_signature_summary,
        "base_simulation_signature": simulation_runtime_state.last_simulation_signature,
        "simulation_signature_summary": _live_cache_signature_summary(simulation_signature),
        "row_content_signature": getattr(
            simulation_runtime_state,
            "stored_q_group_content_signature",
            None,
        ),
        "rows": normalized_rows,
        "stored_rows": [dict(entry) for entry in normalized_rows],
        "projected_rows": normalized_projected_rows,
        "row_count": int(len(normalized_rows)),
        "projected_row_count": int(len(normalized_projected_rows)),
        "valid_for_picker": bool(normalized_rows),
        "valid_for_geometry_fit_dataset": bool(normalized_rows or normalized_projected_rows),
        "empty_reason": (None if normalized_rows else str(empty_reason)),
        "created_from": str(created_from or "unknown"),
        "source_reflection_index_count": int(source_reflection_index_count),
        "projection_view_signature": normalized_projection_signature,
        "projection_view_signature_digest": (
            gui_geometry_fit._geometry_fit_digest_payload(normalized_projection_signature)
            if normalized_projection_signature is not None
            else None
        ),
        "diagnostics": copy.deepcopy(normalized_diagnostics),
    }


def _capture_geometry_source_snapshot() -> None:
    background_index = int(background_runtime_state.current_background_index)
    previous_snapshot = dict(
        simulation_runtime_state.source_row_snapshots.get(int(background_index)) or {}
    )
    try:
        current_param_set = dict(_current_geometry_fit_params())
    except Exception:
        current_param_set = {}
    snapshot_signature = _geometry_source_snapshot_signature_for_background(
        int(background_index),
        current_param_set,
    )
    try:
        rows = [
            dict(entry)
            for entry in (_build_live_preview_simulated_peaks_from_cache() or ())
            if isinstance(entry, dict)
        ]
    except Exception:
        rows = []
    created_from = "none"
    for raw_record in simulation_runtime_state.peak_records or ():
        if not isinstance(raw_record, dict):
            continue
        try:
            display_col = float(raw_record.get("display_col", np.nan))
            display_row = float(raw_record.get("display_row", np.nan))
        except Exception:
            continue
        if np.isfinite(display_col) and np.isfinite(display_row):
            created_from = "peak_records"
            break
    if created_from == "none" and simulation_runtime_state.stored_max_positions_local is not None:
        created_from = "stored_max_positions_local"
    snapshot_payload = _geometry_source_snapshot_payload(
        background_index=int(background_index),
        simulation_signature=snapshot_signature,
        rows=rows,
        created_from=created_from,
        source_reflection_index_count=int(
            len(simulation_runtime_state.stored_source_reflection_indices_local or ())
        ),
        empty_reason="no_projected_rows",
    )
    retain_snapshot_cache = _retain_runtime_optional_cache(
        "source_snapshots",
        feature_needed=True,
    )
    if retain_snapshot_cache and bool(rows):
        simulation_runtime_state.source_row_snapshots[int(background_index)] = snapshot_payload
    else:
        simulation_runtime_state.source_row_snapshots.pop(int(background_index), None)
    _trace_live_cache_event(
        "source_snapshot",
        "store",
        background_index=int(background_index),
        outcome=("stored" if retain_snapshot_cache and bool(rows) else "discarded"),
        overwrite=bool(previous_snapshot),
        previous_row_count=int(previous_snapshot.get("row_count", 0) or 0),
        row_count=int(len(rows)),
        created_from=created_from,
        previous_signature_summary=_live_cache_signature_summary(
            previous_snapshot.get("simulation_signature")
        ),
        signature_summary=_live_cache_signature_summary(snapshot_signature),
    )


def _geometry_manual_set_runtime_peak_cache_from_projected_rows(
    projected_rows: Sequence[object] | None,
) -> None:
    normalized_projected_rows = [
        dict(entry) for entry in (projected_rows or ()) if isinstance(entry, Mapping)
    ]
    try:
        normalized_projected_rows = gui_controllers.filter_enabled_q_group_rows(
            normalized_projected_rows,
            geometry_q_group_state,
        )
    except Exception:
        normalized_projected_rows = [
            dict(entry) for entry in normalized_projected_rows or () if isinstance(entry, Mapping)
        ]

    restored_records: list[dict[str, object]] = []
    restored_positions: list[tuple[float, float]] = []
    restored_millers: list[tuple[int, int, int]] = []
    restored_intensities: list[float] = []
    use_caked_display = bool(_active_caked_primary_view())

    def _detector_mode_projected_point(
        entry: Mapping[str, object] | None,
    ) -> tuple[float, float] | None:
        if not isinstance(entry, Mapping):
            return None
        for key_x, key_y in (
            ("sim_col_raw", "sim_row_raw"),
            ("sim_col", "sim_row"),
            ("display_col", "display_row"),
        ):
            try:
                col = float(entry.get(key_x, np.nan))
                row = float(entry.get(key_y, np.nan))
            except Exception:
                continue
            if np.isfinite(col) and np.isfinite(row):
                return float(col), float(row)
        return None

    for raw_entry in normalized_projected_rows:
        peak_record = gui_manual_geometry.geometry_manual_canonicalize_live_source_entry(
            raw_entry,
            normalize_hkl_key=_normalize_hkl_key,
            allow_legacy_peak_fallback=False,
            preserve_existing_trusted_identity=True,
        )
        if peak_record is None:
            continue
        try:
            active_point = gui_manual_geometry._geometry_manual_entry_active_view_point(
                peak_record,
                use_caked_display=use_caked_display,
            )
        except Exception:
            active_point = None
        if active_point is None and not use_caked_display:
            active_point = _detector_mode_projected_point(peak_record)
        if active_point is None:
            continue
        try:
            active_col = float(active_point[0])
            active_row = float(active_point[1])
        except Exception:
            continue
        if not (np.isfinite(active_col) and np.isfinite(active_row)):
            continue

        hkl_value = peak_record.get("hkl")
        if not isinstance(hkl_value, tuple) or len(hkl_value) < 3:
            continue
        try:
            hkl_triplet = (
                int(hkl_value[0]),
                int(hkl_value[1]),
                int(hkl_value[2]),
            )
        except Exception:
            continue

        try:
            intensity = float(peak_record.get("weight", peak_record.get("intensity", 0.0)))
        except Exception:
            intensity = 0.0
        if not np.isfinite(intensity):
            intensity = 0.0

        peak_record["intensity"] = float(intensity)
        peak_record["weight"] = float(intensity)

        restored_records.append(peak_record)
        restored_positions.append((float(active_col), float(active_row)))
        restored_millers.append(hkl_triplet)
        restored_intensities.append(float(intensity))

    simulation_runtime_state.peak_records = restored_records
    simulation_runtime_state.peak_positions = restored_positions
    simulation_runtime_state.peak_positions_filtered = True
    simulation_runtime_state.peak_millers = restored_millers
    simulation_runtime_state.peak_intensities = restored_intensities
    simulation_runtime_state.selected_peak_record = None
    if _retain_runtime_optional_cache(
        "peak_overlay",
        feature_needed=bool(restored_records),
    ):
        simulation_runtime_state.peak_overlay_cache = {
            "sig": None,
            "positions": list(restored_positions),
            "millers": list(restored_millers),
            "intensities": list(restored_intensities),
            "records": [dict(record) for record in restored_records],
            "click_spatial_index": None,
            "peak_positions_filtered": True,
            "restored_from_gui_state": False,
        }
    else:
        simulation_runtime_state.peak_overlay_cache = _empty_peak_overlay_cache()
    _invalidate_geometry_manual_pick_cache()


def _geometry_manual_set_runtime_peak_cache_from_source_rows(
    source_rows: Sequence[object] | None,
) -> None:
    projected_rows = [dict(entry) for entry in (source_rows or ()) if isinstance(entry, Mapping)]
    if callable(_project_geometry_manual_peaks_to_current_view):
        try:
            projected_rows = [
                dict(entry)
                for entry in (_project_geometry_manual_peaks_to_current_view(projected_rows) or ())
                if isinstance(entry, Mapping)
            ]
        except Exception:
            projected_rows = [
                dict(entry) for entry in (source_rows or ()) if isinstance(entry, Mapping)
            ]
    _geometry_manual_set_runtime_peak_cache_from_projected_rows(projected_rows)


def _geometry_manual_build_source_rows_from_hit_tables(
    hit_tables: Sequence[object] | None,
    *,
    image_size_value: int,
    params_local: Mapping[str, object],
    allow_nominal_hkl_indices: bool,
) -> tuple[
    list[dict[str, object]],
    list[tuple[float, float, str]],
    list[object],
    list[int],
]:
    copied_hit_tables = _copy_hit_tables(hit_tables)
    if not copied_hit_tables:
        return [], [], [], []

    try:
        primary_a = float(params_local.get("a", np.nan))
    except Exception:
        primary_a = float("nan")
    try:
        primary_c = float(params_local.get("c", np.nan))
    except Exception:
        primary_c = float("nan")
    try:
        theta_initial_value = float(params_local.get("theta_initial", np.nan))
    except Exception:
        theta_initial_value = float("nan")

    raw_rows, peak_table_lattice, source_reflection_indices = (
        gui_geometry_q_group_manager.build_geometry_fit_full_order_source_rows(
            copied_hit_tables,
            image_shape=(int(image_size_value), int(image_size_value)),
            native_sim_to_display_coords=_native_sim_to_display_coords,
            primary_a=primary_a,
            primary_c=primary_c,
            default_source_label="primary",
            round_pixel_centers=False,
            allow_nominal_hkl_indices=bool(allow_nominal_hkl_indices),
            owner="runtime_session._geometry_manual_build_source_rows_from_hit_tables",
        )
    )
    raw_rows = [dict(entry) for entry in (raw_rows or ()) if isinstance(entry, Mapping)]
    if np.isfinite(theta_initial_value):
        for entry in raw_rows:
            entry["theta_initial"] = float(theta_initial_value)
            entry["theta_initial_deg"] = float(theta_initial_value)
    return raw_rows, peak_table_lattice, copied_hit_tables, source_reflection_indices


def _geometry_fit_targeted_projected_cache_store() -> dict[int, dict[str, dict[str, object]]]:
    cache_store = getattr(
        simulation_runtime_state,
        "geometry_fit_targeted_projected_cache_by_background",
        None,
    )
    if isinstance(cache_store, dict):
        return cache_store
    cache_store = {}
    setattr(
        simulation_runtime_state,
        "geometry_fit_targeted_projected_cache_by_background",
        cache_store,
    )
    return cache_store


def _geometry_fit_store_targeted_projected_cache_entry(
    *,
    background_index: int,
    key_digest: str,
    payload: Mapping[str, object] | None,
) -> None:
    if not str(key_digest).strip() or not isinstance(payload, Mapping):
        return
    if not gui_geometry_fit._geometry_fit_projected_rows_cacheable(
        background_index=int(background_index),
        projected_rows=payload.get("projected_rows"),
        projection_view_signature=payload.get("projection_view_signature"),
        requested_projection_view_signature=payload.get("projection_view_signature"),
        consumer=str(payload.get("consumer") or ""),
    ):
        return
    cache_store = _geometry_fit_targeted_projected_cache_store()
    background_store = cache_store.setdefault(int(background_index), {})
    background_store[str(key_digest)] = copy.deepcopy(dict(payload))


def _geometry_fit_load_targeted_projected_cache_entry(
    *,
    background_index: int,
    key_digest: str,
) -> dict[str, object] | None:
    cache_store = _geometry_fit_targeted_projected_cache_store()
    background_store = cache_store.get(int(background_index))
    if not isinstance(background_store, Mapping):
        return None
    payload = background_store.get(str(key_digest))
    if not isinstance(payload, Mapping):
        return None
    if not gui_geometry_fit._geometry_fit_projected_rows_cacheable(
        background_index=int(background_index),
        projected_rows=payload.get("projected_rows"),
        projection_view_signature=payload.get("projection_view_signature"),
        requested_projection_view_signature=payload.get("projection_view_signature"),
        consumer=str(payload.get("consumer") or ""),
    ):
        return None
    return copy.deepcopy(dict(payload))


def _geometry_fit_projection_content_hash(*parts: bytes | str) -> str:
    hasher = hashlib.blake2b(digest_size=16)
    for part in parts:
        raw = part.encode("utf-8", "backslashreplace") if isinstance(part, str) else bytes(part)
        hasher.update(len(raw).to_bytes(8, "little", signed=False))
        hasher.update(raw)
    return hasher.hexdigest()


def _geometry_fit_projection_dense_content_token(
    value: object,
    *,
    kind: str,
    allow_empty: bool = True,
) -> dict[str, object] | None:
    try:
        raw = np.asarray(value)
    except Exception:
        return None
    if raw.dtype.kind == "O":
        return None
    if raw.dtype.kind in {"f", "c"}:
        try:
            arr = np.asarray(value, dtype=np.dtype("<f8"))
        except Exception:
            return None
        if not np.all(np.isfinite(arr)):
            return None
    elif raw.dtype.kind in {"i", "u"}:
        try:
            arr = np.asarray(value, dtype=np.dtype("<i8"))
        except Exception:
            return None
    elif raw.dtype.kind == "b":
        arr = np.asarray(value, dtype=np.dtype("u1"))
    else:
        return None
    if arr.size <= 0 and not bool(allow_empty):
        return None
    arr = np.ascontiguousarray(arr)
    shape = [int(v) for v in arr.shape]
    dtype_text = str(arr.dtype)
    return {
        "kind": "dense_content_v3",
        "content_kind": str(kind),
        "shape": shape,
        "dtype": dtype_text,
        "digest": _geometry_fit_projection_content_hash(
            "dense_content_v3",
            str(kind),
            repr(shape),
            dtype_text,
            arr.tobytes(order="C"),
        ),
    }


def _geometry_fit_projection_sparse_content_token(
    value: object,
    *,
    kind: str,
) -> dict[str, object] | None:
    if not hasattr(value, "tocsr"):
        return None
    try:
        csr = value.tocsr(copy=True)  # type: ignore[attr-defined]
    except TypeError:
        try:
            csr = value.tocsr()  # type: ignore[attr-defined]
        except Exception:
            return None
    except Exception:
        return None
    try:
        csr.sort_indices()
    except Exception:
        pass
    try:
        shape = [int(v) for v in tuple(csr.shape)[:2]]
        indptr = np.ascontiguousarray(np.asarray(csr.indptr, dtype=np.dtype("<i8")).reshape(-1))
        indices = np.ascontiguousarray(np.asarray(csr.indices, dtype=np.dtype("<i8")).reshape(-1))
        raw_data = np.asarray(csr.data)
    except Exception:
        return None
    if len(shape) < 2 or shape[0] < 0 or shape[1] < 0 or raw_data.dtype.kind == "O":
        return None
    if raw_data.dtype.kind in {"f", "c"}:
        data = np.asarray(csr.data, dtype=np.dtype("<f8")).reshape(-1)
        if not np.all(np.isfinite(data)):
            return None
    elif raw_data.dtype.kind in {"i", "u", "b"}:
        data = np.asarray(csr.data, dtype=np.dtype("<i8")).reshape(-1)
    else:
        return None
    data = np.ascontiguousarray(data)
    dtype_text = str(data.dtype)
    return {
        "kind": "sparse_csr_content_v3",
        "content_kind": str(kind),
        "shape": shape,
        "indptr_length": int(indptr.size),
        "indices_length": int(indices.size),
        "data_length": int(data.size),
        "data_dtype": dtype_text,
        "digest": _geometry_fit_projection_content_hash(
            "sparse_csr_content_v3",
            str(kind),
            repr(shape),
            indptr.tobytes(order="C"),
            indices.tobytes(order="C"),
            dtype_text,
            data.tobytes(order="C"),
        ),
    }


def _geometry_fit_projection_freeze_array(array: np.ndarray) -> np.ndarray:
    array.setflags(write=False)
    return array


def _geometry_fit_projection_dense_storage_copy(
    value: object,
    *,
    allow_empty: bool = True,
) -> np.ndarray | None:
    try:
        raw = np.asarray(value)
    except Exception:
        return None
    if raw.dtype.kind == "O":
        return None
    if raw.dtype.kind in {"f", "c"}:
        try:
            copied = np.asarray(value, dtype=np.dtype("<f8"))
        except Exception:
            return None
        if not np.all(np.isfinite(copied)):
            return None
    elif raw.dtype.kind in {"i", "u"}:
        try:
            copied = np.asarray(value, dtype=np.dtype("<i8"))
        except Exception:
            return None
    elif raw.dtype.kind == "b":
        copied = np.asarray(value, dtype=np.dtype("u1"))
    else:
        return None
    if copied.size <= 0 and not bool(allow_empty):
        return None
    return _geometry_fit_projection_freeze_array(np.ascontiguousarray(copied).copy())


def _geometry_fit_projection_sparse_storage_copy(value: object) -> object | None:
    if not hasattr(value, "tocsr"):
        return None
    try:
        csr = value.tocsr(copy=True)  # type: ignore[attr-defined]
    except TypeError:
        try:
            csr = value.tocsr()  # type: ignore[attr-defined]
        except Exception:
            return None
    except Exception:
        return None
    try:
        csr.sort_indices()
    except Exception:
        pass
    try:
        shape = tuple(int(v) for v in tuple(csr.shape)[:2])
        indptr = np.ascontiguousarray(np.asarray(csr.indptr, dtype=np.dtype("<i8")).reshape(-1))
        indices = np.ascontiguousarray(np.asarray(csr.indices, dtype=np.dtype("<i8")).reshape(-1))
        raw_data = np.asarray(csr.data)
    except Exception:
        return None
    if len(shape) < 2 or shape[0] < 0 or shape[1] < 0 or raw_data.dtype.kind == "O":
        return None
    if raw_data.dtype.kind in {"f", "c"}:
        data = np.asarray(csr.data, dtype=np.dtype("<f8")).reshape(-1)
        if not np.all(np.isfinite(data)):
            return None
    elif raw_data.dtype.kind in {"i", "u", "b"}:
        data = np.asarray(csr.data, dtype=np.dtype("<i8")).reshape(-1)
    else:
        return None
    data = np.ascontiguousarray(data)
    try:
        csr.indptr = indptr.copy()
        csr.indices = indices.copy()
        csr.data = data.copy()
        csr.sort_indices()
        csr.indptr.setflags(write=False)
        csr.indices.setflags(write=False)
        csr.data.setflags(write=False)
    except Exception:
        return None
    return csr


def _geometry_fit_projection_transform_storage_copy(value: object) -> object | None:
    if value is None:
        return None
    if all(
        hasattr(value, attr) for attr in ("image_shape", "n_rad", "n_az", "matrix", "count_flat")
    ):
        try:
            image_shape = tuple(int(v) for v in tuple(value.image_shape)[:2])
            n_rad = int(value.n_rad)
            n_az = int(value.n_az)
        except Exception:
            return None
        matrix = _geometry_fit_projection_transform_storage_copy(value.matrix)
        count_flat = _geometry_fit_projection_dense_storage_copy(
            value.count_flat,
            allow_empty=True,
        )
        if matrix is None or count_flat is None:
            return None
        try:
            return type(value)(
                image_shape=image_shape,
                n_rad=n_rad,
                n_az=n_az,
                matrix=matrix,
                count_flat=count_flat,
            )
        except Exception:
            return SimpleNamespace(
                image_shape=image_shape,
                n_rad=n_rad,
                n_az=n_az,
                matrix=matrix,
                count_flat=count_flat,
            )
    sparse = _geometry_fit_projection_sparse_storage_copy(value)
    if sparse is not None:
        return sparse
    return _geometry_fit_projection_dense_storage_copy(value, allow_empty=True)


def _geometry_fit_projection_bundle_storage_copy(
    bundle: object,
) -> CakeTransformBundle | None:
    if not isinstance(bundle, CakeTransformBundle):
        return None
    detector_shape = _geometry_fit_projection_shape_token(getattr(bundle, "detector_shape", None))
    radial = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "radial_deg", None),
        allow_empty=False,
    )
    raw_azimuth = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "raw_azimuth_deg", None),
        allow_empty=False,
    )
    gui_azimuth = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "gui_azimuth_deg", None),
        allow_empty=False,
    )
    lut = _geometry_fit_projection_transform_storage_copy(getattr(bundle, "lut", None))
    lut_t_value = getattr(bundle, "lut_t", None)
    lut_t = (
        None
        if lut_t_value is None
        else _geometry_fit_projection_transform_storage_copy(lut_t_value)
    )
    if (
        detector_shape is None
        or radial is None
        or raw_azimuth is None
        or gui_azimuth is None
        or lut is None
        or (lut_t_value is not None and lut_t is None)
    ):
        return None
    return CakeTransformBundle(
        detector_shape=tuple(int(v) for v in detector_shape[:2]),
        radial_deg=radial,
        raw_azimuth_deg=raw_azimuth,
        gui_azimuth_deg=gui_azimuth,
        lut=lut,
        lut_t=lut_t,
    )


def _geometry_fit_projection_transform_content_token(
    value: object,
    *,
    kind: str,
) -> dict[str, object] | None:
    if value is None:
        return {"kind": "transform_none_v3", "content_kind": str(kind)}
    if all(
        hasattr(value, attr) for attr in ("image_shape", "n_rad", "n_az", "matrix", "count_flat")
    ):
        try:
            image_shape = [int(v) for v in tuple(value.image_shape)[:2]]
            n_rad = int(value.n_rad)
            n_az = int(value.n_az)
        except Exception:
            return None
        matrix_token = _geometry_fit_projection_transform_content_token(
            value.matrix,
            kind=f"{kind}.matrix",
        )
        count_token = _geometry_fit_projection_dense_content_token(
            value.count_flat,
            kind=f"{kind}.count_flat",
            allow_empty=True,
        )
        if matrix_token is None or count_token is None:
            return None
        return {
            "kind": "detector_cake_lut_content_v3",
            "content_kind": str(kind),
            "image_shape": image_shape,
            "n_rad": int(n_rad),
            "n_az": int(n_az),
            "matrix": matrix_token,
            "count_flat": count_token,
        }
    sparse_token = _geometry_fit_projection_sparse_content_token(value, kind=kind)
    if sparse_token is not None:
        return sparse_token
    return _geometry_fit_projection_dense_content_token(value, kind=kind, allow_empty=True)


def _geometry_fit_projection_bundle_content_token(
    bundle: object,
) -> dict[str, object] | None:
    if not isinstance(bundle, CakeTransformBundle):
        return None
    detector_shape = _geometry_fit_projection_shape_token(getattr(bundle, "detector_shape", None))
    radial_axis = _geometry_fit_projection_axis_token(getattr(bundle, "radial_deg", None))
    azimuth_axis = _geometry_fit_projection_axis_token(getattr(bundle, "gui_azimuth_deg", None))
    raw_azimuth_axis = _geometry_fit_projection_axis_token(getattr(bundle, "raw_azimuth_deg", None))
    lut = _geometry_fit_projection_transform_content_token(getattr(bundle, "lut", None), kind="lut")
    lut_t = _geometry_fit_projection_transform_content_token(
        getattr(bundle, "lut_t", None),
        kind="lut_t",
    )
    if (
        detector_shape is None
        or radial_axis is None
        or azimuth_axis is None
        or raw_azimuth_axis is None
        or lut is None
        or lut_t is None
    ):
        return None
    return {
        "kind": "cake_transform_bundle_content_v3",
        "detector_shape": detector_shape,
        "radial_axis": radial_axis,
        "azimuth_axis": azimuth_axis,
        "raw_azimuth_axis": raw_azimuth_axis,
        "lut": lut,
        "lut_t": lut_t,
    }


def _geometry_fit_projection_payload_digest(
    payload: Mapping[str, object] | None,
    *,
    trust_stored_token: bool = True,
) -> str | None:
    if not isinstance(payload, Mapping):
        return None
    existing_schema = str(payload.get("projection_token_schema") or "").strip()
    existing_token = payload.get("projection_content_token_v3")
    existing_source = str(payload.get("projection_content_token_source") or "").strip()
    if (
        bool(trust_stored_token)
        and existing_schema == _GEOMETRY_FIT_PROJECTION_TOKEN_SCHEMA
        and existing_source == _GEOMETRY_FIT_PROJECTION_TOKEN_SOURCE
        and isinstance(existing_token, str)
        and existing_token
    ):
        return str(existing_token)
    transform_bundle_token = _geometry_fit_projection_bundle_content_token(
        payload.get("transform_bundle")
    )
    if transform_bundle_token is None:
        return None
    token_payload = {
        "kind": "geometry_fit_projection_payload_content_v3",
        "detector_shape": _geometry_fit_projection_shape_token(payload.get("detector_shape")),
        "radial_axis": _geometry_fit_projection_axis_token(payload.get("radial_axis")),
        "azimuth_axis": _geometry_fit_projection_axis_token(payload.get("azimuth_axis")),
        "raw_azimuth_axis": _geometry_fit_projection_axis_token(payload.get("raw_azimuth_axis")),
        "raw_to_gui_row_permutation": _geometry_fit_projection_permutation_token(
            payload.get("raw_to_gui_row_permutation")
        ),
        "transform_bundle": transform_bundle_token,
    }
    if any(
        token_payload.get(key) is None
        for key in ("detector_shape", "radial_axis", "azimuth_axis", "raw_azimuth_axis")
    ):
        return None
    return gui_geometry_fit._geometry_fit_digest_payload(token_payload)


def _geometry_fit_projection_shape_token(value: object) -> list[int] | None:
    try:
        shape = [int(item) for item in tuple(value)[:2]]  # type: ignore[arg-type]
    except Exception:
        return None
    if len(shape) < 2 or shape[0] <= 0 or shape[1] <= 0:
        return None
    return shape[:2]


def _geometry_fit_projection_axis_token(value: object) -> tuple[object, ...] | None:
    token = gui_manual_geometry.geometry_manual_stable_axis_value_token(value)
    return tuple(token) if token is not None else None


def _geometry_fit_projection_permutation_token(value: object) -> tuple[object, ...] | None:
    return gui_manual_geometry.geometry_manual_stable_permutation_value_token(value)


def _geometry_fit_projection_payload_storage_copy(
    payload: Mapping[str, object] | None,
) -> dict[str, object] | None:
    projection = gui_geometry_fit.geometry_fit_caked_projection_payload(payload)
    if not isinstance(projection, Mapping):
        return None
    stored: dict[str, object] = {"payload_kind": "projection"}
    detector_shape = _geometry_fit_projection_shape_token(projection.get("detector_shape"))
    if detector_shape is not None:
        stored["detector_shape"] = tuple(int(v) for v in detector_shape[:2])
    for key in ("radial_axis", "azimuth_axis", "raw_azimuth_axis"):
        value = projection.get(key)
        if value is None:
            continue
        axis_copy = _geometry_fit_projection_dense_storage_copy(value, allow_empty=False)
        if axis_copy is None:
            return None
        stored[key] = axis_copy
    permutation = projection.get("raw_to_gui_row_permutation")
    if permutation is not None:
        try:
            permutation_copy = np.asarray(permutation, dtype=np.dtype("<i8")).reshape(-1)
        except Exception:
            return None
        if permutation_copy.size <= 0:
            return None
        stored["raw_to_gui_row_permutation"] = _geometry_fit_projection_freeze_array(
            np.ascontiguousarray(permutation_copy).copy()
        )
    transform_bundle = projection.get("transform_bundle")
    if transform_bundle is not None:
        copied_bundle = _geometry_fit_projection_bundle_storage_copy(transform_bundle)
        if copied_bundle is None:
            return None
        stored["transform_bundle"] = copied_bundle
        if "detector_shape" not in stored:
            stored["detector_shape"] = tuple(int(v) for v in copied_bundle.detector_shape[:2])
    projection_token = _geometry_fit_projection_payload_digest(stored, trust_stored_token=False)
    if projection_token is not None:
        stored["projection_token_schema"] = _GEOMETRY_FIT_PROJECTION_TOKEN_SCHEMA
        stored["projection_content_token_v3"] = str(projection_token)
        stored["projection_content_token_source"] = _GEOMETRY_FIT_PROJECTION_TOKEN_SOURCE
    return stored


def _geometry_fit_targeted_projection_view_mode() -> str:
    try:
        view_mode = _current_app_shell_view_mode()
    except Exception:
        view_mode = None
    try:
        figure_mode = _current_primary_figure_mode()
    except Exception:
        figure_mode = None
    normalized_figure_mode = str(figure_mode or "").strip().lower()
    if normalized_figure_mode in {"caked", "q_space"}:
        return normalized_figure_mode
    normalized_mode = str(view_mode or "").strip().lower()
    if normalized_mode not in {"detector", "caked", "q_space"}:
        return "detector"
    return normalized_mode


def _geometry_manual_consumer_is_manual_pick_cache(lookup_context: object) -> bool:
    return str(lookup_context or "").strip() in {
        "manual_pick_cache",
        "manual_pick_cache_coverage",
    }


def _geometry_manual_projection_mode_override_for_consumer(
    lookup_context: str | None,
    *,
    background_index: int | None = None,
) -> str | None:
    if not _geometry_manual_consumer_is_manual_pick_cache(lookup_context):
        return None
    pick_uses_caked = False
    pick_uses_caked_factory = globals().get("_geometry_manual_pick_uses_caked_space")
    if callable(pick_uses_caked_factory):
        try:
            pick_uses_caked = bool(pick_uses_caked_factory())
        except Exception:
            pick_uses_caked = False
    if not pick_uses_caked:
        return "detector"
    if background_index is None:
        return "detector"
    try:
        caked_payload = _geometry_fit_caked_view_for_index(int(background_index))
    except Exception:
        caked_payload = None
    if not isinstance(caked_payload, Mapping):
        return "detector"
    try:
        params_for_payload = dict(_current_geometry_fit_params() or {})
    except Exception:
        params_for_payload = {}
    try:
        hydrated_payload = gui_geometry_fit._geometry_fit_hydrate_exact_caked_payload(
            caked_payload,
            detector_shape=caked_payload.get("detector_shape"),
            params=params_for_payload,
            require_background=False,
        )
    except Exception:
        hydrated_payload = None
    if not isinstance(hydrated_payload, Mapping) or not isinstance(
        hydrated_payload.get("transform_bundle"),
        CakeTransformBundle,
    ):
        return "detector"
    return None


def _geometry_fit_projection_signature_public(
    signature: Mapping[str, object],
) -> dict[str, object]:
    return {
        str(key): gui_geometry_fit._geometry_fit_cache_jsonable(value)
        for key, value in signature.items()
    }


def _geometry_fit_targeted_projection_view_signature(
    background_index: int | None = None,
    *,
    mode_override: str | None = None,
    caked_payload: Mapping[str, object] | None = None,
    detector_shape: Sequence[object] | None = None,
    ai: FastAzimuthalIntegrator | None = None,
    q_space_image: object = None,
    analysis_preview_bins: Sequence[object] | None = None,
) -> dict[str, object]:
    normalized_mode = (
        str(
            mode_override
            if mode_override is not None
            else _geometry_fit_targeted_projection_view_mode()
        )
        .strip()
        .lower()
    )
    if normalized_mode not in {"detector", "caked", "q_space"}:
        normalized_mode = "detector"
    try:
        current_background_idx = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_idx = int(background_index or 0)
    try:
        background_idx = int(
            current_background_idx if background_index is None else background_index
        )
    except Exception:
        background_idx = int(background_index or 0)
    signature: dict[str, object] = {
        "mode": str(normalized_mode),
        "background_index": int(background_idx),
        "current_background_index": int(current_background_idx),
    }
    ai_value = ai
    if ai_value is None:
        ai_cache = getattr(simulation_runtime_state, "ai_cache", None)
        ai_value = ai_cache.get("ai") if isinstance(ai_cache, Mapping) else None
    normalized_shape = _geometry_fit_detector_shape_2d(detector_shape)
    if normalized_shape is None:
        try:
            if int(background_idx) == int(current_background_idx):
                native_background = _get_current_background_native()
            else:
                native_background, _display_background = _load_background_image_by_index(
                    int(background_idx)
                )
            normalized_shape = _geometry_fit_detector_shape_2d(
                np.asarray(native_background, dtype=np.float64).shape[:2]
            )
        except Exception:
            normalized_shape = None
    if normalized_shape is not None:
        signature["detector_shape"] = [int(v) for v in normalized_shape[:2]]
    if normalized_mode == "detector":
        signature["available"] = True
        return _geometry_fit_projection_signature_public(signature)
    preview_bins = analysis_preview_bins
    if preview_bins is None:
        preview_bins = getattr(simulation_runtime_state, "analysis_preview_bins", None)
    if isinstance(preview_bins, (tuple, list)) and len(preview_bins) >= 2:
        normalized_bins = [int(preview_bins[0]), int(preview_bins[1])]
        signature["analysis_bins"] = list(normalized_bins)
    if normalized_mode == "q_space":
        if int(background_idx) != int(current_background_idx):
            signature["available"] = False
            signature["reason"] = "missing_background_projection_payload"
            signature["projection_payload_digest"] = None
            return _geometry_fit_projection_signature_public(signature)
        signature["available"] = True
        signature["extent"] = list(_resolve_primary_q_space_extent())
        resolved_q_space_image = q_space_image
        if resolved_q_space_image is None:
            try:
                resolved_q_space_image = np.asarray(
                    getattr(simulation_runtime_state, "last_q_space_image", None)
                )
            except Exception:
                resolved_q_space_image = None
        if isinstance(resolved_q_space_image, np.ndarray) and resolved_q_space_image.ndim >= 2:
            signature["image_shape"] = [int(v) for v in resolved_q_space_image.shape[:2]]
        signature["projection_payload_digest"] = gui_geometry_fit._geometry_fit_digest_payload(
            {
                "extent": signature.get("extent"),
                "image_shape": signature.get("image_shape"),
                "analysis_bins": signature.get("analysis_bins"),
            }
        )
        return _geometry_fit_projection_signature_public(signature)
    if normalized_mode == "caked":
        normalized_payload = _geometry_fit_resolve_targeted_caked_projection_payload(
            background_idx,
            caked_payload=caked_payload,
            detector_shape=detector_shape,
            ai=ai_value,
            analysis_preview_bins=analysis_preview_bins,
            allow_generated_payload=True,
        )
        if isinstance(normalized_payload, Mapping):
            projection_payload_digest = _geometry_fit_projection_payload_digest(normalized_payload)
            if projection_payload_digest is None:
                signature["available"] = False
                signature["reason"] = "invalid_background_caked_payload"
                signature["projection_payload_digest"] = None
                return _geometry_fit_projection_signature_public(signature)
            signature.update(
                {
                    "available": True,
                    "detector_shape": list(tuple(normalized_payload.get("detector_shape", ()))[:2]),
                    "radial_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("radial_axis")
                    ),
                    "azimuth_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("azimuth_axis")
                    ),
                    "raw_azimuth_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("raw_azimuth_axis")
                    ),
                    "raw_to_gui_row_permutation": _geometry_fit_projection_permutation_token(
                        normalized_payload.get("raw_to_gui_row_permutation")
                    ),
                    "projection_payload_digest": projection_payload_digest,
                }
            )
        else:
            signature["available"] = False
            signature["reason"] = "missing_background_caked_payload"
            signature["projection_payload_digest"] = None
        return _geometry_fit_projection_signature_public(signature)
    return _geometry_fit_projection_signature_public(signature)


def _geometry_fit_filter_hit_tables_for_required_branch_groups(
    source_tables: Sequence[object] | None,
    *,
    required_branch_group_keys: Sequence[tuple[tuple[int, int, int], int | None, object | None]]
    | None,
) -> tuple[list[object], dict[str, object]]:
    copied_tables = list(source_tables or ())
    if not copied_tables:
        return [], {
            "total_hit_tables_available": 0,
            "hit_tables_considered_for_rebinding": 0,
            "hit_tables_expanded_for_rebinding": 0,
        }
    required_keys = list(required_branch_group_keys or ())
    if not required_keys:
        return _copy_hit_tables(copied_tables), {
            "total_hit_tables_available": int(len(copied_tables)),
            "hit_tables_considered_for_rebinding": int(len(copied_tables)),
            "hit_tables_expanded_for_rebinding": int(len(copied_tables)),
        }

    required_group_identities = {
        tuple(key[2])
        for key in required_keys
        if isinstance(key, (tuple, list)) and len(key) >= 3 and key[2] is not None
    }

    def _row_q_group_identity(
        hkl: tuple[int, int, int],
    ) -> tuple[object, ...] | None:
        try:
            q_group_key, _qr_val, _qz_val = (
                gui_geometry_q_group_manager.reflection_q_group_metadata(
                    hkl,
                    source_label="primary",
                    allow_nominal_hkl_indices=True,
                )
            )
        except Exception:
            return None
        if q_group_key is None:
            return None
        try:
            return tuple(q_group_key)
        except Exception:
            return None

    def _matching_required_keys_for_table(
        hkl: tuple[int, int, int],
    ) -> list[tuple[tuple[int, int, int], int | None, object | None]]:
        exact_matches = [key for key in required_keys if tuple(key[0]) == tuple(hkl)]
        if exact_matches:
            return exact_matches
        q_group_key = _row_q_group_identity(hkl)
        if q_group_key is None or q_group_key not in required_group_identities:
            return []
        return [
            key
            for key in required_keys
            if isinstance(key, (tuple, list))
            and len(key) >= 3
            and key[2] is not None
            and tuple(key[2]) == q_group_key
        ]

    filtered_tables: list[object] = []
    considered_count = 0
    expanded_count = 0

    for table in copied_tables:
        arr = np.asarray(table, dtype=np.float64)
        if arr.ndim != 2 or arr.shape[0] <= 0:
            continue
        if is_intersection_cache_table(arr):
            h_col, k_col, l_col, phi_col = (
                CACHE_COL_H,
                CACHE_COL_K,
                CACHE_COL_L,
                CACHE_COL_PHI,
            )
        else:
            h_col, k_col, l_col, phi_col = (
                HIT_ROW_COL_H,
                HIT_ROW_COL_K,
                HIT_ROW_COL_L,
                HIT_ROW_COL_PHI,
            )
        if arr.shape[1] <= max(h_col, k_col, l_col, phi_col):
            continue
        try:
            table_hkl = (
                int(np.rint(float(arr[0, h_col]))),
                int(np.rint(float(arr[0, k_col]))),
                int(np.rint(float(arr[0, l_col]))),
            )
        except Exception:
            continue
        matching_keys = _matching_required_keys_for_table(table_hkl)
        if not matching_keys:
            continue
        considered_count += 1
        allowed_branches = {int(key[1]) for key in matching_keys if key[1] is not None}
        if not allowed_branches:
            filtered_tables.append(arr.copy())
            expanded_count += 1
            continue
        branch_mask = np.zeros(arr.shape[0], dtype=bool)
        for row_idx in range(arr.shape[0]):
            try:
                row_phi = float(arr[row_idx, phi_col])
            except Exception:
                continue
            branch_idx = source_branch_index_from_phi_deg(row_phi)
            if branch_idx in allowed_branches:
                branch_mask[row_idx] = True
        if np.any(branch_mask):
            filtered_tables.append(np.asarray(arr[branch_mask], dtype=np.float64).copy())
            expanded_count += 1

    return filtered_tables, {
        "total_hit_tables_available": int(len(copied_tables)),
        "hit_tables_considered_for_rebinding": int(considered_count),
        "hit_tables_expanded_for_rebinding": int(expanded_count),
    }


def _geometry_manual_logged_cache_matches_params(
    metadata: Mapping[str, object] | None,
    params_local: Mapping[str, object],
) -> dict[str, object]:
    if not isinstance(metadata, Mapping):
        return {
            "matches": False,
            "expected_signature_digest": None,
            "actual_signature_digest": None,
            "mismatch_reason": "missing_metadata",
            "heavy_hit_table_load_attempted": False,
        }

    comparisons: list[tuple[object, float, float]] = []
    comparisons.append((metadata.get("av"), params_local.get("a"), 1.0e-6))
    comparisons.append((metadata.get("cv"), params_local.get("c"), 1.0e-6))
    comparisons.append((metadata.get("wavelength_center"), params_local.get("lambda"), 1.0e-6))
    comparisons.append((metadata.get("theta_center"), params_local.get("theta_initial"), 1.0e-6))

    expected_signature_digest = gui_geometry_fit._geometry_fit_digest_payload(
        {
            "a": params_local.get("a"),
            "c": params_local.get("c"),
            "lambda": params_local.get("lambda"),
            "theta_initial": params_local.get("theta_initial"),
        }
    )
    actual_signature_digest = metadata.get("signature_digest")
    if actual_signature_digest in {None, ""}:
        actual_signature_digest = gui_geometry_fit._geometry_fit_digest_payload(
            {
                "a": metadata.get("av"),
                "c": metadata.get("cv"),
                "lambda": metadata.get("wavelength_center"),
                "theta_initial": metadata.get("theta_center"),
            }
        )

    matched_checks = 0
    for logged_value, requested_value, tol in comparisons:
        try:
            logged_float = float(logged_value)
            requested_float = float(requested_value)
        except Exception:
            continue
        if not (np.isfinite(logged_float) and np.isfinite(requested_float)):
            continue
        matched_checks += 1
        if abs(float(logged_float) - float(requested_float)) > float(tol):
            return {
                "matches": False,
                "expected_signature_digest": str(expected_signature_digest),
                "actual_signature_digest": str(actual_signature_digest),
                "mismatch_reason": "params_mismatch",
                "heavy_hit_table_load_attempted": False,
            }
    if matched_checks <= 0:
        return {
            "matches": False,
            "expected_signature_digest": str(expected_signature_digest),
            "actual_signature_digest": str(actual_signature_digest),
            "mismatch_reason": "insufficient_metadata",
            "heavy_hit_table_load_attempted": False,
        }
    return {
        "matches": True,
        "expected_signature_digest": str(expected_signature_digest),
        "actual_signature_digest": str(actual_signature_digest),
        "mismatch_reason": None,
        "heavy_hit_table_load_attempted": False,
    }


def _geometry_fit_background_label(background_index: int) -> str:
    """Return a short human-readable label for one background index."""

    try:
        osc_path = background_runtime_state.osc_files[int(background_index)]
    except Exception:
        osc_path = None
    if osc_path is not None:
        try:
            name = Path(str(osc_path)).name
        except Exception:
            name = ""
        if str(name).strip():
            return str(name)
    return f"background {int(background_index) + 1}"


def _normalize_geometry_fit_projection_view_signature(
    raw: object,
    background_index: int,
) -> dict[str, object]:
    """Normalize legacy projection signatures before mapping-style access."""

    background_idx = int(background_index)
    if isinstance(raw, Mapping):
        return dict(raw)
    if raw is None:
        return {
            "mode": "detector",
            "available": False,
            "background_index": int(background_idx),
            "reason": "missing_projection_view_signature",
        }
    reason = f"invalid_projection_view_signature_type:{type(raw).__name__}"
    try:
        legacy_signature = gui_geometry_fit._geometry_fit_cache_jsonable(raw)
    except Exception:
        legacy_signature = repr(raw)
    return {
        "mode": "detector",
        "available": False,
        "background_index": int(background_idx),
        "reason": reason,
        "legacy_projection_view_signature": legacy_signature,
    }


def _geometry_fit_logged_intersection_cache_loaders() -> tuple[
    Callable[..., object] | None, Callable[..., object] | None
]:
    try:
        enabled = bool(intersection_cache_logging_enabled())
    except Exception:
        enabled = False
    if not enabled:
        return None, None
    return (
        load_most_recent_logged_intersection_cache_metadata,
        load_most_recent_logged_intersection_cache,
    )


def _commit_geometry_manual_source_row_rebuild_result(
    rebuild_result: gui_geometry_fit.GeometryFitSourceRowRebuildResult,
    *,
    consumer: str | None = None,
) -> list[dict[str, object]]:
    """Commit one pure source-row rebuild payload onto the live runtime state."""

    if not isinstance(rebuild_result, gui_geometry_fit.GeometryFitSourceRowRebuildResult):
        return []

    background_idx = int(rebuild_result.background_index)
    try:
        current_background_index = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_index = int(background_idx)
    is_current_background = int(background_idx) == int(current_background_index)
    stored_rows = [
        dict(entry) for entry in (rebuild_result.stored_rows or ()) if isinstance(entry, Mapping)
    ]
    projected_rows = [
        dict(entry) for entry in (rebuild_result.projected_rows or ()) if isinstance(entry, Mapping)
    ]
    diagnostics = (
        dict(rebuild_result.diagnostics) if isinstance(rebuild_result.diagnostics, Mapping) else {}
    )
    lookup_context = str(diagnostics.get("consumer") or consumer or "unspecified")
    targeted_preflight_enabled = bool(diagnostics.get("targeted_preflight_enabled", False))
    targeted_cache_key_digest = str(
        diagnostics.get("required_hkl_branch_keys_digest") or ""
    ).strip()
    rebuild_succeeded = bool(stored_rows or projected_rows) and bool(
        str(rebuild_result.rebuild_source or "").strip()
    )

    if not rebuild_succeeded:
        if diagnostics:
            _set_geometry_manual_source_snapshot_diagnostics(**diagnostics)
        _trace_live_cache_event(
            "source_snapshot",
            "rebuild",
            background_index=int(background_idx),
            outcome="failed",
            consumer=lookup_context,
            status=str(diagnostics.get("status", "snapshot_rebuild_failed")),
            requested_signature_summary=diagnostics.get("requested_signature_summary"),
            raw_peak_count=int(len(stored_rows)),
            projected_peak_count=int(len(projected_rows)),
            rebuild_source=str(rebuild_result.rebuild_source or "unknown"),
        )
        return []

    if stored_rows:
        if targeted_preflight_enabled and targeted_cache_key_digest:
            targeted_projection_mode = str(
                diagnostics.get("projection_view_mode")
                or _geometry_fit_targeted_projection_view_mode()
            )
            targeted_projection_signature = _normalize_geometry_fit_projection_view_signature(
                diagnostics.get("projection_view_signature")
                or _geometry_fit_targeted_projection_view_signature(
                    background_idx,
                    mode_override=targeted_projection_mode,
                ),
                background_idx,
            )
            _geometry_fit_store_targeted_projected_cache_entry(
                background_index=int(background_idx),
                key_digest=str(targeted_cache_key_digest),
                payload={
                    "requested_signature": (
                        gui_geometry_fit._geometry_fit_cache_jsonable(
                            rebuild_result.requested_signature
                        )
                    ),
                    "requested_signature_summary": (
                        gui_geometry_fit._geometry_fit_cache_jsonable(
                            rebuild_result.requested_signature_summary
                        )
                    ),
                    "stored_rows": [dict(entry) for entry in stored_rows],
                    "projected_rows": [dict(entry) for entry in projected_rows],
                    "diagnostics": copy.deepcopy(diagnostics),
                    "cache_source": str(rebuild_result.rebuild_source or "unknown"),
                    "consumer": str(lookup_context),
                    "projection_view_mode": str(targeted_projection_mode),
                    "projection_view_signature": targeted_projection_signature,
                },
            )
    hit_tables_local = rebuild_result.hit_tables
    q_group_content_signature = None
    source_rows_carry_theta = any(
        isinstance(entry, Mapping)
        and ("theta_initial" in entry or "theta_initial_deg" in entry or "theta_i" in entry)
        for entry in stored_rows
    )
    if stored_rows and (source_rows_carry_theta or hit_tables_local is None):
        q_group_content_signature = (
            gui_geometry_q_group_manager._geometry_q_group_content_signature_from_source_rows(
                stored_rows
            )
        )
    if q_group_content_signature is None and hit_tables_local is not None:
        q_group_content_signature = (
            gui_geometry_q_group_manager._geometry_q_group_content_signature_from_hit_tables(
                hit_tables_local
            )
        )
    if hit_tables_local is not None:
        try:
            max_positions_local = hit_tables_to_max_positions(hit_tables_local)
        except Exception:
            max_positions_local = np.empty((0, 6), dtype=np.float64)
        simulation_runtime_state.stored_max_positions_local = list(max_positions_local)
    else:
        simulation_runtime_state.stored_max_positions_local = None
    simulation_runtime_state.stored_q_group_content_signature = q_group_content_signature
    simulation_runtime_state.stored_source_reflection_indices_local = (
        list(rebuild_result.source_reflection_indices)
        if isinstance(rebuild_result.source_reflection_indices, list)
        else None
    )
    if rebuild_result.peak_table_lattice is not None:
        simulation_runtime_state.stored_peak_table_lattice = list(rebuild_result.peak_table_lattice)
    simulation_runtime_state.stored_sim_image = np.zeros(
        (int(image_size), int(image_size)),
        dtype=np.float64,
    )
    if rebuild_result.intersection_cache is not None:
        simulation_runtime_state.stored_intersection_cache = _copy_intersection_cache_tables(
            rebuild_result.intersection_cache
        )
        _clear_caked_intersection_cache()
    simulation_runtime_state.last_simulation_signature = rebuild_result.requested_signature
    if is_current_background:
        if projected_rows:
            _geometry_manual_set_runtime_peak_cache_from_projected_rows(projected_rows)
        else:
            _geometry_manual_set_runtime_peak_cache_from_source_rows(stored_rows)

    snapshot_payload = _geometry_source_snapshot_payload(
        background_index=int(background_idx),
        simulation_signature=rebuild_result.requested_signature,
        rows=stored_rows,
        projected_rows=projected_rows,
        diagnostics=diagnostics,
        requested_signature=rebuild_result.requested_signature,
        requested_signature_summary=rebuild_result.requested_signature_summary,
        projection_view_signature=_normalize_geometry_fit_projection_view_signature(
            diagnostics.get("projection_view_signature")
            or _geometry_fit_targeted_projection_view_signature(background_idx),
            background_idx,
        ),
        created_from=str(rebuild_result.rebuild_source or "unknown"),
        source_reflection_index_count=int(len(rebuild_result.source_reflection_indices or ())),
        empty_reason="no_source_rows",
    )
    if _retain_runtime_optional_cache("source_snapshots", feature_needed=True) and bool(
        snapshot_payload.get("valid_for_picker", False)
    ):
        simulation_runtime_state.source_row_snapshots[int(background_idx)] = snapshot_payload
    else:
        simulation_runtime_state.source_row_snapshots.pop(int(background_idx), None)

    strict_projection_return = not is_current_background and str(
        diagnostics.get("projection_view_mode") or _geometry_fit_targeted_projection_view_mode()
    ).strip().lower() in {"caked", "q_space"}
    final_return_row_count = int(
        len(projected_rows)
        if projected_rows
        else (0 if strict_projection_return else len(stored_rows))
    )
    if str(diagnostics.get("status", "")) == "snapshot_hit" and final_return_row_count <= 0:
        diagnostics["status"] = (
            "snapshot_hit_projection_unavailable"
            if strict_projection_return
            else "snapshot_hit_empty_rows"
        )
        diagnostics.setdefault(
            "snapshot_filter_reason",
            str(diagnostics.get("status")),
        )
        diagnostics.setdefault("stale_reason", str(diagnostics.get("status")))
        diagnostics["final_returned_row_count"] = 0

    if diagnostics:
        _set_geometry_manual_source_snapshot_diagnostics(**diagnostics)
    _trace_live_cache_event(
        "source_snapshot",
        "rebuild",
        background_index=int(background_idx),
        outcome="success",
        consumer=lookup_context,
        status=str(diagnostics.get("status", "snapshot_hit")),
        requested_signature_summary=diagnostics.get("requested_signature_summary"),
        raw_peak_count=int(len(stored_rows)),
        projected_peak_count=int(len(projected_rows)),
        rebuild_source=str(rebuild_result.rebuild_source or "unknown"),
    )
    if lookup_context == "geometry_fit_trial_source_rows":
        if projected_rows:
            return projected_rows
        if strict_projection_return:
            return []
        return stored_rows
    if projected_rows:
        return projected_rows
    if not is_current_background and str(
        diagnostics.get("projection_view_mode") or _geometry_fit_targeted_projection_view_mode()
    ).strip().lower() in {"caked", "q_space"}:
        return []
    return stored_rows


def _geometry_manual_rebuild_source_rows_for_background(
    background_index: int,
    param_set: dict[str, object] | None = None,
    *,
    consumer: str | None = None,
    prior_diagnostics: Mapping[str, object] | None = None,
    required_pairs: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    background_idx = int(background_index)
    lookup_context = str(consumer or "unspecified")
    params_local = dict(_current_geometry_fit_params())
    if isinstance(param_set, Mapping):
        params_local.update(dict(param_set))

    requested_signature = _geometry_source_snapshot_signature_for_background(
        background_idx,
        params_local,
    )
    requested_signature_summary = _live_cache_signature_summary(requested_signature)
    can_use_live_runtime_cache = background_idx == int(
        background_runtime_state.current_background_index
    )
    live_cache_inventory = _live_cache_inventory_snapshot()
    background_label = _geometry_fit_background_label(background_idx)
    projection_mode_override = _geometry_manual_projection_mode_override_for_consumer(
        lookup_context,
        background_index=background_idx,
    )
    projection_view_signature = _normalize_geometry_fit_projection_view_signature(
        _geometry_fit_targeted_projection_view_signature(
            background_idx,
            mode_override=projection_mode_override,
        ),
        background_idx,
    )
    projection_view_mode = str(projection_view_signature.get("mode") or "detector")
    manual_pick_cache_lookup = _geometry_manual_consumer_is_manual_pick_cache(lookup_context)
    if (
        manual_pick_cache_lookup
        and projection_view_mode != "detector"
        and not bool(projection_view_signature.get("available", True))
    ):
        projection_view_signature = _normalize_geometry_fit_projection_view_signature(
            _geometry_fit_targeted_projection_view_signature(
                background_idx,
                mode_override="detector",
            ),
            background_idx,
        )
        projection_view_mode = str(projection_view_signature.get("mode") or "detector")
    projection_payload = (
        _geometry_fit_resolve_targeted_caked_projection_payload(
            int(background_idx),
            analysis_preview_bins=getattr(
                simulation_runtime_state,
                "analysis_preview_bins",
                None,
            ),
            allow_generated_payload=True,
        )
        if projection_view_mode == "caked"
        else None
    )
    required_manual_fit_targets = (
        gui_geometry_fit.collect_geometry_fit_required_manual_fit_targets(
            required_pairs,
            background_index=int(background_idx),
        )
        if required_pairs
        else []
    )
    required_branch_group_keys = gui_geometry_fit._geometry_fit_required_branch_group_keys(
        required_manual_fit_targets
    )
    preflight_mode = "manual_geometry_targeted" if required_branch_group_keys else "full"

    def _build_source_rows_for_rebuild(
        source_tables: Sequence[object] | None,
        *,
        required_branch_group_keys: Sequence[tuple[tuple[int, int, int], int | None, object | None]]
        | None = None,
        required_manual_fit_targets: Sequence[Mapping[str, object]] | None = None,
        preflight_mode: str = "full",
        consumer: str | None = None,
    ) -> tuple[list[dict[str, object]], list[tuple[float, float, str]], list[object]]:
        table_list = list(source_tables or ())
        if not table_list:
            return [], [], []
        if is_intersection_cache_table(table_list[0]):
            hit_tables_local = intersection_cache_to_hit_tables(table_list)
        else:
            hit_tables_local = _copy_hit_tables(table_list)
        if str(preflight_mode or "full") == "manual_geometry_targeted":
            hit_tables_local, _filter_diag = (
                _geometry_fit_filter_hit_tables_for_required_branch_groups(
                    hit_tables_local,
                    required_branch_group_keys=required_branch_group_keys,
                )
            )
        source_rows, peak_table_lattice, copied_hit_tables, source_reflection_indices = (
            _geometry_manual_build_source_rows_from_hit_tables(
                hit_tables_local,
                image_size_value=int(image_size),
                params_local=params_local,
                allow_nominal_hkl_indices=True,
            )
        )
        if str(consumer or lookup_context) == "geometry_fit_trial_source_rows":
            source_rows, supplemental_diag = _supplement_trial_source_rows_from_hit_tables(
                hit_tables_local,
                existing_rows=source_rows,
                required_branch_group_keys=required_branch_group_keys,
                params_local=params_local,
                image_size_value=int(image_size),
            )
            try:
                setattr(
                    _build_source_rows_for_rebuild,
                    "last_trial_supplemental_diag",
                    supplemental_diag,
                )
            except Exception:
                pass
        return source_rows, peak_table_lattice, copied_hit_tables, source_reflection_indices

    def _supplement_trial_source_rows_from_hit_tables(
        hit_tables: Sequence[object] | None,
        *,
        existing_rows: Sequence[Mapping[str, object]] | None,
        required_branch_group_keys: Sequence[tuple[tuple[int, int, int], int | None, object | None]]
        | None,
        params_local: Mapping[str, object],
        image_size_value: int,
    ) -> tuple[list[dict[str, object]], dict[str, object]]:
        rows = [dict(row) for row in (existing_rows or ()) if isinstance(row, Mapping)]
        diag = {
            "input_row_count": int(len(rows)),
            "supplemental_row_count": 0,
            "hit_row_count": 0,
            "q_group_match_count": 0,
            "branch_match_count": 0,
            "duplicate_row_count": 0,
            "q_group_counts": {},
        }
        required_keys = [
            key
            for key in (required_branch_group_keys or ())
            if isinstance(key, (tuple, list)) and len(key) >= 3 and key[2] is not None
        ]
        if not required_keys:
            return rows, diag
        required_group_identities = {tuple(key[2]) for key in required_keys}
        existing_identity_keys: set[tuple[object, ...]] = set()
        for row in rows:
            try:
                row_hkl = tuple(
                    int(v)
                    for v in (
                        row.get("normalized_hkl") or row.get("hkl") or row.get("source_hkl") or ()
                    )[:3]
                )
            except Exception:
                row_hkl = ()
            try:
                row_branch = int(row.get("source_branch_index"))
            except Exception:
                row_branch = -1
            existing_identity_keys.add(
                (
                    tuple(row.get("q_group_key") or ()),
                    row_hkl,
                    row_branch,
                    row.get("source_table_index"),
                    row.get("source_row_index"),
                    row.get("source_peak_index"),
                )
            )

        try:
            primary_a = float(params_local.get("a", np.nan))
        except Exception:
            primary_a = float("nan")
        try:
            primary_c = float(params_local.get("c", np.nan))
        except Exception:
            primary_c = float("nan")

        for table_position, table in enumerate(hit_tables or ()):
            hit_rows = gui_geometry_q_group_manager.geometry_reference_hit_rows(table)
            if not hit_rows:
                continue
            for row_position, hit_row in enumerate(hit_rows):
                diag["hit_row_count"] = int(diag["hit_row_count"]) + 1
                try:
                    intensity, xpix, ypix, phi_deg, h_val, k_val, l_val = hit_row[:7]
                    hkl = (
                        int(np.rint(float(h_val))),
                        int(np.rint(float(k_val))),
                        int(np.rint(float(l_val))),
                    )
                    native_col = float(xpix)
                    native_row = float(ypix)
                    phi_value = float(phi_deg)
                except Exception:
                    continue
                q_group_key, qr_val, qz_val = (
                    gui_geometry_q_group_manager.reflection_q_group_metadata(
                        hkl,
                        source_label="primary",
                        a_value=primary_a,
                        c_value=primary_c,
                        allow_nominal_hkl_indices=True,
                    )
                )
                if q_group_key is None or tuple(q_group_key) not in required_group_identities:
                    continue
                diag["q_group_match_count"] = int(diag["q_group_match_count"]) + 1
                q_label = json.dumps(tuple(q_group_key), sort_keys=True)
                q_counts = diag["q_group_counts"]
                if isinstance(q_counts, dict):
                    q_counts[q_label] = int(q_counts.get(q_label, 0)) + 1
                branch_index = source_branch_index_from_phi_deg(phi_value)
                matching_required_keys = [
                    key
                    for key in required_keys
                    if tuple(key[2]) == tuple(q_group_key)
                    and (key[1] is None or branch_index == int(key[1]))
                ]
                if not matching_required_keys:
                    continue
                diag["branch_match_count"] = int(diag["branch_match_count"]) + 1
                source_table_index, source_row_index, best_sample_index = (
                    extract_hit_row_provenance(hit_row)
                )
                if source_table_index is None:
                    source_table_index = int(table_position)
                if source_row_index is None:
                    source_row_index = int(row_position)
                source_peak_index = int(branch_index) if branch_index in {0, 1} else None
                identity_key = (
                    tuple(q_group_key),
                    hkl,
                    int(branch_index) if branch_index in {0, 1} else -1,
                    int(source_table_index),
                    int(source_row_index),
                    source_peak_index,
                )
                if identity_key in existing_identity_keys:
                    diag["duplicate_row_count"] = int(diag["duplicate_row_count"]) + 1
                    continue
                try:
                    display_col, display_row = _native_sim_to_display_coords(
                        native_col,
                        native_row,
                        (int(image_size_value), int(image_size_value)),
                    )
                except Exception:
                    display_col, display_row = native_col, native_row
                supplemental = {
                    "hkl": hkl,
                    "normalized_hkl": hkl,
                    "native_col": float(native_col),
                    "native_row": float(native_row),
                    "coordinate_frame": "simulation_native",
                    "sim_col": float(display_col),
                    "sim_row": float(display_row),
                    "sim_col_raw": float(display_col),
                    "sim_row_raw": float(display_row),
                    "display_col": float(display_col),
                    "display_row": float(display_row),
                    "detector_display_source": "native_sim_to_display",
                    "weight": max(0.0, float(abs(float(intensity)))),
                    "source_label": "primary",
                    "source_table_index": int(source_table_index),
                    "source_row_index": int(source_row_index),
                    "hkl_raw": (float(h_val), float(k_val), float(l_val)),
                    "phi": float(phi_value),
                    "av": float(primary_a),
                    "cv": float(primary_c),
                    "qr": float(qr_val),
                    "qz": float(qz_val),
                    "q_group_key": tuple(q_group_key),
                    "row_origin": "geometry_fit_trial_hit_inventory_row",
                    "geometry_fit_trial_hit_inventory_row": True,
                }
                if branch_index in {0, 1}:
                    supplemental["source_branch_index"] = int(branch_index)
                    supplemental["source_peak_index"] = int(branch_index)
                if best_sample_index is not None:
                    supplemental["best_sample_index"] = int(best_sample_index)
                rows.append(supplemental)
                existing_identity_keys.add(identity_key)
                diag["supplemental_row_count"] = int(diag["supplemental_row_count"]) + 1
        diag["output_row_count"] = int(len(rows))
        return rows, diag

    def _build_geometry_fit_live_rows_payload_from_cache() -> (
        dict[str, object] | list[dict[str, object]]
    ):
        live_rows = [
            dict(entry)
            for entry in (_build_live_preview_simulated_peaks_from_cache() or ())
            if isinstance(entry, Mapping)
        ]
        cache_metadata = (
            dict(_last_live_preview_cache_metadata())
            if callable(_last_live_preview_cache_metadata)
            else {}
        )
        live_source_counts = _geometry_fit_live_row_source_counts(live_rows)
        if (
            _geometry_fit_q_group_cache_has_restored_source(DISORDERED_PHASE_SOURCE_LABEL)
            and int(live_source_counts.get(DISORDERED_PHASE_SOURCE_LABEL, 0) or 0) <= 0
        ):
            disordered_rows = _geometry_manual_stored_disordered_phase_source_rows(params_local)
            if disordered_rows:
                disordered_cache_source = "stored_disordered_phase_hit_tables"
                live_rows.extend(disordered_rows)
                cache_metadata["stored_disordered_phase_source_rows"] = int(len(disordered_rows))
                cache_metadata["live_rows_cache_source"] = (
                    f"live_preview_cache+{disordered_cache_source}"
                    if live_source_counts
                    else disordered_cache_source
                )
                if not live_source_counts:
                    cache_metadata["live_rows_signature_match"] = True
                    cache_metadata["live_rows_signature_reason"] = disordered_cache_source
                cache_metadata["source_counts"] = _geometry_fit_live_row_source_counts(live_rows)
        if cache_metadata:
            return {
                "rows": live_rows,
                "cache_metadata": cache_metadata,
            }
        return live_rows

    logged_cache_metadata_loader, logged_cache_loader = (
        _geometry_fit_logged_intersection_cache_loaders()
    )
    rebuild_result = gui_geometry_fit.rebuild_geometry_fit_source_rows(
        background_index=int(background_idx),
        background_label=background_label,
        params_local=params_local,
        consumer=lookup_context,
        prior_diagnostics=prior_diagnostics,
        requested_signature=requested_signature,
        requested_signature_summary=requested_signature_summary,
        can_use_live_runtime_cache=can_use_live_runtime_cache,
        build_live_rows=_build_geometry_fit_live_rows_payload_from_cache,
        projection_view_mode=projection_view_mode,
        projection_view_signature=projection_view_signature,
        projection_payload=projection_payload,
        get_memory_intersection_cache=get_last_intersection_cache,
        memory_cache_signature=simulation_runtime_state.last_simulation_signature,
        load_logged_intersection_cache_metadata=logged_cache_metadata_loader,
        load_logged_intersection_cache=logged_cache_loader,
        logged_cache_matches_params=_geometry_manual_logged_cache_matches_params,
        build_source_rows_from_hit_tables=_build_source_rows_for_rebuild,
        simulate_hit_tables=(
            lambda normalized_params, **kwargs: _simulate_hit_tables_for_fit(
                miller,
                intensities,
                int(image_size),
                normalized_params,
                **kwargs,
            )
        ),
        last_runtime_simulation_diagnostics=(_geometry_manual_last_simulation_diagnostics),
        project_rows=(
            lambda rows: _geometry_manual_project_peaks_for_background(
                int(background_idx),
                rows,
                mode_override=projection_view_mode,
                strict_caked_projection=not manual_pick_cache_lookup,
            )
        ),
        project_rows_for_background_view=(
            lambda rows: _geometry_manual_project_peaks_for_background(
                int(background_idx),
                rows,
                mode_override=projection_view_mode,
                caked_payload=projection_payload,
                strict_caked_projection=not manual_pick_cache_lookup,
            )
        ),
        required_pairs=required_pairs,
        required_branch_group_keys=required_branch_group_keys,
        required_manual_fit_targets=required_manual_fit_targets,
        preflight_mode=preflight_mode,
        live_cache_inventory=live_cache_inventory,
        get_targeted_projected_cache=(
            lambda key_digest: _geometry_fit_load_targeted_projected_cache_entry(
                background_index=int(background_idx),
                key_digest=str(key_digest),
            )
        ),
        store_targeted_projected_cache=(
            lambda key_digest, payload: _geometry_fit_store_targeted_projected_cache_entry(
                background_index=int(background_idx),
                key_digest=str(key_digest),
                payload=payload,
            )
        ),
    )
    return _commit_geometry_manual_source_row_rebuild_result(
        rebuild_result,
        consumer=lookup_context,
    )


def _geometry_manual_source_rows_for_background(
    background_index: int,
    param_set: dict[str, object] | None = None,
    *,
    consumer: str | None = None,
    required_pairs: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    background_idx = int(background_index)
    lookup_context = str(consumer or "unspecified")
    # Import/manual-overlay refreshes should reuse restored peak records and
    # avoid forcing a rebuild until geometry-fit preflight or the current
    # detector manual-pick cache explicitly needs source rows.
    try:
        current_background_idx = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_idx = int(background_idx)
    q_group_state = globals().get("geometry_q_group_state")
    restored_q_group_rows_available = bool(
        getattr(q_group_state, "restored_q_group_rows_pending_live_refresh", False)
        and getattr(q_group_state, "cached_entries", None)
    )
    has_manual_pick_rebuild_artifacts = bool(
        getattr(simulation_runtime_state, "stored_max_positions_local", None) is not None
        or getattr(simulation_runtime_state, "stored_intersection_cache", None) is not None
        or bool(getattr(simulation_runtime_state, "peak_records", None))
        or restored_q_group_rows_available
    )
    manual_pick_cache_lookup = _geometry_manual_consumer_is_manual_pick_cache(lookup_context)
    allow_manual_pick_rebuild = bool(
        manual_pick_cache_lookup
        and int(background_idx) == int(current_background_idx)
        and has_manual_pick_rebuild_artifacts
    )
    allow_source_snapshot_rebuild = bool(
        lookup_context == "geometry_fit_dataset" or allow_manual_pick_rebuild
    )
    requested_signature = _geometry_source_snapshot_signature_for_background(
        background_idx,
        param_set,
    )
    requested_signature_summary = _live_cache_signature_summary(requested_signature)
    normalized_requested_signature = gui_geometry_fit._geometry_fit_cache_jsonable(
        requested_signature
    )
    normalized_requested_signature_summary = gui_geometry_fit._geometry_fit_cache_jsonable(
        requested_signature_summary
    )
    required_manual_fit_targets = (
        gui_geometry_fit.collect_geometry_fit_required_manual_fit_targets(
            required_pairs,
            background_index=int(background_idx),
        )
        if required_pairs
        else []
    )
    required_branch_group_keys = gui_geometry_fit._geometry_fit_required_branch_group_keys(
        required_manual_fit_targets
    )
    preflight_mode = "manual_geometry_targeted" if required_branch_group_keys else "full"
    targeted_preflight_enabled = preflight_mode == "manual_geometry_targeted"
    projection_mode_override = _geometry_manual_projection_mode_override_for_consumer(
        lookup_context,
        background_index=background_idx,
    )
    projection_view_signature = _normalize_geometry_fit_projection_view_signature(
        _geometry_fit_targeted_projection_view_signature(
            background_idx,
            mode_override=projection_mode_override,
        ),
        background_idx,
    )
    projection_view_mode = str(projection_view_signature.get("mode") or "detector")
    if (
        manual_pick_cache_lookup
        and projection_view_mode != "detector"
        and not bool(projection_view_signature.get("available", True))
    ):
        projection_view_signature = _normalize_geometry_fit_projection_view_signature(
            _geometry_fit_targeted_projection_view_signature(
                background_idx,
                mode_override="detector",
            ),
            background_idx,
        )
        projection_view_mode = str(projection_view_signature.get("mode") or "detector")
    required_branch_group_keys_digest = (
        gui_geometry_fit._geometry_fit_required_branch_group_keys_digest(
            required_branch_group_keys,
            background_index=int(background_idx),
            requested_signature=normalized_requested_signature,
            requested_signature_summary=normalized_requested_signature_summary,
            preflight_mode=preflight_mode,
            consumer=lookup_context,
            projection_view_mode=projection_view_mode,
            projection_view_signature=projection_view_signature,
        )
    )
    manual_target_scoring_digest = gui_geometry_fit._geometry_fit_manual_target_scoring_digest(
        required_manual_fit_targets
    )
    projection_view_signature_digest = gui_geometry_fit._geometry_fit_digest_payload(
        projection_view_signature
    )
    projection_diagnostics = {
        "projection_view_mode": str(projection_view_mode),
        "projection_view_signature": copy.deepcopy(dict(projection_view_signature)),
        "projection_view_signature_digest": str(projection_view_signature_digest),
        "projection_view_signature_available": bool(
            projection_view_signature.get("available", True)
        ),
    }
    if projection_view_signature.get("reason") is not None:
        projection_diagnostics["reason"] = str(projection_view_signature.get("reason"))

    dataset_debug = {
        "background_index": int(background_idx),
        "consumer": lookup_context,
        "requested_signature_digest": gui_geometry_fit._geometry_fit_digest_payload(
            normalized_requested_signature
        ),
        "projection_view_signature_digest": str(projection_view_signature_digest),
        "snapshot_present": False,
        "snapshot_status": "not_checked",
        "snapshot_row_count": 0,
        "snapshot_projected_row_count": 0,
        "snapshot_valid_for_picker": False,
        "snapshot_valid_for_geometry_fit_dataset": False,
        "required_pair_count": int(len(required_manual_fit_targets)),
        "rows_before_required_filter": 0,
        "rows_after_required_filter": 0,
        "missing_required_pairs": [],
        "rebuild_attempted": False,
        "rebuild_returned_row_count": 0,
        "final_returned_row_count": 0,
        "manual_pick_rebuild_allowed": bool(allow_manual_pick_rebuild),
        "manual_pick_rebuild_artifacts_available": bool(has_manual_pick_rebuild_artifacts),
        "restored_q_group_rows_available": bool(restored_q_group_rows_available),
    }

    def _print_geometry_fit_dataset_source_snapshot_diagnostics() -> None:
        if lookup_context != "geometry_fit_dataset":
            return
        parts = []
        for key, value in dataset_debug.items():
            if isinstance(value, bool):
                rendered = "yes" if value else "no"
            else:
                rendered = repr(value) if isinstance(value, (list, tuple, dict)) else str(value)
            parts.append(f"{key}={rendered}")
        try:
            print("geometry_fit_dataset_source_snapshot " + " ".join(parts))
        except Exception:
            pass

    def _finish_source_rows(
        rows: Sequence[Mapping[str, object]] | None,
        *,
        status: str | None = None,
    ) -> list[dict[str, object]]:
        returned = [dict(entry) for entry in (rows or ()) if isinstance(entry, Mapping)]
        if status is not None:
            dataset_debug["snapshot_status"] = str(status)
        dataset_debug["final_returned_row_count"] = int(len(returned))
        if status is not None:
            diagnostics = dict(_geometry_manual_last_source_snapshot_diagnostics())
            diagnostics.update(
                {
                    "status": str(status),
                    "source_snapshot_status": str(status),
                    "rebuild_attempted": bool(dataset_debug["rebuild_attempted"]),
                    "source_snapshot_rebuild_attempted": bool(dataset_debug["rebuild_attempted"]),
                    "rebuild_returned_row_count": int(dataset_debug["rebuild_returned_row_count"]),
                    "source_snapshot_rebuild_returned_row_count": int(
                        dataset_debug["rebuild_returned_row_count"]
                    ),
                    "final_returned_row_count": int(len(returned)),
                    "manual_pick_rebuild_allowed": bool(
                        dataset_debug["manual_pick_rebuild_allowed"]
                    ),
                    "manual_pick_rebuild_artifacts_available": bool(
                        dataset_debug["manual_pick_rebuild_artifacts_available"]
                    ),
                    "restored_q_group_rows_available": bool(
                        dataset_debug["restored_q_group_rows_available"]
                    ),
                }
            )
            _set_geometry_manual_source_snapshot_diagnostics(**diagnostics)
        _print_geometry_fit_dataset_source_snapshot_diagnostics()
        return returned

    def _targeted_lookup_flags(
        *,
        total_source_rows_available: int,
        source_rows_considered_for_rebinding: int,
        source_rows_projected_for_rebinding: int,
        candidate_rows_after_hkl_filter: int,
        candidate_rows_after_branch_filter: int,
        candidate_rows_scored_for_background_distance: int,
        unrelated_projected_row_count_for_rebinding: int,
        unrelated_scored_row_count_for_rebinding: int,
        targeted_cache_hit: bool,
        cache_source: str,
        targeted_simulation_supported: bool = False,
        targeted_simulation_used: bool = False,
        targeted_simulation_fallback_reason: str | None = None,
        total_hit_tables_available: int = 0,
        hit_tables_considered_for_rebinding: int = 0,
        hit_tables_expanded_for_rebinding: int = 0,
        full_source_rows_built_for_rebinding: bool = False,
        full_source_rows_projected_for_rebinding: bool = False,
        full_fresh_simulation_fallback_used: bool = False,
    ) -> dict[str, object]:
        payload = {
            "preflight_mode": str(preflight_mode),
            "targeted_preflight_enabled": bool(targeted_preflight_enabled),
            "targeted_simulation_supported": bool(targeted_simulation_supported),
            "targeted_simulation_used": bool(targeted_simulation_used),
            "targeted_simulation_fallback_reason": (
                str(targeted_simulation_fallback_reason)
                if targeted_simulation_fallback_reason is not None
                else None
            ),
            "targeted_cache_hit": bool(targeted_cache_hit),
            "cache_source": str(cache_source),
            "required_manual_pair_count": int(len(required_manual_fit_targets)),
            "required_hkl_branch_group_count": int(len(required_branch_group_keys)),
            "required_hkl_branch_keys_digest": str(required_branch_group_keys_digest),
            "manual_target_scoring_digest": str(manual_target_scoring_digest),
            "total_hit_tables_available": int(total_hit_tables_available),
            "hit_tables_considered_for_rebinding": int(hit_tables_considered_for_rebinding),
            "hit_tables_expanded_for_rebinding": int(hit_tables_expanded_for_rebinding),
            "total_source_rows_available": int(total_source_rows_available),
            "source_rows_considered_for_rebinding": int(source_rows_considered_for_rebinding),
            "source_rows_projected_for_rebinding": int(source_rows_projected_for_rebinding),
            "candidate_rows_after_hkl_filter": int(candidate_rows_after_hkl_filter),
            "candidate_rows_after_branch_filter": int(candidate_rows_after_branch_filter),
            "candidate_rows_scored_for_background_distance": int(
                candidate_rows_scored_for_background_distance
            ),
            "unrelated_projected_row_count_for_rebinding": int(
                unrelated_projected_row_count_for_rebinding
            ),
            "unrelated_scored_row_count_for_rebinding": int(
                unrelated_scored_row_count_for_rebinding
            ),
            "full_source_rows_built_for_rebinding": bool(full_source_rows_built_for_rebinding),
            "full_source_rows_projected_for_rebinding": bool(
                full_source_rows_projected_for_rebinding
            ),
            "full_fresh_simulation_fallback_used": bool(full_fresh_simulation_fallback_used),
            "required_manual_fit_targets": copy.deepcopy(required_manual_fit_targets),
        }
        payload["targeted_performance_gate"] = (
            gui_geometry_fit._geometry_fit_targeted_performance_gate_payload(payload)
        )
        return payload

    def _store_targeted_projected_cache(
        *,
        stored_rows: Sequence[Mapping[str, object]] | None,
        projected_rows: Sequence[Mapping[str, object]] | None,
        cache_source: str,
        diagnostics: Mapping[str, object] | None = None,
    ) -> None:
        if not targeted_preflight_enabled:
            return
        normalized_stored_rows = [
            dict(entry)
            for entry in _geometry_fit_rows_for_background(
                int(background_idx),
                stored_rows,
            )
        ]
        normalized_projected_rows = [
            dict(entry)
            for entry in _geometry_fit_rows_for_background(
                int(background_idx),
                projected_rows,
            )
        ]
        if not gui_geometry_fit._geometry_fit_projected_rows_cacheable(
            background_index=int(background_idx),
            projected_rows=normalized_projected_rows,
            projection_view_signature=projection_view_signature,
            requested_projection_view_signature=projection_view_signature,
            consumer=lookup_context,
        ):
            return
        try:
            _geometry_fit_store_targeted_projected_cache_entry(
                background_index=int(background_idx),
                key_digest=str(required_branch_group_keys_digest),
                payload={
                    "background_index": int(background_idx),
                    "requested_signature": normalized_requested_signature,
                    "requested_signature_summary": (normalized_requested_signature_summary),
                    "required_branch_group_keys_digest": str(required_branch_group_keys_digest),
                    "manual_target_scoring_digest": str(manual_target_scoring_digest),
                    "preflight_mode": str(preflight_mode),
                    "consumer": str(lookup_context),
                    "projection_view_mode": str(projection_view_mode),
                    "projection_view_signature": gui_geometry_fit._geometry_fit_cache_jsonable(
                        projection_view_signature
                    ),
                    "stored_rows": normalized_stored_rows,
                    "projected_rows": normalized_projected_rows,
                    "cache_source": str(cache_source),
                    "diagnostics": copy.deepcopy(dict(diagnostics or {})),
                },
            )
        except Exception:
            pass

    if lookup_context == "manual_pick_cache_coverage" and allow_manual_pick_rebuild:
        dataset_debug["rebuild_attempted"] = True
        rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
            background_idx,
            param_set,
            consumer=lookup_context,
            prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
            required_pairs=required_pairs,
        )
        dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
        if rebuilt_rows:
            return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt_coverage")

    if targeted_preflight_enabled:
        targeted_cache_payload = _geometry_fit_load_targeted_projected_cache_entry(
            background_index=int(background_idx),
            key_digest=str(required_branch_group_keys_digest),
        )
        if isinstance(targeted_cache_payload, Mapping):
            requested_signature_matches = (
                targeted_cache_payload.get("requested_signature") == normalized_requested_signature
            )
            projection_signature_matches = (
                gui_geometry_fit._geometry_fit_stable_projection_view_signature(
                    targeted_cache_payload.get("projection_view_signature")
                )
                == gui_geometry_fit._geometry_fit_stable_projection_view_signature(
                    projection_view_signature
                )
            )
            targeted_rows = [
                dict(entry)
                for entry in _geometry_fit_rows_for_background(
                    int(background_idx),
                    targeted_cache_payload.get("projected_rows"),
                )
            ]
            dataset_debug["snapshot_present"] = True
            dataset_debug["snapshot_status"] = "targeted_projected_cache_lookup"
            dataset_debug["snapshot_projected_row_count"] = int(len(targeted_rows))
            dataset_debug["rows_before_required_filter"] = int(len(targeted_rows))
            dataset_debug["rows_after_required_filter"] = int(len(targeted_rows))
            if (
                requested_signature_matches
                and projection_signature_matches
                and gui_geometry_fit._geometry_fit_projected_rows_cacheable(
                    background_index=int(background_idx),
                    projected_rows=targeted_rows,
                    projection_view_signature=targeted_cache_payload.get(
                        "projection_view_signature"
                    ),
                    requested_projection_view_signature=projection_view_signature,
                    consumer=str(targeted_cache_payload.get("consumer") or ""),
                )
            ):
                live_cache_inventory = _live_cache_inventory_snapshot()
                targeted_flags = _targeted_lookup_flags(
                    total_source_rows_available=int(len(targeted_rows)),
                    source_rows_considered_for_rebinding=int(len(targeted_rows)),
                    source_rows_projected_for_rebinding=0,
                    candidate_rows_after_hkl_filter=int(len(targeted_rows)),
                    candidate_rows_after_branch_filter=int(len(targeted_rows)),
                    candidate_rows_scored_for_background_distance=int(len(targeted_rows)),
                    unrelated_projected_row_count_for_rebinding=0,
                    unrelated_scored_row_count_for_rebinding=0,
                    targeted_cache_hit=True,
                    cache_source="targeted_projected_cache",
                )
                _set_geometry_manual_source_snapshot_diagnostics(
                    source="source_snapshot",
                    cache_family="source_snapshot",
                    action="lookup",
                    consumer=lookup_context,
                    status="snapshot_hit",
                    background_index=int(background_idx),
                    requested_signature=requested_signature,
                    requested_signature_summary=requested_signature_summary,
                    snapshot_signature=requested_signature,
                    stored_signature_summary=requested_signature_summary,
                    raw_peak_count=int(len(targeted_rows)),
                    projected_peak_count=int(len(targeted_rows)),
                    created_from=str(
                        targeted_cache_payload.get("cache_source") or "targeted_projected_cache"
                    ),
                    signature_match=True,
                    live_cache_inventory=live_cache_inventory,
                    **projection_diagnostics,
                    **targeted_flags,
                )
                _trace_live_cache_event(
                    "source_snapshot",
                    "lookup",
                    background_index=int(background_idx),
                    outcome="hit",
                    consumer=lookup_context,
                    status="snapshot_hit",
                    requested_signature_summary=requested_signature_summary,
                    stored_signature_summary=requested_signature_summary,
                    created_from=str(
                        targeted_cache_payload.get("cache_source") or "targeted_projected_cache"
                    ),
                    raw_peak_count=int(len(targeted_rows)),
                    projected_peak_count=int(len(targeted_rows)),
                    signature_match=True,
                )
                return _finish_source_rows(targeted_rows, status="snapshot_hit")
    snapshot = dict(simulation_runtime_state.source_row_snapshots.get(background_idx) or {})
    if not snapshot:
        dataset_debug["snapshot_present"] = False
        dataset_debug["snapshot_status"] = "snapshot_missing_background"
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status="snapshot_missing_background",
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            raw_peak_count=0,
            projected_peak_count=0,
            signature_match=False,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        _trace_live_cache_event(
            "source_snapshot",
            "lookup",
            background_index=int(background_idx),
            outcome="miss",
            consumer=lookup_context,
            status="snapshot_missing_background",
            requested_signature_summary=requested_signature_summary,
            raw_peak_count=0,
            projected_peak_count=0,
            signature_match=False,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status="snapshot_missing_background")
    snapshot_signature = snapshot.get("simulation_signature")
    stored_signature_summary = _live_cache_signature_summary(snapshot_signature)
    created_from = snapshot.get("created_from")
    current_row_content_signature = gui_geometry_q_group_manager._geometry_q_group_signature_value(
        getattr(simulation_runtime_state, "stored_q_group_content_signature", None)
    )
    snapshot_row_content_signature = gui_geometry_q_group_manager._geometry_q_group_signature_value(
        snapshot.get("row_content_signature")
    )
    snapshot_valid_for_picker = bool(snapshot.get("valid_for_picker", False))
    snapshot_valid_for_geometry_fit_dataset = bool(
        snapshot.get("valid_for_geometry_fit_dataset", False)
    )
    snapshot_projected_rows = [
        dict(entry)
        for entry in _geometry_fit_rows_for_background(
            int(background_idx),
            snapshot.get("projected_rows", ()),
        )
    ]
    raw_rows = [
        dict(entry)
        for entry in _geometry_fit_rows_for_background(
            int(background_idx),
            snapshot.get("stored_rows", snapshot.get("rows", ())),
        )
    ]
    if not raw_rows and snapshot_projected_rows:
        raw_rows = [dict(entry) for entry in snapshot_projected_rows]
    dataset_debug["snapshot_present"] = True
    dataset_debug["snapshot_status"] = "snapshot_loaded"
    dataset_debug["snapshot_row_count"] = int(len(raw_rows))
    dataset_debug["snapshot_projected_row_count"] = int(len(snapshot_projected_rows))
    dataset_debug["snapshot_valid_for_picker"] = bool(snapshot_valid_for_picker)
    dataset_debug["snapshot_valid_for_geometry_fit_dataset"] = bool(
        snapshot_valid_for_geometry_fit_dataset
    )
    try:
        snapshot_background_idx = int(snapshot.get("background_index", background_idx))
    except Exception:
        snapshot_background_idx = int(background_idx)
    if int(snapshot_background_idx) != int(background_idx):
        status = "snapshot_hit_wrong_background"
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=int(len(snapshot_projected_rows)),
            created_from=created_from,
            signature_match=False,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    if snapshot_signature != requested_signature:
        dataset_debug["snapshot_status"] = "snapshot_hit_signature_mismatch"
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status="snapshot_hit_signature_mismatch",
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=0,
            created_from=created_from,
            signature_match=False,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        _trace_live_cache_event(
            "source_snapshot",
            "lookup",
            background_index=int(background_idx),
            outcome="mismatch",
            consumer=lookup_context,
            status="snapshot_hit_signature_mismatch",
            requested_signature_summary=requested_signature_summary,
            stored_signature_summary=stored_signature_summary,
            created_from=created_from,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=0,
            signature_match=False,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status="snapshot_hit_signature_mismatch")
    if snapshot_row_content_signature != current_row_content_signature:
        status = "snapshot_hit_signature_mismatch"
        dataset_debug["snapshot_status"] = status
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=int(len(snapshot_projected_rows)),
            created_from=created_from,
            signature_match=False,
            row_content_signature_match=False,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    if not snapshot_valid_for_picker and not (
        lookup_context == "geometry_fit_dataset" and snapshot_valid_for_geometry_fit_dataset
    ):
        status = "snapshot_hit_empty_rows"
        dataset_debug["snapshot_status"] = status
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=int(len(snapshot_projected_rows)),
            created_from=created_from,
            signature_match=True,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    if not raw_rows:
        status = "snapshot_hit_empty_rows"
        dataset_debug["snapshot_status"] = status
        live_cache_inventory = _live_cache_inventory_snapshot()
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=0,
            projected_peak_count=0,
            created_from=created_from,
            signature_match=True,
            live_cache_inventory=live_cache_inventory,
            **projection_diagnostics,
        )
        _trace_live_cache_event(
            "source_snapshot",
            "lookup",
            background_index=int(background_idx),
            outcome="empty",
            consumer=lookup_context,
            status=status,
            requested_signature_summary=requested_signature_summary,
            stored_signature_summary=stored_signature_summary,
            created_from=created_from,
            raw_peak_count=0,
            projected_peak_count=0,
            signature_match=True,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    filtered_rows = [dict(entry) for entry in raw_rows]
    filter_diagnostics = {
        "total_count": int(len(filtered_rows)),
        "after_hkl_filter_count": int(len(filtered_rows)),
        "after_branch_filter_count": int(len(filtered_rows)),
        "unrelated_count": 0,
    }
    if targeted_preflight_enabled:
        (
            filtered_rows,
            filter_diagnostics,
            _matched_required_keys,
        ) = gui_geometry_fit._geometry_fit_filter_entries_for_required_branch_groups(
            raw_rows,
            required_branch_group_keys,
        )
    dataset_debug["rows_before_required_filter"] = int(len(raw_rows))
    dataset_debug["rows_after_required_filter"] = int(len(filtered_rows))
    snapshot_validation = (
        gui_geometry_fit.validate_geometry_fit_live_source_rows(
            filtered_rows,
            required_pairs=required_pairs,
        )
        if required_pairs
        else {}
    )
    if required_pairs and not bool(snapshot_validation.get("valid", False)):
        pair_failures = [
            dict(entry)
            for entry in (snapshot_validation.get("pair_failures", ()) or ())
            if isinstance(entry, Mapping)
        ]
        dataset_debug["missing_required_pairs"] = [
            str(entry.get("pair_id") or entry.get("overlay_match_index") or "")
            for entry in pair_failures
        ]
        status = (
            "snapshot_hit_required_pairs_filtered_out"
            if targeted_preflight_enabled and raw_rows and not filtered_rows
            else "snapshot_hit_missing_required_pairs"
        )
        dataset_debug["snapshot_status"] = status
        live_cache_inventory = _live_cache_inventory_snapshot()
        targeted_flags = (
            _targeted_lookup_flags(
                total_source_rows_available=int(len(raw_rows)),
                source_rows_considered_for_rebinding=int(len(filtered_rows)),
                source_rows_projected_for_rebinding=0,
                candidate_rows_after_hkl_filter=int(
                    filter_diagnostics.get("after_hkl_filter_count", len(filtered_rows))
                ),
                candidate_rows_after_branch_filter=int(
                    filter_diagnostics.get(
                        "after_branch_filter_count",
                        len(filtered_rows),
                    )
                ),
                candidate_rows_scored_for_background_distance=int(len(filtered_rows)),
                unrelated_projected_row_count_for_rebinding=0,
                unrelated_scored_row_count_for_rebinding=int(
                    filter_diagnostics.get("unrelated_count", 0)
                ),
                targeted_cache_hit=True,
                cache_source="source_snapshot",
            )
            if targeted_preflight_enabled
            else {}
        )
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=0,
            created_from=created_from,
            signature_match=True,
            live_cache_inventory=live_cache_inventory,
            live_runtime_cache_validation=snapshot_validation,
            missing_required_pairs=list(dataset_debug["missing_required_pairs"]),
            snapshot_filter_reason=status,
            **projection_diagnostics,
            **targeted_flags,
        )
        _trace_live_cache_event(
            "source_snapshot",
            "lookup",
            background_index=int(background_idx),
            outcome="validation_failed",
            consumer=lookup_context,
            status=status,
            requested_signature_summary=requested_signature_summary,
            stored_signature_summary=stored_signature_summary,
            created_from=created_from,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=0,
            signature_match=True,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    snapshot_projection_signature = snapshot.get("projection_view_signature")
    snapshot_projection_signature_matches = (
        gui_geometry_fit._geometry_fit_stable_projection_view_signature(
            snapshot_projection_signature
        )
        == gui_geometry_fit._geometry_fit_stable_projection_view_signature(
            projection_view_signature
        )
        if isinstance(snapshot_projection_signature, Mapping)
        else projection_view_mode == "detector"
    )
    projected_projection_count = 0
    rows_to_project = filtered_rows if targeted_preflight_enabled else raw_rows
    if (
        lookup_context == "geometry_fit_dataset"
        and snapshot_valid_for_geometry_fit_dataset
        and snapshot_projected_rows
        and snapshot_projection_signature_matches
    ):
        projected_rows = [dict(entry) for entry in snapshot_projected_rows]
        if targeted_preflight_enabled:
            projected_rows, projected_filter_diagnostics, _matched_projected_keys = (
                gui_geometry_fit._geometry_fit_filter_entries_for_required_branch_groups(
                    projected_rows,
                    required_branch_group_keys,
                )
            )
            if not projected_rows and snapshot_projected_rows:
                filter_diagnostics = projected_filter_diagnostics
        projected_projection_count = 0
    else:
        projected_rows = _geometry_manual_project_peaks_for_background(
            int(background_idx),
            rows_to_project,
            mode_override=projection_view_mode,
            strict_caked_projection=not manual_pick_cache_lookup,
        )
        projected_projection_count = int(len(rows_to_project))
        projected_rows = _geometry_fit_rows_for_background(
            int(background_idx),
            projected_rows,
        )
    if not projected_rows:
        status = "snapshot_hit_empty_rows"
        if not bool(projection_view_signature.get("available", True)):
            status = "snapshot_hit_projection_unavailable"
        elif (
            isinstance(snapshot_projection_signature, Mapping)
            and not snapshot_projection_signature_matches
        ):
            status = "snapshot_hit_signature_mismatch"
        elif targeted_preflight_enabled and rows_to_project and not projected_rows:
            status = "snapshot_hit_required_pairs_filtered_out"
        dataset_debug["snapshot_status"] = status
        live_cache_inventory = _live_cache_inventory_snapshot()
        targeted_flags = (
            _targeted_lookup_flags(
                total_source_rows_available=int(len(raw_rows)),
                source_rows_considered_for_rebinding=int(len(filtered_rows)),
                source_rows_projected_for_rebinding=int(projected_projection_count),
                candidate_rows_after_hkl_filter=int(
                    filter_diagnostics.get("after_hkl_filter_count", len(filtered_rows))
                ),
                candidate_rows_after_branch_filter=int(
                    filter_diagnostics.get("after_branch_filter_count", len(filtered_rows))
                ),
                candidate_rows_scored_for_background_distance=0,
                unrelated_projected_row_count_for_rebinding=0,
                unrelated_scored_row_count_for_rebinding=int(
                    filter_diagnostics.get("unrelated_count", 0)
                ),
                targeted_cache_hit=bool(targeted_preflight_enabled),
                cache_source="source_snapshot",
            )
            if targeted_preflight_enabled
            else {}
        )
        _set_geometry_manual_source_snapshot_diagnostics(
            source="source_snapshot",
            cache_family="source_snapshot",
            action="lookup",
            consumer=lookup_context,
            status=status,
            background_index=int(background_idx),
            requested_signature=requested_signature,
            requested_signature_summary=requested_signature_summary,
            snapshot_signature=snapshot_signature,
            stored_signature_summary=stored_signature_summary,
            raw_peak_count=int(len(raw_rows)),
            projected_peak_count=0,
            created_from=created_from,
            signature_match=bool(snapshot_projection_signature_matches),
            live_cache_inventory=live_cache_inventory,
            live_runtime_cache_validation=snapshot_validation,
            snapshot_filter_reason=status,
            **projection_diagnostics,
            **targeted_flags,
        )
        if allow_source_snapshot_rebuild:
            dataset_debug["rebuild_attempted"] = True
            rebuilt_rows = _geometry_manual_rebuild_source_rows_for_background(
                background_idx,
                param_set,
                consumer=lookup_context,
                prior_diagnostics=_geometry_manual_last_source_snapshot_diagnostics(),
                required_pairs=required_pairs,
            )
            dataset_debug["rebuild_returned_row_count"] = int(len(rebuilt_rows or ()))
            if rebuilt_rows:
                return _finish_source_rows(rebuilt_rows, status="snapshot_rebuilt")
        return _finish_source_rows([], status=status)
    live_cache_inventory = _live_cache_inventory_snapshot()
    targeted_flags = (
        _targeted_lookup_flags(
            total_source_rows_available=int(len(raw_rows)),
            source_rows_considered_for_rebinding=int(len(filtered_rows)),
            source_rows_projected_for_rebinding=int(projected_projection_count),
            candidate_rows_after_hkl_filter=int(
                filter_diagnostics.get("after_hkl_filter_count", len(filtered_rows))
            ),
            candidate_rows_after_branch_filter=int(
                filter_diagnostics.get("after_branch_filter_count", len(filtered_rows))
            ),
            candidate_rows_scored_for_background_distance=int(len(projected_rows)),
            unrelated_projected_row_count_for_rebinding=0,
            unrelated_scored_row_count_for_rebinding=0,
            targeted_cache_hit=bool(targeted_preflight_enabled),
            cache_source="source_snapshot",
        )
        if targeted_preflight_enabled
        else {}
    )
    if targeted_preflight_enabled:
        _store_targeted_projected_cache(
            stored_rows=filtered_rows,
            projected_rows=projected_rows,
            cache_source="source_snapshot",
            diagnostics=targeted_flags,
        )
    dataset_debug["snapshot_status"] = "snapshot_hit"
    dataset_debug["snapshot_projected_row_count"] = int(len(projected_rows))
    _set_geometry_manual_source_snapshot_diagnostics(
        source="source_snapshot",
        cache_family="source_snapshot",
        action="lookup",
        consumer=lookup_context,
        status="snapshot_hit",
        background_index=int(background_idx),
        requested_signature=requested_signature,
        requested_signature_summary=requested_signature_summary,
        snapshot_signature=snapshot_signature,
        stored_signature_summary=stored_signature_summary,
        raw_peak_count=int(len(raw_rows)),
        projected_peak_count=int(len(projected_rows)),
        created_from=created_from,
        signature_match=True,
        live_cache_inventory=live_cache_inventory,
        live_runtime_cache_validation=snapshot_validation,
        **projection_diagnostics,
        **targeted_flags,
    )
    _trace_live_cache_event(
        "source_snapshot",
        "lookup",
        background_index=int(background_idx),
        outcome="hit",
        consumer=lookup_context,
        status="snapshot_hit",
        requested_signature_summary=requested_signature_summary,
        stored_signature_summary=stored_signature_summary,
        created_from=created_from,
        raw_peak_count=int(len(raw_rows)),
        projected_peak_count=int(len(projected_rows)),
        signature_match=True,
    )
    return _finish_source_rows(projected_rows, status="snapshot_hit")


