def _clear_widget_children(parent) -> None:
    children_getter = getattr(parent, "winfo_children", None)
    if not callable(children_getter):
        return
    try:
        children = list(children_getter())
    except Exception:
        return
    for child in children:
        try:
            child.destroy()
        except Exception:
            pass


