@dataclass
class RuntimeContext:
    state: object
    simulation_runtime_state: object
    background_runtime_state: object
    app_shell_view_state: object | None = None
    workspace_panels_view_state: object | None = None
    root: object | None = None
    primary_figure: object | None = None
    primary_canvas: object | None = None
    analysis_figure: object | None = None
    analysis_canvas: object | None = None


def build_runtime_state_context() -> RuntimeContext:
    ensure_runtime_state_initialized()
    context = RuntimeContext(
        state=app_state,
        simulation_runtime_state=simulation_runtime_state,
        background_runtime_state=background_runtime_state,
    )
    globals()["app_state"] = context.state
    globals()["simulation_runtime_state"] = context.simulation_runtime_state
    globals()["background_runtime_state"] = context.background_runtime_state
    return context


def build_runtime_window_context(context: RuntimeContext) -> RuntimeContext:
    ensure_runtime_shell_initialized()
    context.root = root
    context.app_shell_view_state = app_shell_view_state
    context.workspace_panels_view_state = workspace_panels_view_state
    globals()["root"] = context.root
    globals()["app_shell_view_state"] = context.app_shell_view_state
    globals()["workspace_panels_view_state"] = context.workspace_panels_view_state
    return context


def build_runtime_plot_context(context: RuntimeContext) -> RuntimeContext:
    ensure_runtime_plot_initialized()
    context.primary_figure = fig
    context.primary_canvas = canvas
    context.analysis_figure = globals().get("fig_1d")
    context.analysis_canvas = globals().get("canvas_1d")
    globals()["fig"] = context.primary_figure
    globals()["canvas"] = context.primary_canvas
    globals()["fig_1d"] = context.analysis_figure
    globals()["canvas_1d"] = context.analysis_canvas
    return context


def build_runtime_controls_context(context: RuntimeContext) -> RuntimeContext:
    ensure_runtime_controls_initialized()
    context.app_shell_view_state = app_shell_view_state
    context.workspace_panels_view_state = workspace_panels_view_state
    context.analysis_figure = globals().get("fig_1d")
    context.analysis_canvas = globals().get("canvas_1d")
    globals()["app_shell_view_state"] = context.app_shell_view_state
    globals()["workspace_panels_view_state"] = context.workspace_panels_view_state
    globals()["fig_1d"] = context.analysis_figure
    globals()["canvas_1d"] = context.analysis_canvas
    return context


_STARTUP_BENCHMARK_ENABLED = str(
    os.environ.get("RA_SIM_STARTUP_BENCHMARK", "")
).strip().lower() in {
    "1",
    "true",
    "yes",
    "on",
}
_STARTUP_BENCHMARK_AUTO_EXIT = str(
    os.environ.get("RA_SIM_STARTUP_BENCHMARK_AUTO_EXIT", "")
).strip().lower() in {"1", "true", "yes", "on"}


def _emit_startup_benchmark_event(event: str, **payload: object) -> None:
    if not _STARTUP_BENCHMARK_ENABLED:
        return
    message = {"event": str(event), **payload}
    print(f"RA_SIM_STARTUP_EVENT {json.dumps(message, sort_keys=True)}", flush=True)


def _saved_state_sequence_count(value: object) -> int | None:
    if isinstance(value, Sequence) and not isinstance(value, str | bytes | bytearray):
        return int(len(value))
    return None


def _saved_state_snapshot_metadata(snapshot: object) -> dict[str, object]:
    metadata: dict[str, object] = {
        "restored_background_count": None,
        "restored_manual_pair_count": None,
        "restored_selection_count": None,
        "restored_has_caked_state": None,
        "restored_has_geometry_manual_pairs": None,
        "metadata_status": "not_detected",
        "missing_phase_reason": "saved_state_snapshot_unavailable",
    }
    if not isinstance(snapshot, Mapping):
        return metadata

    files_state = snapshot.get("files", {})
    geometry_state = snapshot.get("geometry", {})
    missing: list[str] = []
    if isinstance(files_state, Mapping):
        background_count = _saved_state_sequence_count(files_state.get("background_files"))
        metadata["restored_background_count"] = background_count
        if background_count is None:
            missing.append("restored_background_count")
    else:
        missing.append("restored_background_count")

    if isinstance(geometry_state, Mapping):
        manual_pair_count = _saved_state_sequence_count(geometry_state.get("manual_pairs"))
        metadata["restored_manual_pair_count"] = manual_pair_count
        metadata["restored_has_geometry_manual_pairs"] = (
            bool(manual_pair_count) if manual_pair_count is not None else None
        )
        selection_count = _saved_state_sequence_count(geometry_state.get("q_group_rows"))
        metadata["restored_selection_count"] = selection_count
        if manual_pair_count is None:
            missing.append("restored_manual_pair_count")
            missing.append("restored_has_geometry_manual_pairs")
        if selection_count is None:
            missing.append("restored_selection_count")
    else:
        missing.extend(
            [
                "restored_manual_pair_count",
                "restored_has_geometry_manual_pairs",
                "restored_selection_count",
            ]
        )

    if "analysis_range" in snapshot:
        metadata["restored_has_caked_state"] = isinstance(snapshot.get("analysis_range"), Mapping)
    else:
        missing.append("restored_has_caked_state")

    if missing:
        metadata["metadata_status"] = "partial"
        metadata["missing_phase_reason"] = ",".join(sorted(set(missing)))
    else:
        metadata["metadata_status"] = "measured"
        metadata["missing_phase_reason"] = None
    return metadata


def _saved_state_timing_context_fields() -> dict[str, object]:
    fields: dict[str, object] = {}
    try:
        context = getattr(simulation_runtime_state, "timing_saved_state_context", {}) or {}
    except Exception:
        context = {}
    if isinstance(context, Mapping):
        fields.update(dict(context))
    return fields


def _saved_state_timing_event(event: str, **fields: object) -> None:
    if not timing_enabled():
        return
    payload = _saved_state_timing_context_fields()
    payload.update(fields)
    _timing_event(event, phase="startup", **payload)


@contextlib.contextmanager
def _saved_state_timing_span(name: str, **fields: object):
    if not timing_enabled():
        yield
        return
    payload = _saved_state_timing_context_fields()
    payload.update(fields)
    _timing_event(f"{name}.start", phase="startup", **payload)
    try:
        yield
    except Exception as exc:
        _timing_event(
            f"{name}.error",
            phase="startup",
            **payload,
            exc_type=type(exc).__name__,
            error=str(exc),
        )
        raise
    finally:
        _timing_event(f"{name}.end", phase="startup", **payload)


def _timing_apply_startup_state_restore() -> None:
    if not timing_enabled():
        return
    state_path_text = str(os.environ.get("RA_SIM_TIMING_RESTORE_STATE", "")).strip()
    if not state_path_text:
        return
    state_path = Path(state_path_text).expanduser()
    context: dict[str, object] = {
        "state_path_basename": state_path.name,
        "state_file": state_path.name,
    }
    try:
        context["state_file_size_bytes"] = int(state_path.stat().st_size)
    except OSError:
        context["state_file_size_bytes"] = None
    simulation_runtime_state.timing_saved_state_context = dict(context)
    _saved_state_timing_event("saved_state.start")
    _saved_state_timing_event("saved_state.restore.start")
    try:
        previous_startup_updates_suspended = bool(
            getattr(simulation_runtime_state, "startup_updates_suspended", False)
        )
        previous_gui_state_import_active = bool(
            getattr(simulation_runtime_state, "gui_state_import_active", False)
        )
        simulation_runtime_state.startup_updates_suspended = True
        simulation_runtime_state.gui_state_import_active = True
        simulation_runtime_state.timing_saved_state_restore_active = True
        try:
            payload = load_gui_state_file(state_path)
            snapshot = dict(payload.get("state", {}))
            context.update(_saved_state_snapshot_metadata(snapshot))
            simulation_runtime_state.timing_saved_state_context = dict(context)
            _saved_state_timing_event("saved_state.metadata")
            message = _apply_full_gui_state_snapshot(snapshot)
        finally:
            simulation_runtime_state.startup_updates_suspended = previous_startup_updates_suspended
            simulation_runtime_state.gui_state_import_active = previous_gui_state_import_active
            simulation_runtime_state.timing_saved_state_restore_active = False
    except Exception as exc:
        _saved_state_timing_event(
            "saved_state.restore.error",
            exc_type=type(exc).__name__,
            error=str(exc),
        )
        _saved_state_timing_event(
            "saved_state.error",
            exc_type=type(exc).__name__,
            error=str(exc),
        )
        raise
    simulation_runtime_state.timing_saved_state_restore_completed = True
    _saved_state_timing_event(
        "saved_state.restore.end",
        message=message,
    )
    _saved_state_timing_event("saved_state.end", message=message)


def _timing_theta_trace(*_args) -> None:
    if not timing_enabled():
        return
    try:
        new_theta = float(theta_initial_var.get())
    except Exception:
        new_theta = None
    startup_write = bool(getattr(simulation_runtime_state, "startup_updates_suspended", False))
    try:
        old_theta = getattr(simulation_runtime_state, "timing_last_theta_value", None)
        simulation_runtime_state.timing_last_theta_value = new_theta
        if not startup_write:
            simulation_runtime_state.timing_update_reason = "theta_change"
    except Exception:
        old_theta = None
    if startup_write:
        _timing_event(
            "theta_initial.var_write",
            phase="startup",
            old_theta=old_theta,
            new_theta=new_theta,
        )
        return
    _timing_event(
        "theta_change.var_write",
        phase="input",
        update_id=_timing_pending_action_update_id(),
        old_theta=old_theta,
        new_theta=new_theta,
        display_fingerprint_before=_timing_display_fingerprint(),
    )


def _timing_attach_theta_trace() -> None:
    if not timing_enabled():
        return
    trace_add = getattr(theta_initial_var, "trace_add", None)
    if not callable(trace_add):
        return
    try:
        simulation_runtime_state.timing_last_theta_value = float(theta_initial_var.get())
        trace_add("write", _timing_theta_trace)
    except Exception:
        pass


def _timing_automation_enabled() -> bool:
    return timing_enabled() and str(
        os.environ.get("RA_SIM_TIMING_AUTOMATION", "")
    ).strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }


def _timing_automation_repetitions(default: int) -> int:
    raw_value = str(os.environ.get("RA_SIM_TIMING_REPETITIONS", "")).strip()
    if not raw_value:
        return int(default)
    try:
        return max(1, int(raw_value))
    except ValueError:
        return int(default)


def _timing_automation_shutdown(delay_ms: int = 250) -> None:
    after = getattr(globals().get("root"), "after", None)
    if callable(after):
        try:
            after(int(delay_ms), _shutdown_gui)
            return
        except Exception:
            pass
    _shutdown_gui()


def _timing_automation_prepare_actions() -> list[dict[str, object]]:
    scenario = str(os.environ.get("RA_SIM_TIMING_SCENARIO", "")).strip().lower()
    repetitions = _timing_automation_repetitions(30)
    try:
        original_theta = float(theta_initial_var.get())
    except Exception:
        original_theta = 5.0
    actions: list[dict[str, object]] = []
    if scenario in {"theta10", "theta10-restored", "theta10_saved_state"}:
        for rep in range(repetitions):
            actions.append({"kind": "theta", "value": 10.0, "transition": "to_10", "rep": rep + 1})
            actions.append(
                {
                    "kind": "theta",
                    "value": original_theta,
                    "transition": "return",
                    "rep": rep + 1,
                }
            )
    elif scenario in {"redraw-only", "redraw_only"}:
        for rep in range(repetitions):
            actions.append(
                {"kind": "scale", "value": 1.01, "transition": "scale_up", "rep": rep + 1}
            )
            actions.append(
                {"kind": "scale", "value": 1.0, "transition": "scale_back", "rep": rep + 1}
            )
    elif scenario in {"cache-hit", "cache_hit"}:
        actions.append({"kind": "theta", "value": 10.0, "transition": "to_10", "rep": 1})
        actions.append({"kind": "theta", "value": 10.0, "transition": "repeat_10", "rep": 1})
    return actions


def _timing_automation_start() -> None:
    if not _timing_automation_enabled():
        return
    try:
        if bool(getattr(simulation_runtime_state, "timing_automation_started", False)):
            return
        simulation_runtime_state.timing_automation_started = True
        simulation_runtime_state.timing_automation_actions = _timing_automation_prepare_actions()
    except Exception:
        return
    _timing_event(
        "automation.start",
        phase="automation",
        action_count=len(getattr(simulation_runtime_state, "timing_automation_actions", [])),
    )
    if not getattr(simulation_runtime_state, "timing_automation_actions", []):
        _timing_automation_shutdown()
        return
    _timing_automation_step()


def _timing_automation_step() -> None:
    if not _timing_automation_enabled():
        return
    actions = list(getattr(simulation_runtime_state, "timing_automation_actions", []))
    if not actions:
        _timing_event("automation.complete", phase="automation")
        _timing_automation_shutdown()
        return
    action = dict(actions.pop(0))
    simulation_runtime_state.timing_automation_actions = actions
    kind = str(action.get("kind", ""))
    transition = str(action.get("transition", kind))
    rep = int(action.get("rep", 0) or 0)
    if kind == "theta":
        value = float(action["value"])
        update_id = _timing_next_do_update_id()
        simulation_runtime_state.timing_action_update_id = update_id
        simulation_runtime_state.timing_update_reason = "theta_change"
        _timing_event(
            "theta_change.input.start",
            phase="input",
            update_id=update_id,
            new_theta=value,
            transition=transition,
            repetition=rep,
            display_fingerprint_before=_timing_display_fingerprint(),
        )
        theta_initial_var.set(value)
        schedule_update()
        return
    if kind == "scale":
        value = float(action["value"])
        redraw_counter = (
            int(getattr(simulation_runtime_state, "timing_redraw_update_counter", 0)) + 1
        )
        simulation_runtime_state.timing_redraw_update_counter = redraw_counter
        update_id = f"redraw-{redraw_counter}"
        simulation_runtime_state.timing_update_reason = "redraw_only"
        _timing_mark_pending_visible_update(
            update_id=update_id,
            reason="redraw_only",
            cache_hit=True,
        )
        _timing_event(
            "redraw_only.input.start",
            phase="input",
            update_id=update_id,
            scale_factor=value,
            transition=transition,
            repetition=rep,
            display_fingerprint_before=_timing_display_fingerprint(),
        )
        _set_scale_factor_value(value, adjust_range=True, reset_override=False)
        apply_scale_factor_to_existing_results(update_limits=False)
        _timing_event(
            "redraw_only.compute_absent",
            phase="calculation",
            update_id=update_id,
            cache_hit=True,
        )
        return
    _timing_automation_step()


def _timing_automation_after_visible(*, reason: str, update_id: object) -> None:
    if not _timing_automation_enabled():
        return
    if reason == "first_visible":
        _timing_automation_start()
        return
    if not bool(getattr(simulation_runtime_state, "timing_automation_started", False)):
        return
    try:
        actions = getattr(simulation_runtime_state, "timing_automation_actions", [])
    except Exception:
        actions = []
    if actions:
        after = getattr(globals().get("root"), "after", None)
        if callable(after):
            try:
                after(50, _timing_automation_step)
                return
            except Exception:
                pass
        _timing_automation_step()
    else:
        _timing_event("automation.complete", phase="automation", update_id=update_id)
        _timing_automation_shutdown()


def main(write_excel_flag=None, startup_mode="prompt", calibrant_bundle=None):
    """Entry point for running the GUI application.

    Parameters
    ----------
    write_excel_flag : bool or None, optional
        When ``True`` the initial intensities are written to an Excel
        file in the configured downloads directory.  When ``None`` the
        value from the instrument configuration file is used.
    startup_mode : {"prompt", "simulation", "calibrant", "mosaic"}, optional
        Startup behavior. ``prompt`` shows a launcher GUI asking which mode
        to run, ``simulation`` starts this GUI directly, and ``calibrant``
        launches the hBN calibrant fitter. ``mosaic`` launches the installed
        mosaic_sim visualizer.
    calibrant_bundle : str or None, optional
        Optional NPZ bundle path to preload when launching calibrant mode.
    """

    _timing_event("gui.main.start", phase="startup", startup_mode=startup_mode)
    global write_excel
    if write_excel_flag is not None:
        write_excel = write_excel_flag

    if startup_mode not in {"prompt", "simulation", "calibrant", "mosaic"}:
        raise ValueError("startup_mode must be one of: prompt, simulation, calibrant, mosaic")

    resolved_mode = startup_mode
    if resolved_mode == "prompt":
        ensure_runtime_root_initialized()
        resolved_mode = gui_bootstrap.choose_startup_mode_dialog(root)

    if resolved_mode is None:
        _shutdown_gui()
        return

    if resolved_mode == "calibrant":
        if _RUNTIME_ROOT_INITIALIZED:
            _shutdown_gui()
        gui_bootstrap.launch_calibrant_gui(bundle=calibrant_bundle)
        return

    if resolved_mode == "mosaic":
        if _RUNTIME_ROOT_INITIALIZED:
            _shutdown_gui()
        from ra_sim import launcher as package_launcher

        package_launcher.launch_mosaic_visualizer()
        return

    runtime_context = RuntimeContext(
        state=app_state,
        simulation_runtime_state=simulation_runtime_state,
        background_runtime_state=background_runtime_state,
    )
    runtime_context = build_runtime_window_context(runtime_context)
    _ = runtime_context

    gui_views.apply_launch_window_context(root)
    _set_structure_bootstrap_controls_enabled(False)
    progress_label.config(text="Loading startup data...")
    try:
        root.deiconify()
    except tk.TclError:
        pass
    _emit_startup_benchmark_event("window_deiconified")

    def _run_initial_startup_work():
        nonlocal runtime_context

        try:
            _timing_event("background.first_load.start", phase="startup")
            _emit_startup_benchmark_event("after_idle_startup_task")
            runtime_context = build_runtime_state_context()
            runtime_context = build_runtime_window_context(runtime_context)
            runtime_context = build_runtime_plot_context(runtime_context)
            runtime_context = build_runtime_controls_context(runtime_context)
            _ = runtime_context
            _timing_event("background.first_load.end", phase="startup")
            _set_structure_bootstrap_controls_enabled(
                bool(getattr(structure_model_state, "bootstrap_complete", False))
            )
            params_file_path = get_path("parameters_file")
            profile_loaded = False
            if os.path.exists(params_file_path):
                simulation_runtime_state.startup_updates_suspended = True
                simulation_runtime_state.pending_startup_refresh = False
                try:
                    _timing_event("config.load.start", phase="startup")
                    load_parameters(
                        params_file_path,
                        theta_initial_var,
                        cor_angle_var,
                        gamma_var,
                        Gamma_var,
                        chi_var,
                        zs_var,
                        zb_var,
                        sample_width_var,
                        sample_length_var,
                        sample_depth_var,
                        debye_x_var,
                        debye_y_var,
                        corto_detector_var,
                        sigma_mosaic_var,
                        gamma_mosaic_var,
                        eta_var,
                        a_var,
                        c_var,
                        center_x_var,
                        center_y_var,
                        resolution_var,
                        custom_samples_var,
                        rod_points_per_gz_var,
                        bandwidth_percent_var=bandwidth_percent_var,
                        optics_mode_var=optics_mode_var,
                        phase_delta_expr_var=phase_delta_expr_var,
                        phi_l_divisor_var=phi_l_divisor_var,
                        sf_prune_bias_var=sf_prune_bias_var,
                        solve_q_steps_var=solve_q_steps_var,
                        solve_q_rel_tol_var=solve_q_rel_tol_var,
                        solve_q_mode_var=solve_q_mode_var,
                    )
                    _timing_event("config.load.end", phase="startup", source="parameters_file")
                finally:
                    simulation_runtime_state.startup_updates_suspended = False
                if finite_stack_controls_view_state.phase_delta_entry_var is not None:
                    gui_views.set_finite_stack_phase_delta_entry_text(
                        finite_stack_controls_view_state,
                        _current_phase_delta_expression(),
                    )
                if finite_stack_controls_view_state.phi_l_divisor_entry_var is not None:
                    gui_views.set_finite_stack_phi_l_divisor_entry_text(
                        finite_stack_controls_view_state,
                        gui_controllers.format_finite_stack_phi_l_divisor(_current_phi_l_divisor()),
                    )
                _apply_rod_points_per_gz(trigger_update=False)
                ensure_valid_resolution_choice()
                profile_loaded = True
            else:
                _timing_event("config.load.start", phase="startup")
                ensure_valid_resolution_choice()
                _timing_event("config.load.end", phase="startup", source="defaults")

            _timing_apply_startup_state_restore()

            sample_count = int(max(1, simulation_runtime_state.num_samples))
            cif_summary = Path(_current_primary_cif_path()).name
            if structure_model_state.cif_file2:
                cif_summary = f"{cif_summary}, {Path(str(structure_model_state.cif_file2)).name}"
            print(
                "Startup ready: "
                f"profile={'loaded' if profile_loaded else 'defaults'}; "
                f"sampling={sample_count} samples; "
                f"sf_prune={current_sf_prune_bias():+.2f}; "
                f"q_mode={gui_structure_factor_pruning.normalize_runtime_solve_q_mode_label(solve_q_mode_var.get())}; "
                f"q_steps={current_solve_q_values().steps}; "
                f"q_tol={current_solve_q_values().rel_tol:.2e}; "
                f"optics={_normalize_optics_mode_label(optics_mode_var.get())}; "
                f"cif={cif_summary}"
            )

            gui_controllers.clear_tk_after_token(root, simulation_runtime_state.update_pending)
            simulation_runtime_state.update_pending = None
            gui_controllers.clear_tk_after_token(
                root,
                simulation_runtime_state.integration_update_pending,
            )
            simulation_runtime_state.integration_update_pending = None

            post_startup_tasks: list[gui_runtime_startup.StartupTask] = []
            if not structure_model_controls_built:
                post_startup_tasks.append(
                    gui_runtime_startup.StartupTask(
                        "structure controls",
                        _rebuild_structure_model_controls,
                    )
                )
            if write_excel:
                post_startup_tasks.append(
                    gui_runtime_startup.StartupTask(
                        "initial Excel export",
                        export_initial_excel,
                    )
                )

            def _handle_post_startup_error(task_name: str, exc: Exception) -> None:
                progress_label.config(
                    text=f"Startup post-processing failed during {task_name}: {exc}"
                )
                try:
                    import traceback

                    traceback.print_exc()
                except Exception:
                    pass

            post_startup_task_runner = gui_runtime_startup.build_runtime_startup_task_runner(
                root=root,
                tasks=post_startup_tasks,
                on_error=_handle_post_startup_error,
                initial_delay_ms=200,
                inter_task_delay_ms=75,
            )
            progress_label.config(text="Initializing structure model...")
            _bootstrap_structure_model_state_for_startup()
            _set_structure_bootstrap_controls_enabled(True)
            progress_label.config(text="Initializing simulation...")
            _show_initial_simulation_loading_overlay()
            _timing_event("first_update.requested", phase="startup")
            matplotlib_canvas.draw()
            root.update_idletasks()
            do_update()
        except Exception as exc:
            progress_label.config(text=f"Startup initialization failed: {exc}")
            try:
                import traceback

                traceback.print_exc()
            except Exception:
                pass
        else:
            if (
                simulation_runtime_state.worker_active_job is not None
                and simulation_runtime_state.stored_sim_image is None
            ):
                progress_label.config(text="Simulation loading in background...")
            elif (
                simulation_runtime_state.preview_active
                and simulation_runtime_state.worker_active_job is not None
            ):
                progress_label.config(text="Preview ready, refining full simulation...")
            elif simulation_runtime_state.analysis_active_job is not None:
                progress_label.config(text=_analysis_progress_text())
            else:
                progress_label.config(text="Simulation ready.")
            _emit_startup_benchmark_event(
                "ready_status",
                text=str(progress_label.cget("text")),
            )
            if post_startup_task_runner.has_tasks():
                post_startup_task_runner.schedule()
            if _STARTUP_BENCHMARK_AUTO_EXIT:
                root.after(750 if post_startup_task_runner.has_tasks() else 150, _shutdown_gui)

    # Let Tk paint the windows first, then run the expensive initial update.
    root.after_idle(_run_initial_startup_work)
    root.mainloop()
    _timing_event("gui.main.end", phase="startup", startup_mode=startup_mode)


if __name__ == "__main__":
    cli_argv = list(sys.argv[1:])
    early_mode = os.environ.get("RA_SIM_EARLY_STARTUP_MODE")
    args = gui_bootstrap.parse_launch_args(cli_argv)

    try:
        override_flag = False if args.no_excel else None
        mode = gui_bootstrap.resolve_startup_mode(
            args.command,
            early_mode=early_mode,
        )
        main(
            write_excel_flag=override_flag,
            startup_mode=mode,
            calibrant_bundle=args.bundle,
        )
    except Exception as exc:
        print("Unhandled exception during startup:", exc)
        import traceback

        traceback.print_exc()
